/// TermLink MCP server — exposes terminal orchestration as structured tools.
#[derive(Clone)]
pub struct TermLinkTools {
    pub tool_router: ToolRouter<Self>,
    /// Background endpoints registered via `termlink_register`.
    endpoints: Arc<Mutex<Vec<EndpointHandle>>>,
}

impl std::fmt::Debug for TermLinkTools {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("TermLinkTools")
            .field("tool_router", &self.tool_router)
            .field("endpoints", &"[...]")
            .finish()
    }
}

impl Default for TermLinkTools {
    fn default() -> Self {
        Self::new()
    }
}

impl TermLinkTools {
    pub fn new() -> Self {
        Self {
            tool_router: Self::tool_router(),
            endpoints: Arc::new(Mutex::new(Vec::new())),
        }
    }
}

/// Helper: create a JSON error response string.
/// T-1687: parse one of `rotation.log` / `heal.log` (NDJSON) into entries,
/// applying since-cutoff + hub filter and tagging each entry with `event_type`.
/// Mirrors the CLI `cmd_fleet_history` parser so MCP and CLI return the same
/// per-row shape; kept file-local rather than shared to avoid the CLI→MCP
/// dependency direction. Malformed lines are counted but not surfaced
/// per-line (CLI prints the first 3; MCP returns the count instead).
fn fleet_history_parse_log(
    text: &str,
    event_type: &str,
    cutoff_secs: i64,
    hub_filter: Option<&str>,
    out: &mut Vec<serde_json::Value>,
    malformed_counter: &mut usize,
) {
    for raw in text.lines() {
        let trimmed = raw.trim();
        if trimmed.is_empty() {
            continue;
        }
        let mut entry: serde_json::Value = match serde_json::from_str(trimmed) {
            Ok(v) => v,
            Err(_) => {
                *malformed_counter += 1;
                continue;
            }
        };
        let ts_str = entry.get("ts").and_then(|v| v.as_str()).unwrap_or("");
        if fleet_history_rfc3339_to_unix(ts_str) < cutoff_secs {
            continue;
        }
        if let Some(want) = hub_filter {
            let got = entry.get("hub").and_then(|v| v.as_str()).unwrap_or("");
            if got != want {
                continue;
            }
        }
        if let Some(obj) = entry.as_object_mut() {
            obj.insert("event_type".into(), serde_json::Value::from(event_type));
        }
        out.push(entry);
    }
}

/// T-1710 (G-057 punch-list #1): per-hub flap verdict from PL-021 analysis.
/// Parallels CLI `HubFlapVerdict` (remote.rs); MCP cannot import it (pub(crate)).
#[derive(Debug, PartialEq, Eq, Clone, Copy)]
pub(crate) enum FleetHistoryFlapVerdict {
    Clean,
    CertOnly,
    SecretOnly,
    SingleDoubleRotation,
    Pl021Candidate,
}

impl FleetHistoryFlapVerdict {
    pub(crate) fn as_str(self) -> &'static str {
        match self {
            Self::Clean => "clean",
            Self::CertOnly => "cert-only",
            Self::SecretOnly => "secret-only",
            Self::SingleDoubleRotation => "single-double-rotation",
            Self::Pl021Candidate => "pl021-candidate",
        }
    }
}

/// T-1710: per-hub flap report. Parallels CLI `HubFlapReport`.
#[derive(Debug, Clone)]
pub(crate) struct FleetHistoryFlapReport {
    pub hub: String,
    pub verdict: FleetHistoryFlapVerdict,
    pub cert_transitions: u32,
    pub secret_transitions: u32,
    pub double_rotations: u32,
    pub last_double_rotation: Option<String>,
}

/// T-1710: PL-021 flap classifier — pure function on entries already parsed
/// by `fleet_history_parse_log`. Walks only `event_type=rotation` +
/// `kind=transition` rows; counts cert/secret transitions and "double
/// rotations" (cert + secret in the same row). Verdict precedence mirrors
/// CLI T-1690's `analyze_pl021` exactly:
/// - `(0,0,_)` → Clean
/// - `(_,_,n)` if n ≥ 2 → Pl021Candidate
/// - `(_,_,1)` → SingleDoubleRotation
/// - `(c,0,0)` if c > 0 → CertOnly
/// - `(0,s,0)` if s > 0 → SecretOnly
/// - else (c>0, s>0, n=0; cert and secret rotated separately, never together)
///   → SingleDoubleRotation (CLI fallthrough)
fn analyze_pl021_mcp(entries: &[serde_json::Value]) -> Vec<FleetHistoryFlapReport> {
    use std::collections::BTreeMap;
    let mut per_hub: BTreeMap<String, FleetHistoryFlapReport> = BTreeMap::new();
    for e in entries {
        // Analysis is rotation-only by construction; ignore heal events.
        if e.get("event_type").and_then(|v| v.as_str()).unwrap_or("rotation") != "rotation" {
            continue;
        }
        if e.get("kind").and_then(|v| v.as_str()) != Some("transition") {
            continue;
        }
        let hub = e
            .get("hub")
            .and_then(|v| v.as_str())
            .unwrap_or("?")
            .to_string();
        let oc = e.get("old_conn").and_then(|v| v.as_str()).unwrap_or("");
        let nc = e.get("new_conn").and_then(|v| v.as_str()).unwrap_or("");
        let op = e.get("old_pin").and_then(|v| v.as_str()).unwrap_or("");
        let np = e.get("new_pin").and_then(|v| v.as_str()).unwrap_or("");
        let cert_now = np == "drift" && op != "drift";
        let secret_now = nc == "auth-mismatch" && oc != "auth-mismatch";
        if !cert_now && !secret_now {
            continue;
        }
        let entry_ts = e.get("ts").and_then(|v| v.as_str()).map(String::from);
        let rep = per_hub
            .entry(hub.clone())
            .or_insert_with(|| FleetHistoryFlapReport {
                hub,
                verdict: FleetHistoryFlapVerdict::Clean,
                cert_transitions: 0,
                secret_transitions: 0,
                double_rotations: 0,
                last_double_rotation: None,
            });
        if cert_now {
            rep.cert_transitions += 1;
        }
        if secret_now {
            rep.secret_transitions += 1;
        }
        if cert_now && secret_now {
            rep.double_rotations += 1;
            rep.last_double_rotation = entry_ts;
        }
    }
    for rep in per_hub.values_mut() {
        rep.verdict = match (
            rep.cert_transitions,
            rep.secret_transitions,
            rep.double_rotations,
        ) {
            (0, 0, _) => FleetHistoryFlapVerdict::Clean,
            (_, _, n) if n >= 2 => FleetHistoryFlapVerdict::Pl021Candidate,
            (_, _, 1) => FleetHistoryFlapVerdict::SingleDoubleRotation,
            (c, 0, 0) if c > 0 => FleetHistoryFlapVerdict::CertOnly,
            (0, s, 0) if s > 0 => FleetHistoryFlapVerdict::SecretOnly,
            _ => FleetHistoryFlapVerdict::SingleDoubleRotation,
        };
    }
    per_hub.into_values().collect()
}

/// T-1687: civil-from-days RFC3339(Z) → unix seconds. Copy of the CLI parser;
/// see `rfc3339_to_unix_secs` in crates/termlink-cli/src/commands/remote.rs.
/// No chrono — keeps termlink-mcp dep-clean.
fn fleet_history_rfc3339_to_unix(ts: &str) -> i64 {
    if ts.len() < 20 || !ts.ends_with('Z') {
        return 0;
    }
    let bytes = ts.as_bytes();
    let parse_u = |start: usize, len: usize| -> Option<u32> {
        std::str::from_utf8(&bytes[start..start + len])
            .ok()?
            .parse()
            .ok()
    };
    let (Some(y), Some(mo), Some(d), Some(h), Some(mi), Some(s)) = (
        parse_u(0, 4),
        parse_u(5, 2),
        parse_u(8, 2),
        parse_u(11, 2),
        parse_u(14, 2),
        parse_u(17, 2),
    ) else {
        return 0;
    };
    let y = y as i64;
    let mo = mo as i64;
    let d = d as i64;
    let y_shift = if mo <= 2 { y - 1 } else { y };
    let era = if y_shift >= 0 {
        y_shift / 400
    } else {
        (y_shift - 399) / 400
    };
    let yoe = y_shift - era * 400;
    let mp = if mo > 2 { mo - 3 } else { mo + 9 };
    let doy = (153 * mp + 2) / 5 + d - 1;
    let doe = yoe * 365 + yoe / 4 - yoe / 100 + doy;
    let days = era * 146_097 + doe - 719_468;
    days * 86_400 + (h as i64) * 3600 + (mi as i64) * 60 + s as i64
}

// T-2071: predicate identifying whether a hub needs operator attention.
// Used by `termlink_fleet_governor_status` (only_pressured=true) to filter
// the per-hub array down to the actionable subset. Mirror of the CLI
// `governor_hub_is_pressured` in remote.rs. Pure helper — no IO, no state.
//
// A hub is pressured if ANY of:
//   - the probe failed (RPC timeout / connection error) → unreachable
//   - `connections_active >= connections_max` → at capacity right now
//   - `capacity_hits_total > 0` → has refused connections in its lifetime
//   - `rate_hits_total > 0`     → has refused RPCs in its lifetime
//
// The `r` arg is the per-hub probe outcome: Ok(governor_value) on success,
// Err(error_string) on RPC failure / timeout / older-hub-missing-field.
pub(crate) fn mcp_governor_hub_is_pressured(
    r: &Result<serde_json::Value, String>,
) -> bool {
    let v = match r {
        Ok(v) => v,
        Err(_) => return true, // unreachable counts as pressured
    };
    let active = v.get("connections_active").and_then(|x| x.as_i64()).unwrap_or(0);
    let max = v.get("connections_max").and_then(|x| x.as_i64()).unwrap_or(i64::MAX);
    let cap_hits = v.get("capacity_hits_total").and_then(|x| x.as_i64()).unwrap_or(0);
    let rate_hits = v.get("rate_hits_total").and_then(|x| x.as_i64()).unwrap_or(0);
    cap_hits > 0 || rate_hits > 0 || active >= max
}

// T-2069: per-hub aggregate over governor.log entries within window.
// Matches CLI `GovernorHubAgg` (remote.rs) field-for-field.
#[derive(Default, Debug)]
pub(crate) struct GovernorHubAggMcp {
    pub events: u32,
    pub cap_hits: i64,
    pub rate_hits: i64,
    pub dedupe_hits: i64,
}

/// T-2069: parse governor.log NDJSON entries, filter by `cutoff_secs` and
/// optional `hub_filter`. Returns `(entries, malformed_lines_skipped)`.
/// Pure helper — testable without writing a real log file.
pub(crate) fn parse_governor_log(
    text: &str,
    cutoff_secs: i64,
    hub_filter: Option<&str>,
) -> (Vec<serde_json::Value>, usize) {
    let mut entries: Vec<serde_json::Value> = Vec::new();
    let mut malformed: usize = 0;
    for raw in text.lines() {
        let trimmed = raw.trim();
        if trimmed.is_empty() {
            continue;
        }
        let entry: serde_json::Value = match serde_json::from_str(trimmed) {
            Ok(v) => v,
            Err(_) => {
                malformed += 1;
                continue;
            }
        };
        let ts_str = entry.get("ts").and_then(|v| v.as_str()).unwrap_or("");
        if fleet_history_rfc3339_to_unix(ts_str) < cutoff_secs {
            continue;
        }
        if let Some(want) = hub_filter {
            let got = entry.get("hub").and_then(|v| v.as_str()).unwrap_or("");
            if got != want {
                continue;
            }
        }
        entries.push(entry);
    }
    (entries, malformed)
}

/// T-2069: per-hub aggregator. Sums the Track G delta fields so callers can
/// answer "has this hub been backpressured in the window?" without
/// re-walking the entries list.
pub(crate) fn aggregate_governor_entries(
    entries: &[serde_json::Value],
) -> std::collections::BTreeMap<String, GovernorHubAggMcp> {
    let mut per_hub: std::collections::BTreeMap<String, GovernorHubAggMcp> =
        std::collections::BTreeMap::new();
    for e in entries {
        let h = e
            .get("hub")
            .and_then(|v| v.as_str())
            .unwrap_or("?")
            .to_string();
        let agg = per_hub.entry(h).or_default();
        agg.events += 1;
        agg.cap_hits += e.get("cap_hits_delta").and_then(|v| v.as_i64()).unwrap_or(0);
        agg.rate_hits += e.get("rate_hits_delta").and_then(|v| v.as_i64()).unwrap_or(0);
        agg.dedupe_hits += e
            .get("dedupe_hits_delta")
            .and_then(|v| v.as_i64())
            .unwrap_or(0);
    }
    per_hub
}

fn json_err(msg: impl std::fmt::Display) -> String {
    serde_json::to_string_pretty(&serde_json::json!({"ok": false, "error": msg.to_string()}))
        .unwrap_or_else(|e| format!("{{\"ok\":false,\"error\":\"{e}\"}}" ))
}

// T-2075: per-topic aggregate over claims.log entries within window.
// Mirror of GovernorHubAggMcp shape — different counters (kind taxonomy)
// but identical aggregation pattern.
#[derive(Default, Debug, PartialEq, Eq)]
pub(crate) struct ClaimsTopicAggMcp {
    pub transitions: u64,
    pub new_events: u64,
    pub removed_events: u64,
}

// T-2075: pure helper — parse claims.log NDJSON into (entries, malformed).
// Symmetric with parse_governor_log: same signature shape, same skip
// + count semantics, same RFC3339→epoch parser, same cutoff filter.
//
// `topic_filter == None` means "all topics". Lines missing required fields
// (`ts`, `topic`, `kind`) are counted malformed and skipped — never
// returned as half-parsed entries.
pub(crate) fn parse_claims_log(
    text: &str,
    cutoff_secs: i64,
    topic_filter: Option<&str>,
) -> (Vec<serde_json::Value>, usize) {
    let mut entries: Vec<serde_json::Value> = Vec::new();
    let mut malformed: usize = 0;
    for raw in text.lines() {
        let trimmed = raw.trim();
        if trimmed.is_empty() {
            continue;
        }
        let entry: serde_json::Value = match serde_json::from_str(trimmed) {
            Ok(v) => v,
            Err(_) => {
                malformed += 1;
                continue;
            }
        };
        let ts_str = match entry.get("ts").and_then(|v| v.as_str()) {
            Some(s) => s,
            None => {
                malformed += 1;
                continue;
            }
        };
        let topic = match entry.get("topic").and_then(|v| v.as_str()) {
            Some(s) => s,
            None => {
                malformed += 1;
                continue;
            }
        };
        if entry.get("kind").and_then(|k| k.as_str()).is_none() {
            malformed += 1;
            continue;
        }
        if let Some(want) = topic_filter {
            if topic != want {
                continue;
            }
        }
        if fleet_history_rfc3339_to_unix(ts_str) < cutoff_secs {
            continue;
        }
        entries.push(entry);
    }
    (entries, malformed)
}

// T-2075: pure helper — aggregate per-topic kind counts.
// Mirror of aggregate_governor_entries pattern. BTreeMap keeps insertion
// order stable so the JSON envelope's per_topic key order is reproducible
// in test assertions.
pub(crate) fn aggregate_claims_entries(
    entries: &[serde_json::Value],
) -> std::collections::BTreeMap<String, ClaimsTopicAggMcp> {
    let mut per_topic: std::collections::BTreeMap<String, ClaimsTopicAggMcp> =
        std::collections::BTreeMap::new();
    for e in entries {
        let t = e
            .get("topic")
            .and_then(|v| v.as_str())
            .unwrap_or("?")
            .to_string();
        let kind = match e.get("kind").and_then(|v| v.as_str()) {
            Some(s) => s,
            None => continue,
        };
        let agg = per_topic.entry(t).or_default();
        match kind {
            "transition" => agg.transitions += 1,
            "new" => agg.new_events += 1,
            "removed" => agg.removed_events += 1,
            _ => {}
        }
    }
    per_topic
}

