/// T-1960: classify a tool's short description as deprecated when it contains
/// any of the marker phrases used by the registry to flag retirement-WIP or
/// already-legacy tools. Pure derivation — no hand-curated allow/deny list to
/// drift. When the T-1166 inbox retirement lands and the registry is updated
/// to drop "legacy primitive" wording, the flag auto-clears. The case-
/// insensitive match avoids false negatives from sentence-case usage.
fn is_deprecated(description: &str) -> bool {
    let d = description.to_lowercase();
    d.contains("legacy")
        || d.contains("retirement")
        || d.contains("deprecated")
        || d.contains("t-1166")
}

/// T-1970: extract a replacement-tool hint from a deprecated tool's description.
/// Looks for the literal pattern `(use NAME instead)` and returns NAME. The
/// marker lives in the description text so that:
///   - new deprecated tools opt in by appending `(use X instead)` to their description
///   - when the deprecated tool is deleted (T-1166 land), the hint disappears
///     automatically with the tool — zero curated lists to drift
///   - the parser is conservative: no fuzzy matching, exact `(use ` + ` instead)`
///     fences, single name (no spaces) between them. Returns the inner name
///     trimmed of whitespace, or None if no marker is present / malformed.
/// Surfaced in tool_detail, name_filter matches, and default-mode rows when the
/// tool is deprecated. Locked by the
/// `every_deprecated_tool_has_replacement_hint` and
/// `extract_replacement_hint_returns_none_on_live_tools` invariant tests.
fn extract_replacement_hint(description: &str) -> Option<&str> {
    let start_marker = "(use ";
    let end_marker = " instead)";
    let start = description.find(start_marker)? + start_marker.len();
    let rest = &description[start..];
    let end = rest.find(end_marker)?;
    let name = rest[..end].trim();
    if name.is_empty() || name.contains(char::is_whitespace) {
        return None;
    }
    Some(name)
}

/// T-1980: reverse-direction map of the `replacement_hint` graph. Built by
/// walking every category once and collecting, for each `(use NAME instead)`
/// marker in any deprecated tool's description, the entry
/// `NAME -> [list of deprecated tools pointing here]`.
///
/// Used by `tool_detail` to populate the `is_replacement_for[]` field — the
/// inverse of T-1970's forward `replacement_hint`. LLMs landing on a live tool
/// can see which retirement-WIP primitives it replaces at the same round-trip,
/// without enumerating every deprecated tool to find the back-references.
///
/// Cached in a `OnceLock` so the scan runs once per process. Returned lists
/// are sorted alphabetically for deterministic JSON output.
fn tool_replacement_back_refs(
) -> &'static std::collections::HashMap<&'static str, Vec<&'static str>> {
    static MAP: std::sync::OnceLock<std::collections::HashMap<&'static str, Vec<&'static str>>> =
        std::sync::OnceLock::new();
    MAP.get_or_init(|| {
        let cats = help_categories();
        let mut m: std::collections::HashMap<&'static str, Vec<&'static str>> =
            std::collections::HashMap::new();
        for (_, tools) in cats {
            for (name, desc) in tools {
                if !is_deprecated(desc) {
                    continue;
                }
                if let Some(hint) = extract_replacement_hint(desc) {
                    m.entry(hint).or_default().push(name);
                }
            }
        }
        for v in m.values_mut() {
            v.sort();
            v.dedup();
        }
        m
    })
}

