/// T-1732: pure helper — index every thread on a topic walk. Mirror of
/// CLI's `compute_threads_index` (channel.rs:7047) one-to-one.
///
/// Filtering rules (preserved verbatim from CLI):
/// - root that is redacted → row dropped entirely
/// - replies that are redacted → don't count toward reply_count or participants
/// - thread with zero non-redacted replies → row dropped
/// - non-numeric `in_reply_to` → reply ignored
///
/// Sort: `last_ts_ms` descending (most recently active first); ties break
/// on `root_offset` ascending. Pure — no I/O.
fn compute_threads_index_mcp(envelopes: &[serde_json::Value]) -> Vec<ThreadIndexRowMcp> {
    use std::collections::{HashMap, HashSet};
    let redacted = redacted_offsets_mcp(envelopes);
    let mut by_off: HashMap<u64, &serde_json::Value> = HashMap::with_capacity(envelopes.len());
    for env in envelopes {
        if let Some(off) = env.get("offset").and_then(|v| v.as_u64()) {
            by_off.insert(off, env);
        }
    }
    let mut children: HashMap<u64, Vec<(u64, String, i64)>> = HashMap::new();
    for env in envelopes {
        let Some(off) = env.get("offset").and_then(|v| v.as_u64()) else { continue };
        if redacted.contains(&off) {
            continue;
        }
        let Some(parent) = parent_offset_of_mcp(env) else { continue };
        let sender = env
            .get("sender_id")
            .and_then(|v| v.as_str())
            .unwrap_or("")
            .to_string();
        let ts = env
            .get("ts_unix_ms")
            .and_then(|v| v.as_i64())
            .or_else(|| env.get("ts").and_then(|v| v.as_i64()))
            .unwrap_or(0);
        children.entry(parent).or_default().push((off, sender, ts));
    }
    let mut rows: Vec<ThreadIndexRowMcp> = Vec::new();
    for (root_off, _) in children.iter().filter(|(off, _)| !redacted.contains(off)) {
        let root_env = match by_off.get(root_off) {
            Some(e) => *e,
            None => continue,
        };
        let mut stack: Vec<u64> = vec![*root_off];
        let mut seen: HashSet<u64> = HashSet::new();
        seen.insert(*root_off);
        let mut reply_count: usize = 0;
        let mut participants: HashSet<String> = HashSet::new();
        let root_sender = root_env
            .get("sender_id")
            .and_then(|v| v.as_str())
            .unwrap_or("")
            .to_string();
        if !root_sender.is_empty() {
            participants.insert(root_sender);
        }
        let mut last_ts: i64 = root_env
            .get("ts_unix_ms")
            .and_then(|v| v.as_i64())
            .or_else(|| root_env.get("ts").and_then(|v| v.as_i64()))
            .unwrap_or(0);
        while let Some(parent) = stack.pop() {
            if let Some(kids) = children.get(&parent) {
                for (k_off, k_sender, k_ts) in kids {
                    if !seen.insert(*k_off) {
                        continue;
                    }
                    reply_count += 1;
                    if !k_sender.is_empty() {
                        participants.insert(k_sender.clone());
                    }
                    if *k_ts > last_ts {
                        last_ts = *k_ts;
                    }
                    stack.push(*k_off);
                }
            }
        }
        if reply_count == 0 {
            continue;
        }
        rows.push(ThreadIndexRowMcp {
            root_offset: *root_off,
            reply_count,
            participants: participants.len(),
            last_ts_ms: last_ts,
            root_payload: Some(decode_payload_lossy_mcp(root_env)),
        });
    }
    rows.sort_by(|a, b| {
        b.last_ts_ms
            .cmp(&a.last_ts_ms)
            .then_with(|| a.root_offset.cmp(&b.root_offset))
    });
    rows
}

/// T-1738: one rendered line in a snippet block. Mirror of CLI's
/// `SnippetLine` (channel.rs:4487). Field shape preserved one-to-one.
#[derive(Debug, Clone, PartialEq, Eq)]
struct SnippetLineMcp {
    offset: u64,
    sender: String,
    payload: String,
    is_target: bool,
}

impl SnippetLineMcp {
    fn to_json_mcp(&self) -> serde_json::Value {
        serde_json::json!({
            "offset": self.offset,
            "sender": self.sender,
            "payload": self.payload,
            "is_target": self.is_target,
        })
    }
}

/// T-1738: pure helper — pick the snippet window from a topic walk. Mirror
/// of CLI's `compute_snippet` (channel.rs:4514) one-to-one.
///
/// Filters envelopes to content msg_types (`post`/`chat`/`note`) and skips
/// meta types so the snippet stays focused. Locates the target offset,
/// includes up to `lines` content envelopes on each side. Returns `None`
/// when the target is not in `envelopes` or is itself a meta type. Pure
/// — no I/O.
fn compute_snippet_mcp(
    envelopes: &[serde_json::Value],
    target_offset: u64,
    lines: u64,
) -> Option<Vec<SnippetLineMcp>> {
    let is_content = |env: &serde_json::Value| -> bool {
        matches!(
            env.get("msg_type").and_then(|v| v.as_str()),
            Some("post") | Some("chat") | Some("note")
        )
    };
    let mut content_envs: Vec<&serde_json::Value> =
        envelopes.iter().filter(|e| is_content(e)).collect();
    content_envs.sort_by_key(|e| e.get("offset").and_then(|v| v.as_u64()).unwrap_or(0));

    let target_idx = content_envs
        .iter()
        .position(|e| e.get("offset").and_then(|v| v.as_u64()) == Some(target_offset))?;
    let lines_usize = lines as usize;
    let lo = target_idx.saturating_sub(lines_usize);
    let hi = (target_idx + lines_usize + 1).min(content_envs.len());

    let snippet: Vec<SnippetLineMcp> = content_envs[lo..hi]
        .iter()
        .map(|e| {
            let off = e.get("offset").and_then(|v| v.as_u64()).unwrap_or(0);
            SnippetLineMcp {
                offset: off,
                sender: e
                    .get("sender_id")
                    .and_then(|v| v.as_str())
                    .unwrap_or("?")
                    .to_string(),
                payload: decode_payload_lossy_mcp(e),
                is_target: off == target_offset,
            }
        })
        .collect();
    Some(snippet)
}

