/// T-1739: pure helper — extract last N non-meta posts from `msgs` with
/// optional peer/thread/project/msg_type/grep filters. Mirror of CLI's
/// `extract_recent_posts` (channel.rs:1284). All four filters are
/// independent and AND-composed when set. Returns posts in chrono asc
/// order (oldest first; natural reading flow). Caps content at 200
/// chars (suffix `…` if truncated). Untagged posts fail any tag filter
/// that's set. Grep is case-insensitive.
///
/// META = ["reaction", "edit", "redaction", "topic_metadata", "receipt"]
/// — always excluded before any allowlist filter runs (so `edit` etc.
/// cannot be re-introduced via `filter_msg_types`).
///
/// Content extraction fallback chain matches CLI exactly:
///   1. `payload_b64` (base64 → UTF-8) — REAL wire envelopes
///   2. `payload.text` — historical
///   3. `payload` as &str — historical
///   4. `payload.to_string()` — last-resort raw JSON
fn extract_recent_posts_mcp(
    msgs: &[serde_json::Value],
    n: usize,
    window_ms: i64,
    now_ms: i64,
    filter_peer_fp: Option<&str>,
    filter_thread: Option<&str>,
    filter_project: Option<&str>,
    filter_msg_types: Option<&[&str]>,
    filter_grep: Option<&str>,
) -> Vec<RecentPostMcp> {
    use base64::Engine as _;
    const META: &[&str] = &["reaction", "edit", "redaction", "topic_metadata", "receipt"];
    const CONTENT_CAP: usize = 200;
    let cutoff = now_ms - window_ms;
    let grep_lower: Option<String> = filter_grep
        .filter(|s| !s.is_empty())
        .map(|s| s.to_lowercase());
    let mut hits: Vec<RecentPostMcp> = Vec::new();
    for m in msgs {
        let mt = m.get("msg_type").and_then(|v| v.as_str()).unwrap_or("");
        if META.contains(&mt) {
            continue;
        }
        if let Some(allowed) = filter_msg_types {
            if !allowed.contains(&mt) {
                continue;
            }
        }
        let sender = m.get("sender_id").and_then(|v| v.as_str()).unwrap_or("");
        if sender.is_empty() {
            continue;
        }
        if let Some(want) = filter_peer_fp {
            if sender != want {
                continue;
            }
        }
        let ts = m
            .get("ts_unix_ms")
            .and_then(|v| v.as_i64())
            .or_else(|| m.get("ts").and_then(|v| v.as_i64()))
            .unwrap_or(0);
        if ts < cutoff {
            continue;
        }
        let project = m
            .get("metadata")
            .and_then(|md| md.get("from_project"))
            .and_then(|v| v.as_str())
            .map(String::from);
        let thread = m
            .get("metadata")
            .and_then(|md| md.get("thread").or_else(|| md.get("_thread")))
            .and_then(|v| v.as_str())
            .map(String::from);
        if let Some(want) = filter_thread {
            if thread.as_deref() != Some(want) {
                continue;
            }
        }
        if let Some(want) = filter_project {
            if project.as_deref() != Some(want) {
                continue;
            }
        }
        let content_raw = m
            .get("payload_b64")
            .and_then(|v| v.as_str())
            .and_then(|b64| {
                base64::engine::general_purpose::STANDARD
                    .decode(b64)
                    .ok()
                    .and_then(|bytes| String::from_utf8(bytes).ok())
            })
            .or_else(|| {
                m.get("payload")
                    .and_then(|p| p.get("text"))
                    .and_then(|v| v.as_str())
                    .map(String::from)
            })
            .or_else(|| m.get("payload").and_then(|p| p.as_str()).map(String::from))
            .or_else(|| m.get("payload").map(|p| p.to_string()))
            .unwrap_or_default();
        let content = if content_raw.chars().count() > CONTENT_CAP {
            let truncated: String = content_raw.chars().take(CONTENT_CAP).collect();
            format!("{truncated}…")
        } else {
            content_raw
        };
        if let Some(needle) = grep_lower.as_deref() {
            if !content.to_lowercase().contains(needle) {
                continue;
            }
        }
        let offset = m.get("offset").and_then(|v| v.as_u64()).unwrap_or(0);
        hits.push(RecentPostMcp {
            offset,
            ts_ms: ts,
            peer_fp: sender.to_string(),
            msg_type: mt.to_string(),
            content,
            thread,
            project,
        });
    }
    hits.sort_by(|a, b| a.ts_ms.cmp(&b.ts_ms));
    if hits.len() > n {
        let drop = hits.len() - n;
        hits.drain(0..drop);
    }
    hits
}

/// T-1740: chat-arc activity stats over a window. Mirror of CLI's
/// `ChatArcStats` (channel.rs:1426). Field shape preserved one-to-one
/// so JSON envelope is byte-identical with CLI `agent stats --json`.
#[derive(Debug, Clone, PartialEq, Eq)]
struct ChatArcStatsMcp {
    total: usize,
    by_msg_type: Vec<(String, usize)>,
    by_peer: Vec<(String, usize)>,
    by_project: Vec<(String, usize)>,
    by_thread: Vec<(String, usize)>,
}

/// T-1740: pure helper — summarize chat-arc activity inside a window.
/// Mirror of CLI's `summarize_chat_arc_stats` (channel.rs:1434).
///
/// Drops:
/// - META msg_types (reaction/edit/redaction/topic_metadata/receipt)
/// - empty `sender_id`
/// - envelopes with `ts < cutoff` OR `ts > now_ms` (future-clock safety)
///
/// Buckets each surviving envelope into by_msg_type, by_peer,
/// by_project, by_thread (latter two skip envelopes lacking the
/// `metadata.from_project` / `metadata.thread`+`metadata._thread`
/// keys — the same fallback pair `extract_recent_posts_mcp` uses).
///
/// Sort within each bucket: desc by count, asc by key (stable
/// tie-break).
fn summarize_chat_arc_stats_mcp(
    msgs: &[serde_json::Value],
    now_ms: i64,
    window_ms: i64,
) -> ChatArcStatsMcp {
    const META: &[&str] = &["reaction", "edit", "redaction", "topic_metadata", "receipt"];
    let cutoff = now_ms - window_ms;
    let mut total = 0usize;
    let mut mt_counts: std::collections::HashMap<String, usize> = std::collections::HashMap::new();
    let mut peer_counts: std::collections::HashMap<String, usize> =
        std::collections::HashMap::new();
    let mut project_counts: std::collections::HashMap<String, usize> =
        std::collections::HashMap::new();
    let mut thread_counts: std::collections::HashMap<String, usize> =
        std::collections::HashMap::new();
    for m in msgs {
        let mt = m.get("msg_type").and_then(|v| v.as_str()).unwrap_or("");
        if META.contains(&mt) {
            continue;
        }
        let sender = m.get("sender_id").and_then(|v| v.as_str()).unwrap_or("");
        if sender.is_empty() {
            continue;
        }
        let ts = m
            .get("ts_unix_ms")
            .and_then(|v| v.as_i64())
            .or_else(|| m.get("ts").and_then(|v| v.as_i64()))
            .unwrap_or(0);
        if ts < cutoff || ts > now_ms {
            continue;
        }
        total += 1;
        *mt_counts.entry(mt.to_string()).or_insert(0) += 1;
        *peer_counts.entry(sender.to_string()).or_insert(0) += 1;
        if let Some(p) = m
            .get("metadata")
            .and_then(|md| md.get("from_project"))
            .and_then(|v| v.as_str())
        {
            *project_counts.entry(p.to_string()).or_insert(0) += 1;
        }
        if let Some(t) = m
            .get("metadata")
            .and_then(|md| md.get("thread").or_else(|| md.get("_thread")))
            .and_then(|v| v.as_str())
        {
            *thread_counts.entry(t.to_string()).or_insert(0) += 1;
        }
    }
    fn sort_buckets_mcp(map: std::collections::HashMap<String, usize>) -> Vec<(String, usize)> {
        let mut v: Vec<(String, usize)> = map.into_iter().collect();
        v.sort_by(|a, b| b.1.cmp(&a.1).then_with(|| a.0.cmp(&b.0)));
        v
    }
    ChatArcStatsMcp {
        total,
        by_msg_type: sort_buckets_mcp(mt_counts),
        by_peer: sort_buckets_mcp(peer_counts),
        by_project: sort_buckets_mcp(project_counts),
        by_thread: sort_buckets_mcp(thread_counts),
    }
}

