/// T-1741: pure helper — aggregate non-meta msgs by `from_project`
/// within the window. Mirror of CLI's `summarize_fleet_by_project`
/// (channel.rs:1145).
///
/// Drops:
/// - META msg_types
/// - empty `sender_id`
/// - UNTAGGED posts (no `from_project` or empty) — project IS the key,
///   so untagged can never appear in by-project view (unconditional,
///   independent of filter_project)
/// - posts older than `cutoff`
///
/// `filter_project` / `filter_thread`: AND-compose with filters as in
/// `summarize_fleet_presence_mcp`.
///
/// `top_peer_fp` is the peer who posted the most on this project
/// (alphabetic tie-break). `distinct_peers` counts unique sender_ids.
///
/// Sort: posts desc, project asc.
fn summarize_fleet_by_project_mcp(
    msgs: &[serde_json::Value],
    now_ms: i64,
    window_ms: i64,
    filter_project: Option<&str>,
    filter_thread: Option<&str>,
) -> Vec<FleetProjectRowMcp> {
    use std::collections::HashMap;
    const META: &[&str] = &["reaction", "edit", "redaction", "topic_metadata", "receipt"];
    let cutoff = now_ms - window_ms;
    struct Acc {
        posts: u64,
        last_seen: Option<i64>,
        peers: HashMap<String, u64>,
    }
    let mut by_project: HashMap<String, Acc> = HashMap::new();
    for m in msgs {
        let mt = m.get("msg_type").and_then(|v| v.as_str()).unwrap_or("");
        if META.contains(&mt) {
            continue;
        }
        let sender = match m.get("sender_id").and_then(|v| v.as_str()) {
            Some(s) if !s.is_empty() => s.to_string(),
            _ => continue,
        };
        let ts = m
            .get("ts_unix_ms")
            .and_then(|v| v.as_i64())
            .or_else(|| m.get("ts").and_then(|v| v.as_i64()))
            .unwrap_or(0);
        let from_project = match m
            .get("metadata")
            .and_then(|md| md.get("from_project"))
            .and_then(|v| v.as_str())
        {
            Some(p) if !p.is_empty() => p.to_string(),
            _ => continue,
        };
        if let Some(want) = filter_project {
            if from_project != want {
                continue;
            }
        }
        if let Some(want) = filter_thread {
            let from_thread = m
                .get("metadata")
                .and_then(|md| md.get("_thread"))
                .and_then(|v| v.as_str());
            if from_thread != Some(want) {
                continue;
            }
        }
        if ts < cutoff {
            continue;
        }
        let acc = by_project.entry(from_project).or_insert(Acc {
            posts: 0,
            last_seen: None,
            peers: HashMap::new(),
        });
        acc.posts += 1;
        acc.last_seen = Some(acc.last_seen.map_or(ts, |b| b.max(ts)));
        *acc.peers.entry(sender).or_insert(0) += 1;
    }
    let mut rows: Vec<FleetProjectRowMcp> = by_project
        .into_iter()
        .map(|(project, acc)| {
            let top_peer_fp = if acc.peers.is_empty() {
                None
            } else {
                let mut v: Vec<(String, u64)> =
                    acc.peers.iter().map(|(k, v)| (k.clone(), *v)).collect();
                v.sort_by(|a, b| b.1.cmp(&a.1).then_with(|| a.0.cmp(&b.0)));
                Some(v.into_iter().next().unwrap().0)
            };
            let distinct_peers = acc.peers.len() as u64;
            FleetProjectRowMcp {
                project,
                posts: acc.posts,
                distinct_peers,
                top_peer_fp,
                last_seen_ms: acc.last_seen,
            }
        })
        .collect();
    rows.sort_by(|a, b| b.posts.cmp(&a.posts).then_with(|| a.project.cmp(&b.project)));
    rows
}

/// T-1745: one canonical-state row. Mirror of CLI's `StateRow`
/// (channel.rs:5834). Field shape preserved one-to-one.
#[derive(Debug, Clone, PartialEq, Eq)]
struct StateRowMcp {
    offset: u64,
    sender_id: String,
    payload: String,
    is_edited: bool,
    edit_count: u64,
    latest_edit_ts_ms: i64,
    ts_ms: i64,
    is_redacted: bool,
}

impl StateRowMcp {
    fn to_json_mcp(&self) -> serde_json::Value {
        serde_json::json!({
            "offset": self.offset,
            "sender_id": self.sender_id,
            "payload": self.payload,
            "is_edited": self.is_edited,
            "edit_count": self.edit_count,
            "latest_edit_ts_ms": self.latest_edit_ts_ms,
            "ts_ms": self.ts_ms,
            "is_redacted": self.is_redacted,
        })
    }
}

/// T-1745: pure helper — build the canonical content-row state of a topic.
/// Mirror of CLI's `compute_state` (channel.rs:5881) one-to-one.
///
/// One row per content envelope (META_MSG_TYPES skipped), in offset-asc order.
/// Edits collapse to latest-wins (max ts_ms, offset tiebreak; redacted edits
/// excluded from the count and from latest-selection). Redactions either drop
/// the row (when `include_redacted=false`, default) or surface it with payload
/// `"[REDACTED]"` and `is_redacted=true`.
///
/// `ts_ms` is always the original content row's timestamp (not the latest
/// edit's). Use `latest_edit_ts_ms` to know when the current text was written.
/// Pure — no I/O. Reads `ts_unix_ms` first, falls back to `ts` for legacy
/// envelopes (matching CLI exactly).
fn compute_state_mcp(envelopes: &[serde_json::Value], include_redacted: bool) -> Vec<StateRowMcp> {
    use std::collections::HashMap;
    let redacted = redacted_offsets_mcp(envelopes);
    // target -> (latest_ts, latest_offset, latest_text, count)
    let mut edits: HashMap<u64, (i64, u64, String, u64)> = HashMap::new();
    for env in envelopes {
        if env.get("msg_type").and_then(|v| v.as_str()) != Some("edit") {
            continue;
        }
        let off = match env.get("offset").and_then(|v| v.as_u64()) {
            Some(o) => o,
            None => continue,
        };
        if redacted.contains(&off) {
            continue;
        }
        let target = match env
            .get("metadata")
            .and_then(|md| md.get("replaces"))
            .and_then(|v| v.as_str())
            .and_then(|s| s.parse::<u64>().ok())
        {
            Some(t) => t,
            None => continue,
        };
        let ts = env
            .get("ts_unix_ms")
            .and_then(|v| v.as_i64())
            .or_else(|| env.get("ts").and_then(|v| v.as_i64()))
            .unwrap_or(0);
        let text = decode_payload_lossy_mcp(env);
        let entry = edits
            .entry(target)
            .or_insert((i64::MIN, 0, String::new(), 0));
        entry.3 += 1;
        if ts > entry.0 || (ts == entry.0 && off > entry.1) {
            entry.0 = ts;
            entry.1 = off;
            entry.2 = text;
        }
    }
    let mut rows: Vec<StateRowMcp> = Vec::new();
    for env in envelopes {
        let mt = env.get("msg_type").and_then(|v| v.as_str()).unwrap_or("");
        if META_MSG_TYPES.contains(&mt) {
            continue;
        }
        let off = match env.get("offset").and_then(|v| v.as_u64()) {
            Some(o) => o,
            None => continue,
        };
        let is_red = redacted.contains(&off);
        if is_red && !include_redacted {
            continue;
        }
        let sender = env
            .get("sender_id")
            .and_then(|v| v.as_str())
            .unwrap_or("?")
            .to_string();
        let ts = env
            .get("ts_unix_ms")
            .and_then(|v| v.as_i64())
            .or_else(|| env.get("ts").and_then(|v| v.as_i64()))
            .unwrap_or(0);
        let original_payload = decode_payload_lossy_mcp(env);
        let (payload, is_edited, edit_count, latest_edit_ts) = if is_red {
            ("[REDACTED]".to_string(), false, 0u64, 0i64)
        } else if let Some((latest_ts, _, text, count)) = edits.get(&off) {
            (text.clone(), true, *count, *latest_ts)
        } else {
            (original_payload, false, 0u64, 0i64)
        };
        rows.push(StateRowMcp {
            offset: off,
            sender_id: sender,
            payload,
            is_edited,
            edit_count,
            latest_edit_ts_ms: latest_edit_ts,
            ts_ms: ts,
            is_redacted: is_red,
        });
    }
    rows.sort_by_key(|r| r.offset);
    rows
}

/// T-1746: per-sender membership row. Mirror of CLI's `MemberRow`
/// (channel.rs:2454). Field shape preserved one-to-one.
#[derive(Debug, Clone, PartialEq, Eq)]
struct MemberRowMcp {
    sender_id: String,
    posts: u64,
    first_ts: Option<i64>,
    last_ts: Option<i64>,
}

impl MemberRowMcp {
    fn to_json_mcp(&self) -> serde_json::Value {
        serde_json::json!({
            "sender_id": self.sender_id,
            "posts": self.posts,
            "first_ts": self.first_ts,
            "last_ts": self.last_ts,
        })
    }
}

/// T-1746: pure helper — group envelopes by sender_id and accumulate
/// post-count + first/last ts. Mirror of CLI `summarize_members`
/// (channel.rs:2476). Returns rows sorted by last_ts desc (None last_ts
/// sorts last; sender_id tiebreak via BTreeMap stable ordering).
/// Skips meta envelopes (META_MSG_TYPES) unless `include_meta` is true.
/// Empty sender_ids are skipped (defensive).
fn summarize_members_mcp(msgs: &[serde_json::Value], include_meta: bool) -> Vec<MemberRowMcp> {
    use std::collections::BTreeMap;
    let mut acc: BTreeMap<String, MemberRowMcp> = BTreeMap::new();
    for m in msgs {
        let mt = m.get("msg_type").and_then(|v| v.as_str()).unwrap_or("");
        if !include_meta && META_MSG_TYPES.contains(&mt) {
            continue;
        }
        let sender = match m.get("sender_id").and_then(|v| v.as_str()) {
            Some(s) if !s.is_empty() => s.to_string(),
            _ => continue,
        };
        let ts_opt = m
            .get("ts_unix_ms")
            .and_then(|v| v.as_i64())
            .or_else(|| m.get("ts").and_then(|v| v.as_i64()));
        let entry = acc.entry(sender.clone()).or_insert_with(|| MemberRowMcp {
            sender_id: sender,
            posts: 0,
            first_ts: None,
            last_ts: None,
        });
        entry.posts += 1;
        if let Some(ts) = ts_opt {
            entry.first_ts = Some(entry.first_ts.map_or(ts, |a| a.min(ts)));
            entry.last_ts = Some(entry.last_ts.map_or(ts, |a| a.max(ts)));
        }
    }
    let mut rows: Vec<MemberRowMcp> = acc.into_values().collect();
    rows.sort_by(|a, b| match (a.last_ts, b.last_ts) {
        (Some(av), Some(bv)) => bv.cmp(&av),
        (Some(_), None) => std::cmp::Ordering::Less,
        (None, Some(_)) => std::cmp::Ordering::Greater,
        (None, None) => std::cmp::Ordering::Equal,
    });
    rows
}

/// T-1746: pure helper — same as `summarize_members_mcp` but pre-filters
/// envelopes by `ts <= as_of_ms`. Mirror of CLI `summarize_members_as_of`
/// (channel.rs:2520). Envelopes missing a timestamp are treated as ts=0.
/// When `as_of_ms` is None, behaves identically to summarize_members_mcp.
fn summarize_members_as_of_mcp(
    msgs: &[serde_json::Value],
    include_meta: bool,
    as_of_ms: Option<i64>,
) -> Vec<MemberRowMcp> {
    let Some(cutoff) = as_of_ms else {
        return summarize_members_mcp(msgs, include_meta);
    };
    let filtered: Vec<serde_json::Value> = msgs
        .iter()
        .filter(|env| {
            let ts = env
                .get("ts_unix_ms")
                .and_then(|v| v.as_i64())
                .or_else(|| env.get("ts").and_then(|v| v.as_i64()))
                .unwrap_or(0);
            ts <= cutoff
        })
        .cloned()
        .collect();
    summarize_members_mcp(&filtered, include_meta)
}

/// T-1747: point-in-time canonical state. Mirror of CLI's `compute_snapshot`
/// (channel.rs). Filters envelopes by ts<=as_of_ms then delegates to
/// `compute_state_mcp`. Envelopes missing a timestamp are treated as ts=0
/// (always included for as_of >= 0; never excluded by the upper bound).
/// Pure — no I/O.
fn compute_snapshot_mcp(
    envelopes: &[serde_json::Value],
    as_of_ms: i64,
    include_redacted: bool,
) -> Vec<StateRowMcp> {
    let filtered: Vec<serde_json::Value> = envelopes
        .iter()
        .filter(|env| {
            let ts = env
                .get("ts_unix_ms")
                .and_then(|v| v.as_i64())
                .or_else(|| env.get("ts").and_then(|v| v.as_i64()))
                .unwrap_or(0);
            ts <= as_of_ms
        })
        .cloned()
        .collect();
    compute_state_mcp(&filtered, include_redacted)
}

/// T-1748: incremental canonical state — rows whose last-change ts >= `since_ms`.
/// Mirror of CLI's `compute_state_since` (channel.rs:6489) one-to-one.
///
/// "Last change" = max(`ts_ms`, `latest_edit_ts_ms`, redact_ts). The redact_ts
/// map is built in a separate pass over `msg_type="redaction"` envelopes
/// (target = metadata.redacts, ts = ts_unix_ms with ts fallback) before
/// delegating to `compute_state_mcp`. A row with no edits/redactions falls
/// back to `ts_ms`. Pure — no I/O.
///
/// Use case: agents poll for incremental topic deltas using their last-seen
/// wall-clock cursor instead of refetching full state every cycle.
fn compute_state_since_mcp(
    envelopes: &[serde_json::Value],
    since_ms: i64,
    include_redacted: bool,
) -> Vec<StateRowMcp> {
    use std::collections::HashMap;
    let mut redact_ts: HashMap<u64, i64> = HashMap::new();
    for env in envelopes {
        if env.get("msg_type").and_then(|v| v.as_str()) != Some("redaction") {
            continue;
        }
        let target = match env
            .get("metadata")
            .and_then(|md| md.get("redacts"))
            .and_then(|v| v.as_str())
            .and_then(|s| s.parse::<u64>().ok())
        {
            Some(t) => t,
            None => continue,
        };
        let ts = env
            .get("ts_unix_ms")
            .and_then(|v| v.as_i64())
            .or_else(|| env.get("ts").and_then(|v| v.as_i64()))
            .unwrap_or(0);
        let entry = redact_ts.entry(target).or_insert(i64::MIN);
        if ts > *entry {
            *entry = ts;
        }
    }
    let rows = compute_state_mcp(envelopes, include_redacted);
    rows.into_iter()
        .filter(|r| {
            let red = redact_ts.get(&r.offset).copied().unwrap_or(i64::MIN);
            let last_change = r.ts_ms.max(r.latest_edit_ts_ms).max(red);
            last_change >= since_ms
        })
        .collect()
}

/// T-1749: one row of a snapshot diff. `change_kind` classifies the per-offset
/// transition between two `compute_snapshot_mcp` views.
/// Mirror of CLI's `DiffRow` (channel.rs:6580).
///
/// - `"added"`:     offset absent at `from`, present at `to`
/// - `"removed"`:   present at `from`, absent at `to` (e.g. redaction landed)
/// - `"edited"`:    present in both; payload text differs
/// - `"unchanged"`: present in both; payload identical
#[derive(Debug, Clone, PartialEq, Eq)]
struct DiffRowMcp {
    offset: u64,
    change_kind: &'static str,
    sender_id: String,
    from_payload: Option<String>,
    to_payload: Option<String>,
}

impl DiffRowMcp {
    fn to_json_mcp(&self) -> serde_json::Value {
        serde_json::json!({
            "offset": self.offset,
            "change_kind": self.change_kind,
            "sender_id": self.sender_id,
            "from_payload": self.from_payload,
            "to_payload": self.to_payload,
        })
    }
}

/// T-1749: pure helper — typed diff between two snapshots.
/// Mirror of CLI's `compute_snapshot_diff` (channel.rs:6612).
///
/// Pipeline:
/// 1. from_rows = compute_snapshot_mcp(envelopes, from_ms, include_redacted)
/// 2. to_rows   = compute_snapshot_mcp(envelopes, to_ms,   include_redacted)
/// 3. union of offsets, classified per-offset
///
/// Sort: offset asc.
///
/// `from_ms == to_ms` produces all-`unchanged` rows. The caller decides
/// whether to filter unchanged out (matches CLI's `include_unchanged` flag).
fn compute_snapshot_diff_mcp(
    envelopes: &[serde_json::Value],
    from_ms: i64,
    to_ms: i64,
    include_redacted: bool,
) -> Vec<DiffRowMcp> {
    use std::collections::{BTreeSet, HashMap};
    let from_rows = compute_snapshot_mcp(envelopes, from_ms, include_redacted);
    let to_rows = compute_snapshot_mcp(envelopes, to_ms, include_redacted);
    let from_map: HashMap<u64, &StateRowMcp> = from_rows.iter().map(|r| (r.offset, r)).collect();
    let to_map: HashMap<u64, &StateRowMcp> = to_rows.iter().map(|r| (r.offset, r)).collect();
    let mut all_offsets: BTreeSet<u64> = BTreeSet::new();
    all_offsets.extend(from_map.keys());
    all_offsets.extend(to_map.keys());
    let mut rows: Vec<DiffRowMcp> = Vec::with_capacity(all_offsets.len());
    for off in all_offsets {
        let f = from_map.get(&off);
        let t = to_map.get(&off);
        let (kind, from_payload, to_payload, sender) = match (f, t) {
            (None, Some(tr)) => (
                "added",
                None,
                Some(tr.payload.clone()),
                tr.sender_id.clone(),
            ),
            (Some(fr), None) => (
                "removed",
                Some(fr.payload.clone()),
                None,
                fr.sender_id.clone(),
            ),
            (Some(fr), Some(tr)) => {
                let kind = if fr.payload == tr.payload {
                    "unchanged"
                } else {
                    "edited"
                };
                (
                    kind,
                    Some(fr.payload.clone()),
                    Some(tr.payload.clone()),
                    tr.sender_id.clone(),
                )
            }
            (None, None) => unreachable!("offset came from union of both maps"),
        };
        rows.push(DiffRowMcp {
            offset: off,
            change_kind: kind,
            sender_id: sender,
            from_payload,
            to_payload,
        });
    }
    rows
}

/// T-1750: one row in the chronological receipt audit log. Mirror of CLI's
/// `AckHistoryRow` (channel.rs:6743). Distinct from a receipts-LWW snapshot
/// — this is the full append-log of every receipt envelope.
#[derive(Debug, Clone, PartialEq, Eq)]
struct AckHistoryRowMcp {
    receipt_offset: u64,
    sender_id: String,
    up_to: u64,
    ts_ms: i64,
}

impl AckHistoryRowMcp {
    fn to_json_mcp(&self) -> serde_json::Value {
        serde_json::json!({
            "receipt_offset": self.receipt_offset,
            "sender_id": self.sender_id,
            "up_to": self.up_to,
            "ts_ms": self.ts_ms,
        })
    }
}

/// T-1750: pure helper — chronological receipt audit log.
/// Mirror of CLI's `compute_ack_history` (channel.rs:6772).
///
/// One row per `msg_type=receipt` envelope with a parseable `metadata.up_to`.
/// When `user_filter = Some(uid)`, only receipts where `sender_id == uid`
/// survive.
///
/// Sort: ts_ms asc, receipt_offset asc tiebreak.
///
/// Filters: receipts with non-numeric / missing `metadata.up_to` are silently
/// dropped (malformed shape — not actionable as ack-state).
fn compute_ack_history_mcp(
    envelopes: &[serde_json::Value],
    user_filter: Option<&str>,
) -> Vec<AckHistoryRowMcp> {
    let mut rows: Vec<AckHistoryRowMcp> = Vec::new();
    for env in envelopes {
        if env.get("msg_type").and_then(|v| v.as_str()) != Some("receipt") {
            continue;
        }
        let off = match env.get("offset").and_then(|v| v.as_u64()) {
            Some(o) => o,
            None => continue,
        };
        let sender = env
            .get("sender_id")
            .and_then(|v| v.as_str())
            .unwrap_or("?")
            .to_string();
        if let Some(uid) = user_filter
            && sender != uid
        {
            continue;
        }
        let up_to = match env
            .get("metadata")
            .and_then(|md| md.get("up_to"))
            .and_then(|v| v.as_str())
            .and_then(|s| s.parse::<u64>().ok())
        {
            Some(u) => u,
            None => continue,
        };
        let ts = env
            .get("ts_unix_ms")
            .and_then(|v| v.as_i64())
            .or_else(|| env.get("ts").and_then(|v| v.as_i64()))
            .unwrap_or(0);
        rows.push(AckHistoryRowMcp {
            receipt_offset: off,
            sender_id: sender,
            up_to,
            ts_ms: ts,
        });
    }
    rows.sort_by(|a, b| {
        a.ts_ms
            .cmp(&b.ts_ms)
            .then_with(|| a.receipt_offset.cmp(&b.receipt_offset))
    });
    rows
}

