/// T-1753: pure helper — chronological audit of redaction events.
/// Mirror of CLI's `compute_redactions` (channel.rs:5491).
///
/// One row per `msg_type=redaction` envelope with parseable
/// `metadata.redacts`. Reason is best-effort (passed through if
/// `metadata.reason` exists). `target_payload` is best-effort from the
/// envelope set — `None` when target is missing.
///
/// Sort: `event_offset` ascending. Pure — no I/O.
fn compute_redactions_mcp(envelopes: &[serde_json::Value]) -> Vec<RedactionRowMcp> {
    use std::collections::HashMap;
    let mut by_off: HashMap<u64, &serde_json::Value> = HashMap::with_capacity(envelopes.len());
    for env in envelopes {
        if let Some(off) = env.get("offset").and_then(|v| v.as_u64()) {
            by_off.insert(off, env);
        }
    }
    let mut rows: Vec<RedactionRowMcp> = Vec::new();
    for env in envelopes {
        // Mirror of extract_redaction (channel.rs:3213) — inlined to avoid
        // exporting a new MCP-side helper for one call site.
        if env.get("msg_type").and_then(|v| v.as_str()) != Some("redaction") {
            continue;
        }
        let target = match env
            .get("metadata")
            .and_then(|md| md.get("redacts"))
            .and_then(|v| v.as_str())
            .and_then(|s| s.parse::<u64>().ok())
        {
            Some(t) => t,
            None => continue,
        };
        let off = match env.get("offset").and_then(|v| v.as_u64()) {
            Some(o) => o,
            None => continue,
        };
        let sender = env
            .get("sender_id")
            .and_then(|v| v.as_str())
            .unwrap_or("?")
            .to_string();
        let reason = env
            .get("metadata")
            .and_then(|md| md.get("reason"))
            .and_then(|v| v.as_str())
            .map(String::from);
        let ts = env
            .get("ts_unix_ms")
            .and_then(|v| v.as_i64())
            .or_else(|| env.get("ts").and_then(|v| v.as_i64()))
            .unwrap_or(0);
        let target_payload = by_off.get(&target).map(|e| decode_payload_lossy_mcp(e));
        rows.push(RedactionRowMcp {
            event_offset: off,
            target_offset: target,
            redactor_sender: sender,
            reason,
            ts_ms: ts,
            target_payload,
        });
    }
    rows.sort_by(|a, b| a.event_offset.cmp(&b.event_offset));
    rows
}

/// T-1755: aggregate full-topic stats. Mirror of CLI's `FullTopicStats`
/// (channel.rs:4727).
#[derive(Debug, Clone, PartialEq, Eq)]
struct FullTopicStatsMcp {
    total: usize,
    distinct_senders: usize,
    by_msg_type: Vec<(String, usize)>,
    top_senders: Vec<(String, usize)>,
    distinct_emojis: usize,
    top_emojis: Vec<(String, usize)>,
    thread_roots: usize,
    active_pins: usize,
    forwards_in: usize,
    edits: usize,
    redactions: usize,
    first_ts_ms: Option<i64>,
    last_ts_ms: Option<i64>,
}

impl FullTopicStatsMcp {
    fn to_json_mcp(&self) -> serde_json::Value {
        serde_json::json!({
            "total": self.total,
            "distinct_senders": self.distinct_senders,
            "by_msg_type": self.by_msg_type.iter().map(|(t, c)| serde_json::json!({"msg_type": t, "count": c})).collect::<Vec<_>>(),
            "top_senders": self.top_senders.iter().map(|(s, c)| serde_json::json!({"sender_id": s, "count": c})).collect::<Vec<_>>(),
            "distinct_emojis": self.distinct_emojis,
            "top_emojis": self.top_emojis.iter().map(|(e, c)| serde_json::json!({"emoji": e, "count": c})).collect::<Vec<_>>(),
            "thread_roots": self.thread_roots,
            "active_pins": self.active_pins,
            "forwards_in": self.forwards_in,
            "edits": self.edits,
            "redactions": self.redactions,
            "first_ts_ms": self.first_ts_ms,
            "last_ts_ms": self.last_ts_ms,
        })
    }
}

/// T-1755: pure helper — aggregate per-topic statistics. Mirror of CLI's
/// `compute_full_topic_stats` (channel.rs:4771) one-to-one.
///
/// Counters exclude redacted envelopes (their offset appears in
/// `redacted_offsets_mcp`). Redaction envelopes themselves are counted
/// separately under `redactions` (counted regardless of whether the
/// redaction envelope itself is redacted — first-pass logic).
///
/// Pin state is last-write-wins: each `pin` envelope sets active=true,
/// each `unpin` sets active=false, the final state determines `active_pins`.
///
/// Top-N lists are sorted by count desc with name asc tiebreak; truncated
/// to 5 rows. Time span uses `ts_unix_ms` (falling back to `ts`).
/// Pure — no I/O.
fn compute_full_topic_stats_mcp(envelopes: &[serde_json::Value]) -> FullTopicStatsMcp {
    use std::collections::{HashMap, HashSet};
    let redacted = redacted_offsets_mcp(envelopes);
    let mut total: usize = 0;
    let mut by_type: HashMap<String, usize> = HashMap::new();
    let mut by_sender: HashMap<String, usize> = HashMap::new();
    let mut emoji_count: HashMap<String, usize> = HashMap::new();
    let mut thread_roots_set: HashSet<u64> = HashSet::new();
    let mut active_pins: HashSet<u64> = HashSet::new();
    let mut forwards_in: usize = 0;
    let mut edits: usize = 0;
    let mut redactions: usize = 0;
    let mut first_ts: Option<i64> = None;
    let mut last_ts: Option<i64> = None;

    // First pass: count redactions specially.
    for env in envelopes {
        if env.get("msg_type").and_then(|v| v.as_str()) == Some("redaction") {
            redactions += 1;
        }
    }

    let mut pin_state: HashMap<u64, bool> = HashMap::new();

    for env in envelopes {
        let off = match env.get("offset").and_then(|v| v.as_u64()) {
            Some(o) => o,
            None => continue,
        };
        if redacted.contains(&off) {
            continue;
        }
        total += 1;
        let mt = env
            .get("msg_type")
            .and_then(|v| v.as_str())
            .unwrap_or("?")
            .to_string();
        *by_type.entry(mt.clone()).or_insert(0) += 1;
        let sender = env
            .get("sender_id")
            .and_then(|v| v.as_str())
            .unwrap_or("?")
            .to_string();
        *by_sender.entry(sender).or_insert(0) += 1;
        let ts = env
            .get("ts_unix_ms")
            .and_then(|v| v.as_i64())
            .or_else(|| env.get("ts").and_then(|v| v.as_i64()));
        if let Some(t) = ts {
            first_ts = Some(first_ts.map_or(t, |f| f.min(t)));
            last_ts = Some(last_ts.map_or(t, |l| l.max(t)));
        }
        match mt.as_str() {
            "reaction" => {
                let emoji = decode_payload_lossy_mcp(env);
                if !emoji.is_empty() {
                    *emoji_count.entry(emoji).or_insert(0) += 1;
                }
            }
            "edit" => {
                edits += 1;
            }
            "pin" => {
                if let Some(md) = env.get("metadata")
                    && let Some(target) = md
                        .get("pin_target")
                        .and_then(|v| v.as_str())
                        .and_then(|s| s.parse::<u64>().ok())
                {
                    let action = md.get("action").and_then(|v| v.as_str()).unwrap_or("pin");
                    pin_state.insert(target, action != "unpin");
                }
            }
            _ => {}
        }
        if let Some(parent) = parent_offset_of_mcp(env) {
            thread_roots_set.insert(parent);
        }
        if extract_forward_mcp(env).is_some() {
            forwards_in += 1;
        }
    }

    for (target, active) in &pin_state {
        if *active {
            active_pins.insert(*target);
        }
    }

    let distinct_senders = by_sender.len();
    let distinct_emojis = emoji_count.len();

    let mut by_msg_type: Vec<(String, usize)> = by_type.into_iter().collect();
    by_msg_type.sort_by(|a, b| b.1.cmp(&a.1).then_with(|| a.0.cmp(&b.0)));

    let mut top_senders: Vec<(String, usize)> = by_sender.into_iter().collect();
    top_senders.sort_by(|a, b| b.1.cmp(&a.1).then_with(|| a.0.cmp(&b.0)));
    top_senders.truncate(5);

    let mut top_emojis: Vec<(String, usize)> = emoji_count.into_iter().collect();
    top_emojis.sort_by(|a, b| b.1.cmp(&a.1).then_with(|| a.0.cmp(&b.0)));
    top_emojis.truncate(5);

    FullTopicStatsMcp {
        total,
        distinct_senders,
        by_msg_type,
        top_senders,
        distinct_emojis,
        top_emojis,
        thread_roots: thread_roots_set.len(),
        active_pins: active_pins.len(),
        forwards_in,
        edits,
        redactions,
        first_ts_ms: first_ts,
        last_ts_ms: last_ts,
    }
}

/// T-1758: one row in the currently-pinned set. Mirror of CLI's `PinRow`
/// (channel.rs:3540). `payload` is filled from the original envelope at
/// `target` if still present in the topic; `None` when the target is
/// out-of-range (rare). Empty string when payload is non-utf8.
#[derive(Debug, Clone, PartialEq, Eq)]
struct PinRowMcp {
    target: u64,
    pinned_by: String,
    pinned_ts: i64,
    payload: Option<String>,
}

impl PinRowMcp {
    fn to_json_mcp(&self) -> serde_json::Value {
        serde_json::json!({
            "target": self.target,
            "pinned_by": self.pinned_by,
            "pinned_ts": self.pinned_ts,
            "payload": self.payload,
        })
    }
}

/// T-1758: pure helper — compute the current pin set from a topic walk.
/// Mirror of CLI's `compute_pinned_set` (channel.rs:3575) one-to-one.
///
/// Iterates `envelopes` in input order, applying each `msg_type=pin` envelope
/// per its `metadata.action`:
///   - `action=pin` (default)   → record (or update) PinRowMcp for the target
///   - `action=unpin`           → remove the entry for the target
///
/// After the scan, the original envelope at each pinned target is looked up
/// to fill `payload`. Sorted by `pinned_ts` descending (most-recently pinned
/// first); ties break on `target` ascending for determinism.
///
/// Pure — no I/O.
fn compute_pinned_set_mcp(envelopes: &[serde_json::Value]) -> Vec<PinRowMcp> {
    use std::collections::HashMap;
    let mut by_off: HashMap<u64, &serde_json::Value> = HashMap::with_capacity(envelopes.len());
    for env in envelopes {
        if let Some(off) = env.get("offset").and_then(|v| v.as_u64()) {
            by_off.insert(off, env);
        }
    }
    let mut active: HashMap<u64, PinRowMcp> = HashMap::new();
    for env in envelopes {
        if env.get("msg_type").and_then(|v| v.as_str()) != Some("pin") {
            continue;
        }
        let md = match env.get("metadata") {
            Some(m) => m,
            None => continue,
        };
        let target = match md
            .get("pin_target")
            .and_then(|v| v.as_str())
            .and_then(|s| s.parse::<u64>().ok())
        {
            Some(t) => t,
            None => continue,
        };
        let action = md.get("action").and_then(|v| v.as_str()).unwrap_or("pin");
        if action == "unpin" {
            active.remove(&target);
            continue;
        }
        let pinned_by = env
            .get("sender_id")
            .and_then(|v| v.as_str())
            .unwrap_or("?")
            .to_string();
        let pinned_ts = env
            .get("ts_unix_ms")
            .and_then(|v| v.as_i64())
            .or_else(|| env.get("ts").and_then(|v| v.as_i64()))
            .unwrap_or(0);
        active.insert(
            target,
            PinRowMcp {
                target,
                pinned_by,
                pinned_ts,
                payload: None,
            },
        );
    }
    for row in active.values_mut() {
        if let Some(orig) = by_off.get(&row.target) {
            row.payload = Some(decode_payload_lossy_mcp(orig));
        }
    }
    let mut rows: Vec<PinRowMcp> = active.into_values().collect();
    rows.sort_by(|a, b| {
        b.pinned_ts
            .cmp(&a.pinned_ts)
            .then_with(|| a.target.cmp(&b.target))
    });
    rows
}

/// T-1759: one row in the currently-starred set. Mirror of CLI's `StarRow`
/// (channel.rs:3708). Like pins but keyed by `(sender_id, target)` because
/// stars are personal bookmarks (each user can star a post independently),
/// not a shared curation surface.
#[derive(Debug, Clone, PartialEq, Eq)]
struct StarRowMcp {
    target: u64,
    starred_by: String,
    starred_ts: i64,
    payload: Option<String>,
}

impl StarRowMcp {
    fn to_json_mcp(&self) -> serde_json::Value {
        serde_json::json!({
            "target": self.target,
            "starred_by": self.starred_by,
            "starred_ts": self.starred_ts,
            "payload": self.payload,
        })
    }
}

/// T-1759: pure helper — compute the current star set from a topic walk.
/// Mirror of CLI's `compute_starred_set` (channel.rs:3741) one-to-one.
///
/// Iterates `envelopes` in input order, applying each `msg_type=star`
/// envelope per its `metadata.star` flag, keyed by `(sender_id, star_target)`:
///   - `star=true` (default)   → record/update StarRowMcp
///   - `star=false`            → remove the entry
///
/// When `caller` is `Some(fp)`, only stars by that fingerprint are returned
/// (use case: "what have I starred"). When `caller` is `None`, all users'
/// stars are returned (use case: "what's interesting to the room").
///
/// After the scan, the original envelope at each starred target is looked
/// up to fill `payload`. Sorted by `starred_ts` desc; ties break on
/// `(target, starred_by)` asc for determinism. Pure — no I/O.
fn compute_starred_set_mcp(
    envelopes: &[serde_json::Value],
    caller: Option<&str>,
) -> Vec<StarRowMcp> {
    use std::collections::HashMap;
    let mut by_off: HashMap<u64, &serde_json::Value> = HashMap::with_capacity(envelopes.len());
    for env in envelopes {
        if let Some(off) = env.get("offset").and_then(|v| v.as_u64()) {
            by_off.insert(off, env);
        }
    }
    let mut active: HashMap<(String, u64), StarRowMcp> = HashMap::new();
    for env in envelopes {
        if env.get("msg_type").and_then(|v| v.as_str()) != Some("star") {
            continue;
        }
        let md = match env.get("metadata") {
            Some(m) => m,
            None => continue,
        };
        let target = match md
            .get("star_target")
            .and_then(|v| v.as_str())
            .and_then(|s| s.parse::<u64>().ok())
        {
            Some(t) => t,
            None => continue,
        };
        let star_flag = md.get("star").and_then(|v| v.as_str()).unwrap_or("true");
        let sender = env
            .get("sender_id")
            .and_then(|v| v.as_str())
            .unwrap_or("?")
            .to_string();
        if let Some(fp) = caller
            && sender != fp
        {
            continue;
        }
        let key = (sender.clone(), target);
        if star_flag == "false" {
            active.remove(&key);
            continue;
        }
        let starred_ts = env
            .get("ts_unix_ms")
            .and_then(|v| v.as_i64())
            .or_else(|| env.get("ts").and_then(|v| v.as_i64()))
            .unwrap_or(0);
        active.insert(
            key,
            StarRowMcp {
                target,
                starred_by: sender,
                starred_ts,
                payload: None,
            },
        );
    }
    for row in active.values_mut() {
        if let Some(orig) = by_off.get(&row.target) {
            row.payload = Some(decode_payload_lossy_mcp(orig));
        }
    }
    let mut rows: Vec<StarRowMcp> = active.into_values().collect();
    rows.sort_by(|a, b| {
        b.starred_ts
            .cmp(&a.starred_ts)
            .then_with(|| a.target.cmp(&b.target))
            .then_with(|| a.starred_by.cmp(&b.starred_by))
    });
    rows
}

/// T-1760: one row in the per-sender ack-status dashboard. Mirror of CLI's
/// `AckStatusRow` (channel.rs:7184). `up_to=None` for members who posted
/// but never emitted a receipt (the "ghost lurker" case — surfaced with
/// lag=latest+1 so they sort to the top of the pending list).
#[derive(Debug, Clone, PartialEq, Eq)]
struct AckStatusRowMcp {
    sender_id: String,
    up_to: Option<u64>,
    latest: u64,
    lag: u64,
    receipt_ts: i64,
}

impl AckStatusRowMcp {
    fn to_json_mcp(&self) -> serde_json::Value {
        serde_json::json!({
            "sender_id": self.sender_id,
            "up_to": self.up_to,
            "latest": self.latest,
            "lag": self.lag,
            "ts": self.receipt_ts,
        })
    }
}

/// T-1760: pure helper — compute the per-sender ack-status rows. Mirror of
/// CLI's `compute_ack_status` (channel.rs:7216) one-to-one.
///
/// Inputs:
/// - `envelopes`: full topic walk (used to extract member set)
/// - `receipts`: latest receipt per sender, as `(sender_id -> (up_to, ts))`
/// - `latest_offset`: max offset in the topic
///
/// Rows:
/// - Senders with a receipt: `up_to=Some(U)`, `lag=max(0, latest-U)`
/// - Senders who posted content but never acked: `up_to=None`, `lag=latest+1`
///   (ranks them above ackers in the pending list — surfaces ghost lurkers).
///
/// Members are the UNION of envelope senders (anyone with sender_id, even
/// reaction-only "lurkers") AND receipt-only senders. Sort: lag descending;
/// sender_id ascending tiebreak. Pure — no I/O.
fn compute_ack_status_mcp(
    envelopes: &[serde_json::Value],
    receipts: &std::collections::HashMap<String, (u64, i64)>,
    latest_offset: u64,
) -> Vec<AckStatusRowMcp> {
    use std::collections::HashSet;
    let mut members: HashSet<String> = HashSet::new();
    for env in envelopes {
        if let Some(s) = env.get("sender_id").and_then(|v| v.as_str()) {
            members.insert(s.to_string());
        }
    }
    for sender in receipts.keys() {
        members.insert(sender.clone());
    }
    let mut rows: Vec<AckStatusRowMcp> = members
        .into_iter()
        .map(|sender_id| match receipts.get(&sender_id) {
            Some((up_to, ts)) => {
                let lag = latest_offset.saturating_sub(*up_to);
                AckStatusRowMcp {
                    sender_id,
                    up_to: Some(*up_to),
                    latest: latest_offset,
                    lag,
                    receipt_ts: *ts,
                }
            }
            None => AckStatusRowMcp {
                sender_id,
                up_to: None,
                latest: latest_offset,
                lag: latest_offset + 1,
                receipt_ts: 0,
            },
        })
        .collect();
    rows.sort_by(|a, b| {
        b.lag
            .cmp(&a.lag)
            .then_with(|| a.sender_id.cmp(&b.sender_id))
    });
    rows
}

