/// T-1769: pure helper — per-target reply rollup. Mirrors CLI
/// `compute_quote_stats` (commands/channel.rs:6287).
///
/// One row per target offset that has at least one surviving reply.
/// Filters:
/// - replies are envelopes with parseable `metadata.in_reply_to` AND
///   `msg_type != "reaction"` (reactions are not replies)
/// - reply offsets that are themselves redacted are excluded
/// - target offsets that are themselves redacted drop their row entirely
///
/// `distinct_repliers` is sorted-asc (BTreeSet → Vec).
/// Sort: reply_count desc, target_offset asc tiebreak.
fn compute_quote_stats_mcp(envelopes: &[serde_json::Value]) -> Vec<QuoteStatsRowMcp> {
    use std::collections::{BTreeSet, HashMap};
    let redacted = redacted_offsets_mcp(envelopes);
    let mut by_off: HashMap<u64, &serde_json::Value> = HashMap::with_capacity(envelopes.len());
    for env in envelopes {
        if let Some(off) = env.get("offset").and_then(|v| v.as_u64()) {
            by_off.insert(off, env);
        }
    }
    // target -> (count, BTreeSet<sender>, latest_ts)
    let mut by_target: HashMap<u64, (u64, BTreeSet<String>, i64)> = HashMap::new();
    for env in envelopes {
        let mt = env.get("msg_type").and_then(|v| v.as_str()).unwrap_or("");
        if mt == "reaction" {
            continue;
        }
        let off = match env.get("offset").and_then(|v| v.as_u64()) {
            Some(o) => o,
            None => continue,
        };
        if redacted.contains(&off) {
            continue;
        }
        let parent = match parent_offset_of_mcp(env) {
            Some(p) => p,
            None => continue,
        };
        let sender = env
            .get("sender_id")
            .and_then(|v| v.as_str())
            .unwrap_or("?")
            .to_string();
        let ts = env
            .get("ts_unix_ms")
            .and_then(|v| v.as_i64())
            .or_else(|| env.get("ts").and_then(|v| v.as_i64()))
            .unwrap_or(0);
        let entry = by_target
            .entry(parent)
            .or_insert((0, BTreeSet::new(), i64::MIN));
        entry.0 += 1;
        entry.1.insert(sender);
        if ts > entry.2 {
            entry.2 = ts;
        }
    }
    let mut rows: Vec<QuoteStatsRowMcp> = by_target
        .into_iter()
        .filter_map(|(target, (count, repliers, latest_ts))| {
            if redacted.contains(&target) {
                return None;
            }
            let target_env = by_off.get(&target)?;
            Some(QuoteStatsRowMcp {
                target_offset: target,
                target_sender: target_env
                    .get("sender_id")
                    .and_then(|v| v.as_str())
                    .unwrap_or("")
                    .to_string(),
                target_payload: decode_payload_lossy_mcp(target_env),
                reply_count: count,
                distinct_repliers: repliers.into_iter().collect(),
                latest_reply_ts_ms: latest_ts,
            })
        })
        .collect();
    rows.sort_by(|a, b| {
        b.reply_count
            .cmp(&a.reply_count)
            .then_with(|| a.target_offset.cmp(&b.target_offset))
    });
    rows
}

/// T-1771: pure helper — payload matcher. Mirrors CLI `payload_matches`
/// (commands/channel.rs:8493). When `regex=true`, compiles the pattern
/// (with `(?i)` prefix if case-insensitive); otherwise falls back to
/// substring match (lowercased on both sides if case-insensitive).
fn payload_matches_mcp(
    text: &str,
    pattern: &str,
    regex: bool,
    case_sensitive: bool,
) -> Result<bool, String> {
    if regex {
        let effective = if case_sensitive {
            pattern.to_string()
        } else {
            format!("(?i){pattern}")
        };
        let re = ::regex::Regex::new(&effective)
            .map_err(|e| format!("invalid regex pattern '{pattern}': {e}"))?;
        Ok(re.is_match(text))
    } else if case_sensitive {
        Ok(text.contains(pattern))
    } else {
        Ok(text.to_lowercase().contains(&pattern.to_lowercase()))
    }
}

/// T-1762: pure helper — given an offset→envelope map and a leaf offset,
/// walk up the `metadata.in_reply_to` chain until reaching a root post
/// (no parent recorded) or a missing parent (chain breaks).
/// Returns the chain root→leaf order. Mirrors CLI `build_ancestors`
/// (commands/channel.rs:2592) one-to-one — cycle-safe via visited set,
/// depth-capped via `max_depth`. Used by `termlink_channel_ancestors`.
///
/// - If `leaf` is absent from the map, returns empty vec.
/// - If the chain hits a cycle, stops at the cycle point (no re-emission).
/// - If the chain hits a missing parent, stops at the last present envelope.
fn compute_ancestors_mcp(
    by_offset: &std::collections::HashMap<u64, &serde_json::Value>,
    leaf: u64,
    max_depth: usize,
) -> Vec<u64> {
    let mut chain: Vec<u64> = Vec::new();
    let mut visited: std::collections::HashSet<u64> = std::collections::HashSet::new();
    let mut current = leaf;
    if !by_offset.contains_key(&current) {
        return chain;
    }
    for _ in 0..max_depth {
        if !visited.insert(current) {
            break;
        }
        chain.push(current);
        let Some(env) = by_offset.get(&current) else { break };
        let parent = env
            .get("metadata")
            .and_then(|md| md.get("in_reply_to"))
            .and_then(|v| v.as_str())
            .and_then(|s| s.parse::<u64>().ok());
        let Some(p) = parent else { break };
        if !by_offset.contains_key(&p) {
            break;
        }
        current = p;
    }
    chain.reverse(); // root → leaf
    chain
}

/// T-1744: parse the first CERTIFICATE block in a PEM string and return its
/// sha256:<hex> fingerprint. Mirror of CLI cmd_hub_fingerprint's PEM parsing
/// + base64-decode + cert_fingerprint chain (infrastructure.rs:946-969).
/// Pure — no filesystem access.
///
/// Returns Err with a human-readable message if the PEM is malformed.
/// Defensive: handles concatenated certs (uses first only), filters whitespace
/// from base64 body, and reports the failing stage in the error message.
fn parse_first_cert_block_to_fingerprint(pem: &str) -> Result<String, String> {
    use base64::Engine;
    let begin_marker = "-----BEGIN CERTIFICATE-----";
    let end_marker = "-----END CERTIFICATE-----";
    let start = pem
        .find(begin_marker)
        .ok_or_else(|| "no CERTIFICATE block in PEM".to_string())?;
    let end = pem
        .find(end_marker)
        .ok_or_else(|| "malformed CERTIFICATE block (no END marker)".to_string())?;
    if end <= start + begin_marker.len() {
        return Err("malformed CERTIFICATE block (END before BEGIN body)".to_string());
    }
    let body = &pem[start + begin_marker.len()..end];
    let b64: String = body.chars().filter(|c| !c.is_whitespace()).collect();
    let der = base64::engine::general_purpose::STANDARD
        .decode(b64.as_bytes())
        .map_err(|e| format!("base64-decode failed: {e}"))?;
    Ok(termlink_session::tofu::cert_fingerprint(&der))
}

/// T-1743: shape raw `event.subscribe` events from the `agent.request` topic
/// into the same JSON the CLI's `cmd_agent_listen --json` produces. Pure — no
/// I/O. Mirror of agent.rs:278-287.
///
/// Each input event is `{"seq": N, "payload": {AgentRequest fields...}}` (the
/// envelope produced by event.subscribe). We project out `{seq, from, action,
/// request_id, params, timeout_secs}` so MCP consumers get a stable shape
/// instead of having to dig through nested envelope JSON. Each output element
/// also carries `"ok": true` matching the CLI's `--json` per-line convention.
///
/// Events whose `payload` is missing or non-object are still emitted (with
/// null fields) — we preserve the upstream count so callers can use
/// `events.len()` for empty-batch detection without doing a separate count.
fn shape_agent_request_events_mcp(events: &[serde_json::Value]) -> Vec<serde_json::Value> {
    events
        .iter()
        .map(|event| {
            let payload = &event["payload"];
            serde_json::json!({
                "ok": true,
                "seq": event["seq"],
                "from": payload["from"],
                "action": payload["action"],
                "request_id": payload["request_id"],
                "params": payload["params"],
                "timeout_secs": payload["timeout_secs"],
            })
        })
        .collect()
}

