/// T-1715: MCP-side parity for the `termlink agent contact` CLI verb (T-1429
/// Phase-1 + Phase-2 partial). Targets a peer agent on its canonical
/// `dm:<a>:<b>` topic. v1 scope: target / target_fp (mutually exclusive),
/// message body, thread, dry_run, sender_id override. v2 will add
/// require_online + ack_required (CLI ships these via T-1480 / T-1485 but
/// they need extra wiring on the MCP side for the presence-probe / ack-poll
/// loops).
#[derive(Deserialize, JsonSchema)]
pub struct AgentContactParams {
    /// Peer session display name to contact. Resolved via local
    /// `manager::find_session` to read the peer's identity_fingerprint
    /// from `SessionMetadata` (T-1436). Optionally qualified with
    /// `:project` to stamp `metadata.to_project=<project>` on the dm post
    /// (T-1448 (b)). Mutually exclusive with `target_fp`; exactly one
    /// required.
    pub target: Option<String>,
    /// Peer's identity fingerprint (hex, ≥8 chars). Cross-host bypass for
    /// the local-only `session.discover` path — useful when the peer is on
    /// a remote hub and not locally resolvable. Mutually exclusive with
    /// `target`; exactly one required.
    pub target_fp: Option<String>,
    /// Message body. Mutually exclusive with `body_file` (T-1717); exactly
    /// one of `message` / `body_file` required. v1 callers that always set
    /// `message` continue working unchanged (PL-172 byte-identical default).
    pub message: Option<String>,
    /// T-1717: path to a file whose contents become the message body. Mirror
    /// of CLI `--file PATH` (T-1646, `commands::agent::resolve_contact_message`).
    /// Mutually exclusive with `message`. Empty file rejected. Path resolves
    /// against the MCP server's current working directory — pass an absolute
    /// path when cwd is ambiguous. Useful for long-form structured payloads
    /// (inception findings, RCAs, code reviews) that are awkward to inline
    /// as a single JSON-escaped string at the MCP boundary.
    pub body_file: Option<String>,
    /// Optional task-id for `metadata._thread` routing per the agent-chat-arc
    /// protocol canon (T-1430 topic doc). Vendored agents can group dm:*
    /// messages by thread server-side without parsing the body.
    pub thread: Option<String>,
    /// If true, preview the resolved dm topic + metadata as JSON without
    /// posting (mirrors CLI `--dry-run` / T-1478). Useful in CI or ops
    /// validation to confirm name resolution + metadata stamping before
    /// committing to a real post.
    pub dry_run: Option<bool>,
    /// Override sender_id (default: local identity fingerprint).
    pub sender_id: Option<String>,
    /// T-1716: pre-flight presence check (mirror of CLI `--require-online`,
    /// T-1480). When true, probes `agent-chat-arc` for the peer's fingerprint
    /// within `online_window_secs` BEFORE posting. If the peer has no posts
    /// in the window, returns `{ok: false, online_check: {...}, error: ...}`
    /// without posting. Default: false (no probe, behavior identical to v1).
    pub require_online: Option<bool>,
    /// T-1716: window (seconds) for `require_online` presence check. Clamped
    /// to [10, 86400]; default 300 (5 min). Ignored when `require_online` is
    /// false or unset.
    pub online_window_secs: Option<u64>,
    /// T-1716: synchronous ack wait (mirror of CLI `--ack-required`, T-1485).
    /// When true, after posting, polls the dm topic at ~1s cadence for any
    /// non-meta envelope from the peer with `ts > send_ts_ms`. Returns
    /// `{ok: true, ack: {received: bool, ts_ms?, wait_secs}}` — received=true
    /// on match, received=false on timeout. Default: false (fire-and-forget).
    pub ack_required: Option<bool>,
    /// T-1716: timeout (seconds) for `ack_required` poll. Clamped to [5, 600];
    /// default 60. Ignored when `ack_required` is false or unset.
    pub ack_timeout_secs: Option<u64>,
}

