#[derive(Deserialize, JsonSchema)]
pub struct HelpParams {
    /// Filter by category: session, execution, events, kv, files, hub, tofu, fleet,
    /// remote, batch, dispatch, tokens, channel*, agent_*, diagnostics. Omit to see all.
    pub category: Option<String>,
    /// Substring-search across tool names AND descriptions (case-insensitive).
    /// Returns a flat `matches` array of `{category, name, description}`.
    /// Combine with `category` to scope the search within one category.
    /// Use when you know roughly what you want (e.g. "redact", "fleet", "thread")
    /// but not the exact category. T-1940.
    pub name_filter: Option<String>,
    /// Overview mode: when true, returns category names + tool counts + a
    /// one-line `description` per category
    /// (`{categories: [{name, tool_count, description}, ...], total_categories, total_tools}`).
    /// Use for cold-start two-step discovery — get the ~27-row overview with
    /// purpose hints, then drill in via `category=<name>` for the per-tool
    /// detail. When set, `category` and `name_filter` are ignored. T-1948 +
    /// T-1957 (per-category description).
    pub list_categories: Option<bool>,
    /// Drill-in mode: pass a tool name (e.g. `termlink_agent_post`) to get its
    /// category + short registry description + the full `#[tool(description=…)]`
    /// macro text in one round-trip. Closes the 3-step discovery loop
    /// (list_categories → category → tool_detail). When set, all other params
    /// are ignored. T-1952.
    pub tool_detail: Option<String>,
    /// Aggregate-shape mode: when true, returns a one-shot snapshot of the
    /// registry — `{total_tools, total_categories, total_deprecated,
    /// deprecated_by_category, largest_categories, smallest_categories}` —
    /// so an MCP client can size the API surface in a single call instead of
    /// enumerating `list_categories` + N drill-ins. All fields derive live
    /// from `help_categories()` + `is_deprecated()` so the snapshot cannot
    /// drift from the registry. `largest_categories` / `smallest_categories`
    /// are capped at 5 entries each; `deprecated_by_category` lists only
    /// categories with at least one deprecated tool. Takes precedence over
    /// `list_categories`, `name_filter`, and `category`; `tool_detail` is
    /// the only mode with higher precedence. T-1963.
    pub summary: Option<bool>,
    /// Canonical entry-point mode: when true, returns a focused starter set
    /// — `{essentials: [{name, category, description}], total}` — picking
    /// the FIRST non-deprecated tool of each category (registry order =
    /// author's canonical ordering). Gives MCP clients a ~27-tool cold-start
    /// view instead of the 252-tool full listing. Auto-derived from
    /// `help_categories()` + `is_deprecated()` so the set cannot drift from
    /// the registry. Categories whose tools are ALL deprecated are skipped.
    /// Precedence: `tool_detail` > `essentials` > `summary` >
    /// `list_categories` > `name_filter`. T-1968.
    pub essentials: Option<bool>,
    /// Cost-aware-search filter: when set, suppresses matches whose
    /// `parameter_count` exceeds this threshold. Composes with `name_filter`
    /// (filtered name-search) AND stands alone (filter the entire registry
    /// by arity). With `name_filter`, answers "find me simple tools matching
    /// X". Standalone with `max_parameters=0`, lists every zero-arg primitive
    /// — the canonical no-config tools. Output shape unchanged
    /// (`{matches:[...], total_matches}`); only the row set shrinks. T-1975.
    pub max_parameters: Option<usize>,
    /// Lower-bound arity filter — mirror of `max_parameters`. When set,
    /// suppresses matches whose `parameter_count` is BELOW this threshold.
    /// Composes with `max_parameters` for arity-range queries:
    /// `min_parameters=2, max_parameters=4, name_filter='channel'` returns
    /// only channel-family tools with 2-4 parameters in one round-trip.
    /// Standalone (no `name_filter`), `min_parameters=5` walks the registry
    /// and returns every rich-API tool — useful when the LLM wants to find
    /// configurable primitives without enumerating the full catalog. T-1976.
    pub min_parameters: Option<usize>,
    /// Retirement-WIP filter: when true, suppresses matches whose
    /// `deprecated==true`. Composes with `name_filter`, `min_parameters`,
    /// and `max_parameters` for clean discovery queries — e.g.
    /// `name_filter='inbox', exclude_deprecated=true` returns only the
    /// live channel-based alternatives, hiding the legacy `termlink_inbox_*`
    /// primitives that T-1166 is retiring. Output shape unchanged (rows
    /// still carry `deprecated` field, the row set just shrinks). T-1977.
    pub exclude_deprecated: Option<bool>,
    /// Migration-planning filter: symmetric inverse of `exclude_deprecated`.
    /// When true, suppresses LIVE rows — only deprecated retirement-WIP
    /// tools surface. Composes with `name_filter`, the arity bounds, and
    /// `category` — e.g. `name_filter='inbox', deprecated_only=true` lists
    /// every retirement-WIP inbox tool for migration planning. If both
    /// `exclude_deprecated` and `deprecated_only` are true the intersection
    /// is empty and the hint explains the conflict. T-1982.
    pub deprecated_only: Option<bool>,
    /// Pagination cap for `name_filter` (and standalone-arity-filter) mode.
    /// When set, caps `matches[]` at the first N entries (deterministic order:
    /// category iteration order × registry order within each category). The
    /// response gains `total_matched` (pre-cap count) and `limit_applied`
    /// (true iff truncation actually happened) so clients can detect and
    /// paginate. Ignored in other modes (`tool_detail`, `list_categories`,
    /// `summary`, `essentials`, default). `limit=0` returns an empty
    /// `matches[]` but still surfaces `total_matched` so a caller can decide
    /// whether the query was worth pursuing. Without `limit`, behavior and
    /// envelope shape are unchanged (backward compat). T-1984.
    pub limit: Option<usize>,
    /// Pagination cursor for `name_filter` (and standalone-arity-filter)
    /// mode. Pairs with `limit` to enable real paging: `offset=10, limit=10`
    /// returns rows 10..20 of the deterministic-order match set. Filters
    /// (arity, deprecated, category) run BEFORE offset, so the window
    /// slices the filtered set. The envelope echoes `offset` and surfaces
    /// `next_offset` (== offset + matches.len()) when more matches exist
    /// beyond the current window — absent when exhausted. `offset` past
    /// the end returns an empty `matches[]` with `total_matched` still set
    /// so the caller sees the overshoot. Ignored in other modes. Without
    /// `offset`, behavior unchanged (backward compat). T-1994.
    pub offset: Option<usize>,
    /// Deterministic sort axis for `name_filter` (and standalone-arity-filter)
    /// mode. Accepts `name` (alphabetical ASC), `arity` (parameter_count ASC),
    /// `required_arity` (parameter_required_count ASC), or `category`
    /// (category alphabetical, registry order within). Sort runs AFTER all
    /// filters (arity, deprecated, category, needle) and BEFORE pagination,
    /// so `offset` + `limit` slice the sorted sequence. Stable sort —
    /// registry walk order is preserved on ties, keeping pagination
    /// invariants stable across pages. Envelope emits `sort_by_applied`
    /// echoing the value on success. Unknown values fall through (no sort,
    /// matches stay in registry order) and emit `sort_by_unknown` so the
    /// caller sees the request was silently dropped instead of misread.
    /// Ignored in other modes. Without `sort_by`, behavior unchanged
    /// (backward compat). Pairs with `parameter_required_count` for
    /// cost-aware ranking: `sort_by='required_arity', limit=10` returns
    /// the 10 cheapest-to-call matches. T-1996.
    pub sort_by: Option<String>,
    /// Row projection for `name_filter` (and bulk-flat-listing) mode.
    /// When set to a non-empty list, every row in `matches[]` is filtered
    /// to retain ONLY the requested keys (strict — no implicit field
    /// retention; if the caller wants `name` they include it). Allowed
    /// values: `name`, `category`, `category_tool_count`, `description`,
    /// `deprecated`, `parameter_count`, `parameter_required_count`,
    /// `replacement_hint`. Unknown values are silently dropped from the
    /// projection AND surfaced via the envelope `fields_unknown` list so
    /// the LLM client sees the silently-ignored input rather than
    /// misreading the response. The envelope emits `fields_applied`
    /// echoing the recognized fields on success. Empty `fields:[]` is
    /// degenerate and treated as no projection (envelope omits both
    /// flags). Without `fields`, behavior unchanged (backward compat).
    /// Pairs with `limit`/`sort_by`/`parameter_required_count` to shrink
    /// paged responses by ~80% when prose descriptions aren't needed —
    /// e.g. `fields=['name','parameter_required_count'], sort_by=
    /// 'required_arity', limit=20` returns 20 cheap-to-call name+arity
    /// rows for a downstream ranking pass. T-1998.
    pub fields: Option<Vec<String>>,
    /// Multi-namespace scope filter for `name_filter` and bulk-flat-listing
    /// mode. When set to a non-empty array, takes precedence over single
    /// `category` and filters to rows whose category is in the set —
    /// e.g. `categories=['channel','agent_chat','agent_inbox']` returns
    /// matches in the messaging-arc namespaces in one round-trip. Unknown
    /// category names are silently dropped from the filter AND surfaced
    /// via the envelope `categories_unknown` list so the LLM client sees
    /// the silently-ignored input (mirrors `sort_by_unknown` and
    /// `fields_unknown`). The envelope emits `categories_applied`
    /// echoing the recognized subset. Empty `categories:[]` is
    /// degenerate and treated as no multi-filter (falls back to single
    /// `category` if set, otherwise no scope). Without `categories`,
    /// behavior unchanged (backward compat). T-1999.
    pub categories: Option<Vec<String>>,
    /// Negative multi-namespace filter for `name_filter` and bulk-flat-listing
    /// mode. When set to a non-empty array, drops rows whose category is in
    /// the set — use it to exclude noise namespaces from registry-wide
    /// queries (e.g. `exclude_categories=['agent_chat','agent_inbox']` for
    /// a query over everything except the messaging-arc rows). Composes
    /// with `categories` and single `category`: when both positive and
    /// negative are set, exclusion wins on overlap (intersection-minus-
    /// exclusion semantic). Unknown names dropped from the filter AND
    /// surfaced via envelope `exclude_categories_unknown`; recognized
    /// ones echoed via `exclude_categories_applied`. Empty
    /// `exclude_categories:[]` is degenerate and treated as no exclusion.
    /// Without `exclude_categories`, behavior unchanged (backward compat).
    /// T-2000.
    pub exclude_categories: Option<Vec<String>>,
}

