    #[tool(
        name = "termlink_remote_doctor",
        description = "Health check a remote hub — connectivity, sessions, inbox status. Returns pass/warn/fail checks. The hub address can be host:port or a profile name from ~/.termlink/hubs.toml."
    )]
    async fn termlink_remote_doctor(&self, Parameters(p): Parameters<RemoteDoctorParams>) -> String {
        let scope = p.scope.as_deref().unwrap_or("execute");
        let timeout = std::time::Duration::from_secs(p.timeout.unwrap_or(10));

        let fut = async move {
            let mut checks: Vec<serde_json::Value> = Vec::new();
            let mut pass_count: u32 = 0;
            let mut warn_count: u32 = 0;
            // T-1620: was `let fail_count` (immutable) — every probe outcome was
            // forced to warn or pass and the summary `fail` field was a tautology
            // (always 0 → `"ok": true` even on hub-side probe failure). PL-152.
            let mut fail_count: u32 = 0;

            // 1. Connectivity
            let connect_start = std::time::Instant::now();
            let mut rpc_client = match connect_remote_hub_mcp(
                &p.hub, p.secret_file.as_deref(), p.secret.as_deref(), scope,
            ).await {
                Ok(c) => {
                    let latency = connect_start.elapsed().as_millis();
                    pass_count += 1;
                    checks.push(serde_json::json!({"check": "connectivity", "status": "pass", "message": format!("connected in {}ms", latency)}));
                    c
                }
                Err(e) => {
                    return e;
                }
            };

            // 2. Sessions (use session.discover — hub-level method, not session.list which requires target)
            match rpc_client.call("session.discover", serde_json::json!("mcp-doc-sd"), serde_json::json!({})).await {
                Ok(termlink_protocol::jsonrpc::RpcResponse::Success(r)) => {
                    if let Some(sessions) = r.result["sessions"].as_array() {
                        let count = sessions.len();
                        let names: Vec<&str> = sessions.iter()
                            .filter_map(|s| s["display_name"].as_str())
                            .collect();
                        pass_count += 1;
                        checks.push(serde_json::json!({"check": "sessions", "status": "pass", "message": format!("{} session(s): {}", count, names.join(", "))}));
                    } else {
                        warn_count += 1;
                        checks.push(serde_json::json!({"check": "sessions", "status": "warn", "message": "unexpected response format"}));
                    }
                }
                Ok(termlink_protocol::jsonrpc::RpcResponse::Error(e)) => {
                    warn_count += 1;
                    checks.push(serde_json::json!({"check": "sessions", "status": "warn", "message": format!("session.discover error: {}", e.error.message)}));
                }
                Err(e) => {
                    warn_count += 1;
                    checks.push(serde_json::json!({"check": "sessions", "status": "warn", "message": format!("RPC failed: {}", e)}));
                }
            }

            // 3. Inbox.
            //
            // T-1400/T-1415: Probes inbox state via channel.list(prefix="inbox:").
            // The legacy `inbox.status` RPC was retired in T-1166 / T-1415 — its
            // hub-side handler no longer exists, so the prior dual-probe fallback
            // would always fail on the inbox.status leg. channel.list is the only
            // load-bearing path now. Parallel to commands/infrastructure.rs::doctor
            // step 7.
            let inbox_outcome: Result<(u64, usize), String> = match rpc_client
                .call(
                    "channel.list",
                    serde_json::json!("mcp-doc-cl"),
                    serde_json::json!({"prefix": "inbox:"}),
                )
                .await
            {
                Ok(termlink_protocol::jsonrpc::RpcResponse::Success(r)) => {
                    let topics = r.result["topics"].as_array().cloned().unwrap_or_default();
                    let target_count = topics.len();
                    let total: u64 = topics
                        .iter()
                        .filter_map(|t| t["count"].as_u64())
                        .sum();
                    Ok((total, target_count))
                }
                Ok(termlink_protocol::jsonrpc::RpcResponse::Error(e)) => {
                    Err(format!("channel.list error: {}", e.error.message))
                }
                Err(e) => Err(format!("RPC failed: {}", e)),
            };

            match inbox_outcome {
                Ok((0, _)) => {
                    pass_count += 1;
                    checks.push(serde_json::json!({"check": "inbox", "status": "pass", "message": "no pending transfers"}));
                }
                Ok((total, targets)) => {
                    warn_count += 1;
                    checks.push(serde_json::json!({"check": "inbox", "status": "warn", "message": format!("{} pending transfer(s) for {} target(s)", total, targets)}));
                }
                Err(msg) => {
                    // T-1620 / T-1415: channel.list is the sole inbox probe
                    // post-cut; failure is a structural fail (not warn) per
                    // PL-152.
                    fail_count += 1;
                    checks.push(serde_json::json!({"check": "inbox", "status": "fail", "message": msg}));
                }
            }

            serde_json::to_string_pretty(&serde_json::json!({
                "ok": fail_count == 0,
                "hub": p.hub,
                "checks": checks,
                "summary": {"pass": pass_count, "warn": warn_count, "fail": fail_count}
            })).unwrap_or_else(json_err)
        };

        match tokio::time::timeout(timeout, fut).await {
            Ok(response) => response,
            Err(_) => json_err(format!("Timeout after {}s", p.timeout.unwrap_or(10))),
        }
    }

    // === TOFU management (T-1038) ===

    #[tool(
        name = "termlink_tofu_list",
        description = "List all trusted hub certificates (TOFU store). Shows host:port, fingerprint, first_seen, and last_seen for each trusted hub."
    )]
    async fn termlink_tofu_list(&self, Parameters(_p): Parameters<TofuListParams>) -> String {
        let store = termlink_session::tofu::KnownHubStore::default_store();
        let entries = store.list_all();
        let items: Vec<serde_json::Value> = entries.iter().map(|e| {
            serde_json::json!({
                "host": e.host_port,
                "fingerprint": e.fingerprint,
                "first_seen": e.first_seen,
                "last_seen": e.last_seen,
            })
        }).collect();
        serde_json::to_string_pretty(&serde_json::json!({
            "ok": true,
            "count": items.len(),
            "entries": items,
        })).unwrap_or_else(json_err)
    }

    #[tool(
        name = "termlink_tofu_clear",
        description = "Clear trusted hub certificate(s) from the TOFU store. Pass `host` for single-host clear OR `all: true` for bulk wipe (mirrors CLI `tofu clear --all`). After clearing, next connection re-trusts (TOFU). Use after a hub restart that regenerated its cert."
    )]
    async fn termlink_tofu_clear(&self, Parameters(p): Parameters<TofuClearParams>) -> String {
        let store = termlink_session::tofu::KnownHubStore::default_store();
        // T-1934: bulk-clear branch — parity with `tofu clear --all`.
        if p.all.unwrap_or(false) {
            let count = store.clear_all();
            return serde_json::to_string_pretty(&serde_json::json!({
                "ok": true,
                "cleared": count,
            })).unwrap_or_else(json_err);
        }
        // Single-host branch — `host` is required when `all` is false.
        let host = match p.host.as_deref() {
            Some(h) => h,
            None => return json_err("'host' is required when 'all' is false".to_string()),
        };
        let existed = store.remove(host);
        serde_json::to_string_pretty(&serde_json::json!({
            "ok": existed,
            "host": host,
            "removed": existed,
            "message": if existed {
                format!("Removed TOFU entry for {host}. Next connection will re-trust.")
            } else {
                format!("No TOFU entry found for '{host}'")
            },
        })).unwrap_or_else(json_err)
    }
    // === Fleet status (T-1102) ===

    #[tool(
        name = "termlink_fleet_status",
        description = "One-screen operational overview of all configured hubs. Shows each hub's status (up/down/auth-fail), session count, latency, and actionable fix steps for broken hubs. The operator's morning-check command. T-1711: pass `verbose: true` to also include `session_names: [...]` per up-hub (display_name strings from session.discover) — for agents that need to know WHICH workloads are running, not just how many."
    )]
    async fn termlink_fleet_status(&self, Parameters(p): Parameters<FleetStatusParams>) -> String {
        let profiles = list_all_hub_profiles();
        if profiles.is_empty() {
            return serde_json::to_string_pretty(&serde_json::json!({
                "ok": true,
                "fleet": [],
                "summary": {"total": 0, "up": 0, "down": 0, "auth_fail": 0},
                "actions": [],
                "message": "No hubs configured in ~/.termlink/hubs.toml",
            })).unwrap_or_else(json_err);
        }

        let timeout_secs = p.timeout.unwrap_or(10);
        let verbose = p.verbose.unwrap_or(false);
        let timeout_dur = std::time::Duration::from_secs(timeout_secs);
        let mut fleet: Vec<serde_json::Value> = Vec::new();
        let mut actions: Vec<String> = Vec::new();
        let mut up_count: u32 = 0;
        let mut down_count: u32 = 0;
        let mut auth_fail_count: u32 = 0;

        for (name, address, secret_file, secret_hex) in &profiles {
            let connect_start = std::time::Instant::now();
            let result = tokio::time::timeout(
                timeout_dur,
                connect_remote_hub_mcp(
                    address,
                    secret_file.as_deref(),
                    secret_hex.as_deref(),
                    "execute",
                ),
            ).await;

            match result {
                Ok(Ok(mut client)) => {
                    let latency = connect_start.elapsed().as_millis();
                    up_count += 1;

                    // Query session count (and names when verbose). T-1711: parallel
                    // to CLI behavior — fetch the array once, derive count + names.
                    let (session_count, session_names) = match client.call(
                        "session.discover",
                        serde_json::json!("mcp-fleet-sd"),
                        serde_json::json!({}),
                    ).await {
                        Ok(termlink_protocol::jsonrpc::RpcResponse::Success(r)) => {
                            let arr = r.result["sessions"].as_array();
                            let count = arr.map(|s| s.len()).unwrap_or(0);
                            let names: Vec<String> = if verbose {
                                arr.map(|s| {
                                    s.iter()
                                        .filter_map(|sess| {
                                            sess["display_name"].as_str().map(String::from)
                                        })
                                        .collect()
                                })
                                .unwrap_or_default()
                            } else {
                                Vec::new()
                            };
                            (count, names)
                        }
                        _ => (0, Vec::new()),
                    };

                    let mut entry = serde_json::json!({
                        "hub": name, "address": address,
                        "status": "up", "latency_ms": latency,
                        "sessions": session_count,
                    });
                    // T-1711: mirror CLI JSON shape exactly — when verbose=true,
                    // always include session_names (even an empty array). The CLI
                    // human-readable path only prints names when non-empty, but
                    // the JSON field is unconditional. Match the JSON contract.
                    if verbose
                        && let Some(obj) = entry.as_object_mut()
                    {
                        obj.insert("session_names".into(), serde_json::json!(session_names));
                    }
                    fleet.push(entry);
                }
                Ok(Err(err_json)) => {
                    let is_auth = err_json.contains("invalid signature")
                        || err_json.contains("Token validation")
                        || err_json.contains("TOFU VIOLATION");
                    if is_auth {
                        auth_fail_count += 1;
                        fleet.push(serde_json::json!({"hub": name, "address": address, "status": "auth-fail", "error": err_json}));
                        actions.push(format!("{}: Reauth needed — termlink fleet reauth {} --bootstrap-from ssh:<host>", name, name));
                    } else {
                        down_count += 1;
                        fleet.push(serde_json::json!({"hub": name, "address": address, "status": "down", "error": err_json}));
                        actions.push(format!("{}: {}", name, err_json));
                    }
                }
                Err(_) => {
                    down_count += 1;
                    fleet.push(serde_json::json!({"hub": name, "address": address, "status": "timeout"}));
                    actions.push(format!("{}: Timeout — check network to {}", name, address));
                }
            }
        }

        serde_json::to_string_pretty(&serde_json::json!({
            "ok": down_count == 0 && auth_fail_count == 0,
            "fleet": fleet,
            "summary": {"total": fleet.len(), "up": up_count, "down": down_count, "auth_fail": auth_fail_count},
            "actions": actions,
        })).unwrap_or_else(json_err)
    }

    // === Fleet governor-status (T-2063 / T-2028 Track D) ===

    #[tool(
        name = "termlink_fleet_governor_status",
        description = "T-2063 / T-2028 Track D: fleet-wide aggregation of `hub.governor_status`. Walks every hub in ~/.termlink/hubs.toml, probes the substrate connection-cap + per-sender rate-limit + post-dedupe counters that T-2048 Track B exposed via RPC, and returns a per-hub + fleet-rollup envelope. Each hub is bounded by per-hub `tokio::time::timeout` (default 8s) — a wedged hub cannot hang the fleet view. Pure read (Observe scope), no mutation. Returns `{ok, total, reachable, hubs:[{hub, ok, governor|error}], summary{total_connections_active, total_capacity_hits_total, total_rate_hits_total, total_dedupe_entries_active, total_dedupe_hits_total, hubs_at_capacity, hubs_rate_limited}}`. Use to answer 'which hub is wedged / hitting capacity / rate-limited?' in one call without iterating profiles. CLI parity: `termlink fleet governor-status [--json] [--timeout SECS]` (T-2062). Single-hub MCP parity: `termlink_hub_governor_status`. See `docs/operations/substrate-governor.md`."
    )]
    async fn termlink_fleet_governor_status(
        &self,
        Parameters(p): Parameters<FleetGovernorStatusParams>,
    ) -> String {
        use termlink_protocol::jsonrpc::RpcResponse;

        let profiles = list_all_hub_profiles();
        if profiles.is_empty() {
            return serde_json::to_string_pretty(&serde_json::json!({
                "ok": true,
                "total": 0,
                "reachable": 0,
                "hubs": [],
                "summary": {
                    "total_connections_active":    0,
                    "total_capacity_hits_total":   0,
                    "total_rate_hits_total":       0,
                    "total_dedupe_entries_active": 0,
                    "total_dedupe_hits_total":     0,
                    "hubs_at_capacity":            0,
                    "hubs_rate_limited":           0,
                    "shown":                       0,
                    "only_pressured":              p.only_pressured.unwrap_or(false),
                },
                "message": "No hubs configured in ~/.termlink/hubs.toml",
            }))
            .unwrap_or_else(json_err);
        }

        let timeout_secs = p.timeout.unwrap_or(8);
        let timeout_dur = std::time::Duration::from_secs(timeout_secs);
        let only_pressured = p.only_pressured.unwrap_or(false);

        // T-2071: collect per-hub outcomes first so the predicate can filter
        // both the rendered hubs[] AND the per-hub counters consistently.
        // Counters (totals + hubs_at_capacity / hubs_rate_limited) are
        // computed from the full set regardless of filter — the operator/
        // agent always sees "N/M pressured" against the original totals.
        let mut probe_results: Vec<(String, std::result::Result<serde_json::Value, String>)> =
            Vec::with_capacity(profiles.len());

        for (name, address, secret_file, secret_hex) in &profiles {
            let probe = async {
                let mut client = connect_remote_hub_mcp(
                    address,
                    secret_file.as_deref(),
                    secret_hex.as_deref(),
                    "execute",
                )
                .await
                .map_err(|e| anyhow::anyhow!(e))?;
                let resp = client
                    .call(
                        "hub.governor_status",
                        serde_json::json!("mcp-fleet-gov"),
                        serde_json::json!({}),
                    )
                    .await?;
                match resp {
                    RpcResponse::Success(r) => {
                        Ok::<serde_json::Value, anyhow::Error>(r.result)
                    }
                    RpcResponse::Error(e) => {
                        anyhow::bail!(
                            "RPC error {}: {}",
                            e.error.code,
                            e.error.message
                        )
                    }
                }
            };

            let result: std::result::Result<serde_json::Value, String> =
                match tokio::time::timeout(timeout_dur, probe).await {
                    Ok(Ok(v)) => Ok(v),
                    Ok(Err(e)) => Err(e.to_string()),
                    Err(_) => Err(format!("timed out after {}s", timeout_secs)),
                };
            probe_results.push((name.clone(), result));
        }

        // Counters from the FULL set — never filter-narrowed.
        let mut reachable: usize = 0;
        let mut sum_connections_active: i64 = 0;
        let mut sum_capacity_hits: i64 = 0;
        let mut sum_rate_hits: i64 = 0;
        let mut sum_dedupe_entries: i64 = 0;
        let mut sum_dedupe_hits: i64 = 0;
        let mut hubs_at_capacity: usize = 0;
        let mut hubs_rate_limited: usize = 0;
        for (_, r) in &probe_results {
            if let Ok(v) = r {
                reachable += 1;
                let active = v.get("connections_active").and_then(|x| x.as_i64()).unwrap_or(0);
                let max = v.get("connections_max").and_then(|x| x.as_i64()).unwrap_or(i64::MAX);
                let cap_hits = v.get("capacity_hits_total").and_then(|x| x.as_i64()).unwrap_or(0);
                let rate_hits = v.get("rate_hits_total").and_then(|x| x.as_i64()).unwrap_or(0);
                let ded_entries = v.get("dedupe_entries_active").and_then(|x| x.as_i64()).unwrap_or(0);
                let ded_hits = v.get("dedupe_hits_total").and_then(|x| x.as_i64()).unwrap_or(0);
                sum_connections_active += active;
                sum_capacity_hits += cap_hits;
                sum_rate_hits += rate_hits;
                sum_dedupe_entries += ded_entries;
                sum_dedupe_hits += ded_hits;
                if active >= max { hubs_at_capacity += 1; }
                if rate_hits > 0 { hubs_rate_limited += 1; }
            }
        }

        // hubs[] respects the filter.
        let mut hubs_json: Vec<serde_json::Value> = Vec::with_capacity(probe_results.len());
        for (name, r) in &probe_results {
            if only_pressured && !mcp_governor_hub_is_pressured(r) {
                continue;
            }
            match r {
                Ok(v) => hubs_json.push(serde_json::json!({
                    "hub": name,
                    "ok": true,
                    "governor": v,
                })),
                Err(e) => hubs_json.push(serde_json::json!({
                    "hub": name,
                    "ok": false,
                    "error": e,
                })),
            }
        }

        serde_json::to_string_pretty(&serde_json::json!({
            "ok": true,
            "total": profiles.len(),
            "reachable": reachable,
            "hubs": hubs_json,
            "summary": {
                "total_connections_active":    sum_connections_active,
                "total_capacity_hits_total":   sum_capacity_hits,
                "total_rate_hits_total":       sum_rate_hits,
                "total_dedupe_entries_active": sum_dedupe_entries,
                "total_dedupe_hits_total":     sum_dedupe_hits,
                "hubs_at_capacity":            hubs_at_capacity,
                "hubs_rate_limited":           hubs_rate_limited,
                "shown":                       hubs_json.len(),
                "only_pressured":              only_pressured,
            }
        }))
        .unwrap_or_else(json_err)
    }

    // === Fleet verify (T-1661) — TLS pin drift check, no auth required ===

    #[tool(
        name = "termlink_fleet_verify",
        description = "Probe every hub in ~/.termlink/hubs.toml via TLS handshake and compare wire fingerprint vs the stored TOFU pin. Pure read-only diagnostic: no authentication, no cert/secret mutation. Returns per-profile status (match / drift / no-pin / probe-failed) plus a fleet rollup verdict where drift dominates. Use to detect hub rotation BEFORE auth-bearing workloads fail."
    )]
    async fn termlink_fleet_verify(&self, Parameters(p): Parameters<FleetVerifyParams>) -> String {
        let profiles = list_all_hub_profiles();
        if profiles.is_empty() {
            return serde_json::to_string_pretty(&serde_json::json!({
                "ok": true,
                "verdict": "match",
                "profiles": [],
                "message": "No hubs configured in ~/.termlink/hubs.toml",
            })).unwrap_or_else(json_err);
        }

        let store = termlink_session::tofu::KnownHubStore::default_store();

        // T-1675: 10s per-probe bound — keeps fleet sweeps from hanging on
        // an unreachable host's OS TCP retry budget. Matches CLI defaults.
        let probe_timeout = std::time::Duration::from_secs(10);
        let probes: Vec<_> = profiles
            .iter()
            .map(|(name, address, _, _)| {
                let name = name.clone();
                let address = address.clone();
                tokio::spawn(async move {
                    let result = termlink_session::tofu::probe_cert_with_timeout(
                        &address, probe_timeout,
                    ).await;
                    (name, address, result)
                })
            })
            .collect();

        let mut results: Vec<serde_json::Value> = Vec::with_capacity(profiles.len());
        for handle in probes {
            let (name, address, probe_result) = match handle.await {
                Ok(t) => t,
                Err(e) => {
                    results.push(serde_json::json!({
                        "name": "<join-error>",
                        "address": "<unknown>",
                        "status": "probe-failed",
                        "wire": serde_json::Value::Null,
                        "pinned": serde_json::Value::Null,
                        "error": format!("task panic: {e}"),
                    }));
                    continue;
                }
            };
            let pinned = store.get(&address);
            let (status, wire, error): (&str, Option<String>, Option<String>) = match probe_result {
                Ok((_, wire)) => match &pinned {
                    Some(pin) if pin == &wire => ("match", Some(wire), None),
                    Some(_) => ("drift", Some(wire), None),
                    None => ("no-pin", Some(wire), None),
                },
                Err(e) => ("probe-failed", None, Some(e)),
            };
            results.push(serde_json::json!({
                "name": name,
                "address": address,
                "status": status,
                "wire": wire,
                "pinned": pinned,
                "error": error,
            }));
        }

        let any_drift = results.iter().any(|r| r["status"] == "drift");
        let any_probe_fail = results.iter().any(|r| r["status"] == "probe-failed");
        let any_no_pin = results.iter().any(|r| r["status"] == "no-pin");
        let verdict = if any_drift { "drift" }
            else if any_probe_fail { "probe-failed" }
            else if any_no_pin { "no-pin" }
            else { "match" };

        // ok rollup mirrors the CLI exit-code semantics:
        //   strict mode (default): ok iff verdict == match
        //   --exit-on-drift-only:  ok iff verdict != drift
        let drift_only = p.exit_on_drift_only.unwrap_or(false);
        let ok = if drift_only { verdict != "drift" } else { verdict == "match" };

        serde_json::to_string_pretty(&serde_json::json!({
            "ok": ok,
            "verdict": verdict,
            "profiles": results,
            "actions": if verdict == "drift" {
                vec![
                    "Heal drifted hubs: termlink fleet reauth <profile> --bootstrap-from auto".to_string(),
                    "Then re-pin:       termlink tofu clear <address>".to_string(),
                ]
            } else { vec![] },
        })).unwrap_or_else(json_err)
    }

    // === Hub fingerprint + export-secret (T-1744) — local rotation primitives ===

    #[tool(
        name = "termlink_hub_fingerprint",
        description = "Read the LOCAL hub's TLS leaf-cert fingerprint — MCP parity for the `termlink hub fingerprint` CLI verb (T-1657). Pure read-only: opens `<runtime_dir>/hub.cert.pem`, extracts the first CERTIFICATE block, decodes DER, returns `{ok, path, fingerprint}` in canonical `sha256:<hex>` form. Companion to `termlink_hub_probe` (remote TLS-probe over the wire): this one reads the LOCAL file. Use to answer 'what fingerprint should peers pin for my hub?' from an agent co-located with the hub, without shelling out. Returns `{ok: false, error, path}` if the hub isn't running (no cert file)."
    )]
    async fn termlink_hub_fingerprint(&self) -> String {
        let cert_path = termlink_hub::tls::hub_cert_path();
        let pem = match std::fs::read_to_string(&cert_path) {
            Ok(s) => s,
            Err(e) => {
                return serde_json::to_string_pretty(&serde_json::json!({
                    "ok": false,
                    "path": cert_path.display().to_string(),
                    "fingerprint": serde_json::Value::Null,
                    "error": format!("no hub.cert.pem at {} — is the hub running? ({e})", cert_path.display()),
                }))
                .unwrap_or_else(json_err);
            }
        };
        match parse_first_cert_block_to_fingerprint(&pem) {
            Ok(fingerprint) => serde_json::to_string_pretty(&serde_json::json!({
                "ok": true,
                "path": cert_path.display().to_string(),
                "fingerprint": fingerprint,
                "error": serde_json::Value::Null,
            }))
            .unwrap_or_else(json_err),
            Err(e) => serde_json::to_string_pretty(&serde_json::json!({
                "ok": false,
                "path": cert_path.display().to_string(),
                "fingerprint": serde_json::Value::Null,
                "error": format!("parse failed for {}: {e}", cert_path.display()),
            }))
            .unwrap_or_else(json_err),
        }
    }

    #[tool(
        name = "termlink_hub_export_secret",
        description = "Read the LOCAL hub's HMAC secret from the AUTHORITATIVE live file — MCP parity for the `termlink hub export-secret` CLI verb (T-1656). Reads `<runtime_dir>/hub.secret` directly (R3 — NEVER the IP-keyed `~/.termlink/secrets/<ip>.hex` cache, which goes stale across hub restarts). Returns `{ok, path, hex, bytes}` where `hex` is the trimmed 64-char hex secret. Use as the authoritative source when sharing your hub's secret with a peer during heal-after-rotation handoff. Caller is responsible for chmod 600 and out-of-band transport — this verb does not write any file. Returns `{ok: false, error, path}` if the hub isn't running (no secret file)."
    )]
    async fn termlink_hub_export_secret(&self) -> String {
        let live_path = termlink_hub::server::hub_secret_path();
        match std::fs::read_to_string(&live_path) {
            Ok(raw) => {
                let hex = raw.trim().to_string();
                let bytes = hex.len() / 2;
                serde_json::to_string_pretty(&serde_json::json!({
                    "ok": true,
                    "path": live_path.display().to_string(),
                    "hex": hex,
                    "bytes": bytes,
                    "error": serde_json::Value::Null,
                }))
                .unwrap_or_else(json_err)
            }
            Err(e) => serde_json::to_string_pretty(&serde_json::json!({
                "ok": false,
                "path": live_path.display().to_string(),
                "hex": serde_json::Value::Null,
                "bytes": serde_json::Value::Null,
                "error": format!("no hub.secret at {} — is the hub running? ({e})", live_path.display()),
            }))
            .unwrap_or_else(json_err),
        }
    }

    // === Hub probe (T-1663) — single-host TLS fingerprint, no auth required ===

    #[tool(
        name = "termlink_hub_probe",
        description = "Probe a single hub via TLS handshake and return its leaf cert sha256 fingerprint in canonical `sha256:<hex>` form. Pure read-only diagnostic: no authentication, no profile required, no `KnownHubStore` mutation. Use for pre-pin verification, comparing-without-trust after a suspected rotation, or operator first-contact before adding a profile. Companion to termlink_fleet_verify for per-host investigation without probing the whole fleet."
    )]
    async fn termlink_hub_probe(&self, Parameters(p): Parameters<HubProbeParams>) -> String {
        // T-1675: 10s bound matches CLI `hub probe` default.
        match termlink_session::tofu::probe_cert_with_timeout(
            &p.address, std::time::Duration::from_secs(10),
        ).await {
            Ok((_der, fingerprint)) => serde_json::to_string_pretty(&serde_json::json!({
                "ok": true,
                "address": p.address,
                "fingerprint": fingerprint,
                "error": serde_json::Value::Null,
            })).unwrap_or_else(json_err),
            Err(e) => serde_json::to_string_pretty(&serde_json::json!({
                "ok": false,
                "address": p.address,
                "fingerprint": serde_json::Value::Null,
                "error": e,
            })).unwrap_or_else(json_err),
        }
    }

    // === Tofu verify (T-1663) — single-host wire-vs-pin drift check ===

    #[tool(
        name = "termlink_tofu_verify",
        description = "Probe a single hub via TLS and compare its wire fingerprint against the stored TOFU pin in `~/.termlink/known_hubs`. Pure read-only diagnostic: no authentication, no profile required, no `KnownHubStore` mutation. Returns status (match / drift / no-pin / probe-failed) plus heal hints when drift detected. Use for per-host rotation diagnosis when termlink_fleet_verify would be overkill or too slow."
    )]
    async fn termlink_tofu_verify(&self, Parameters(p): Parameters<TofuVerifyParams>) -> String {
        let store = termlink_session::tofu::KnownHubStore::default_store();
        let pinned = store.get(&p.address);
        // T-1675: 10s bound matches CLI `tofu verify` default.
        let probe_result = termlink_session::tofu::probe_cert_with_timeout(
            &p.address, std::time::Duration::from_secs(10),
        ).await;

        // T-1927: envelope converged with CLI `tofu verify --json` shape.
        // - status: "probe-failed" (T-1927 convention, T-1937 universalized across rotation-protocol family)
        // - probe_error: probe error message (renamed from `error`)
        // - match: Some(bool) when probe succeeded, None when probe failed
        let (status, wire, match_flag, probe_error): (&str, Option<String>, Option<bool>, Option<String>) = match probe_result {
            Ok((_, wire)) => match &pinned {
                Some(pin) if pin == &wire => ("match", Some(wire), Some(true), None),
                Some(_) => ("drift", Some(wire), Some(false), None),
                None => ("no-pin", Some(wire), None, None),
            },
            Err(e) => ("probe-failed", None, None, Some(e)),
        };

        let ok = status == "match";
        let actions: Vec<String> = if status == "drift" {
            vec![
                format!("Heal: termlink fleet reauth <profile-for-{}> --bootstrap-from auto", p.address),
                format!("Re-pin: termlink tofu clear {}", p.address),
            ]
        } else { Vec::new() };

        serde_json::to_string_pretty(&serde_json::json!({
            "ok": ok,
            "address": p.address,
            "status": status,
            "wire": wire,
            "pinned": pinned,
            "match": match_flag,
            "probe_error": probe_error,
            "actions": actions,
        })).unwrap_or_else(json_err)
    }

    // === Net test (T-1106) ===

    #[tool(
        name = "termlink_net_test",
        description = "Layered connectivity diagnostic for configured hubs. Tests each hub through TCP → TLS → auth → RPC ping, pinpointing exactly where a connection breaks. Use when fleet_status shows 'down' and you need to know if it's a network, cert, or secret issue."
    )]
    async fn termlink_net_test(&self, Parameters(p): Parameters<NetTestParams>) -> String {
        use serde_json::json;
        use std::time::{Duration, Instant};

        let all_profiles = list_all_hub_profiles();
        if all_profiles.is_empty() {
            return serde_json::to_string_pretty(&json!({
                "ok": true, "hubs": [],
                "summary": {"total": 0, "healthy": 0, "degraded": 0, "unreachable": 0},
                "message": "No hubs configured in ~/.termlink/hubs.toml",
            })).unwrap_or_else(json_err);
        }

        let profiles: Vec<_> = if let Some(ref filter) = p.profile {
            let matches: Vec<_> = all_profiles.into_iter()
                .filter(|(n, _, _, _)| n == filter).collect();
            if matches.is_empty() {
                return serde_json::to_string_pretty(&json!({
                    "ok": false,
                    "error": format!("Hub profile '{}' not found", filter),
                })).unwrap_or_else(json_err);
            }
            matches
        } else {
            all_profiles
        };

        let timeout_secs = p.timeout.unwrap_or(5);
        let timeout_dur = Duration::from_secs(timeout_secs);
        let mut hubs: Vec<serde_json::Value> = Vec::new();
        let mut healthy = 0u32;
        let mut degraded = 0u32;
        let mut unreachable = 0u32;

        for (name, address, secret_file, secret_hex) in &profiles {
            let parts: Vec<&str> = address.split(':').collect();
            if parts.len() != 2 {
                unreachable += 1;
                hubs.push(json!({
                    "hub": name, "address": address, "healthy": false,
                    "diagnosis": "invalid hub address", "layers": {},
                }));
                continue;
            }
            let host = parts[0].to_string();
            let port: u16 = match parts[1].parse() {
                Ok(p) => p,
                Err(_) => {
                    unreachable += 1;
                    hubs.push(json!({
                        "hub": name, "address": address, "healthy": false,
                        "diagnosis": "invalid port", "layers": {},
                    }));
                    continue;
                }
            };

            let mut layers = serde_json::Map::new();

            // L1: TCP
            let tcp_start = Instant::now();
            let tcp_result = tokio::time::timeout(
                timeout_dur,
                tokio::net::TcpStream::connect((host.as_str(), port)),
            ).await;
            let tcp_latency = tcp_start.elapsed().as_millis() as u64;

            let (tcp_ok, tcp_entry) = match tcp_result {
                Ok(Ok(_)) => (true, json!({"status": "pass", "latency_ms": tcp_latency})),
                Ok(Err(e)) => (false, json!({"status": "fail", "latency_ms": tcp_latency,
                    "error": e.to_string()})),
                Err(_) => (false, json!({"status": "timeout", "latency_ms": timeout_secs * 1000})),
            };
            layers.insert("tcp".to_string(), tcp_entry);

            if !tcp_ok {
                unreachable += 1;
                hubs.push(json!({
                    "hub": name, "address": address, "healthy": false,
                    "diagnosis": "Network-level failure — check firewall/VPN/routing and hub process is listening on the configured port",
                    "layers": layers,
                }));
                continue;
            }

            // L2+L3: TLS + auth (MCP's connect_remote_hub_mcp bundles both)
            let conn_start = Instant::now();
            let conn_result = tokio::time::timeout(
                timeout_dur,
                connect_remote_hub_mcp(
                    address,
                    secret_file.as_deref(),
                    secret_hex.as_deref(),
                    "execute",
                ),
            ).await;
            let conn_latency = conn_start.elapsed().as_millis() as u64;

            match conn_result {
                Ok(Ok(mut client)) => {
                    // TLS+auth bundled — report as pass for both layers
                    layers.insert("tls".to_string(),
                        json!({"status": "pass", "latency_ms": conn_latency}));
                    layers.insert("auth".to_string(),
                        json!({"status": "pass", "latency_ms": 0}));

                    // L4: PING via session.discover
                    let ping_start = Instant::now();
                    let ping_result = tokio::time::timeout(
                        timeout_dur,
                        client.call("session.discover", json!("mcp-net-ping"), json!({})),
                    ).await;
                    let ping_latency = ping_start.elapsed().as_millis() as u64;

                    let (ping_ok, ping_entry) = match ping_result {
                        Ok(Ok(termlink_protocol::jsonrpc::RpcResponse::Success(_))) =>
                            (true, json!({"status": "pass", "latency_ms": ping_latency})),
                        Ok(Ok(termlink_protocol::jsonrpc::RpcResponse::Error(e))) =>
                            (false, json!({"status": "fail", "latency_ms": ping_latency,
                                "error": format!("{} {}", e.error.code, e.error.message)})),
                        Ok(Err(e)) => (false, json!({"status": "fail", "latency_ms": ping_latency,
                            "error": e.to_string()})),
                        Err(_) => (false, json!({"status": "timeout",
                            "latency_ms": timeout_secs * 1000})),
                    };
                    layers.insert("ping".to_string(), ping_entry);

                    if ping_ok {
                        healthy += 1;
                        hubs.push(json!({
                            "hub": name, "address": address, "healthy": true, "layers": layers,
                        }));
                    } else {
                        degraded += 1;
                        hubs.push(json!({
                            "hub": name, "address": address, "healthy": false,
                            "diagnosis": "RPC ping failed after auth — hub is reachable and trusted but misbehaving",
                            "layers": layers,
                        }));
                    }
                }
                Ok(Err(err_json)) => {
                    let is_auth = err_json.contains("invalid signature")
                        || err_json.contains("Token validation")
                        || err_json.contains("Authentication");
                    let is_tofu = err_json.contains("TOFU") || err_json.contains("fingerprint");

                    if is_auth && !is_tofu {
                        layers.insert("tls".to_string(),
                            json!({"status": "pass", "latency_ms": conn_latency}));
                        layers.insert("auth".to_string(), json!({
                            "status": "fail", "latency_ms": conn_latency,
                            "error": err_json.clone(),
                        }));
                        degraded += 1;
                        hubs.push(json!({
                            "hub": name, "address": address, "healthy": false,
                            "diagnosis": "HMAC secret mismatch — run: termlink fleet reauth <profile> --bootstrap-from ssh:<host>",
                            "layers": layers,
                        }));
                    } else {
                        layers.insert("tls".to_string(), json!({
                            "status": "fail", "latency_ms": conn_latency,
                            "error": err_json.clone(),
                        }));
                        degraded += 1;
                        hubs.push(json!({
                            "hub": name, "address": address, "healthy": false,
                            "diagnosis": if is_tofu {
                                "TLS cert changed — run: termlink tofu clear <host:port> and retry"
                            } else {
                                "TLS handshake failed — hub may not be speaking TLS, or cert is invalid"
                            },
                            "layers": layers,
                        }));
                    }
                }
                Err(_) => {
                    layers.insert("tls".to_string(),
                        json!({"status": "timeout", "latency_ms": timeout_secs * 1000}));
                    degraded += 1;
                    hubs.push(json!({
                        "hub": name, "address": address, "healthy": false,
                        "diagnosis": "TLS handshake timed out — hub is slow or silently dropping TLS",
                        "layers": layers,
                    }));
                }
            }
        }

        serde_json::to_string_pretty(&json!({
            "ok": degraded == 0 && unreachable == 0,
            "hubs": hubs,
            "summary": {
                "total": profiles.len(),
                "healthy": healthy,
                "degraded": degraded,
                "unreachable": unreachable,
            },
        })).unwrap_or_else(json_err)
    }

    // === Fleet doctor (T-1039) ===

    #[tool(
        name = "termlink_fleet_doctor",
        description = "Health check all configured hubs in ~/.termlink/hubs.toml. Returns per-hub connectivity status, latency, and diagnostic hints for failures. Pass `legacy_usage: true` (T-1707, MCP parity for CLI `--legacy-usage`/T-1432) to also probe each hub's `hub.legacy_usage` Tier-A RPC and aggregate a fleet-wide T-1166 cut-readiness verdict (CUT-READY / CUT-READY-DECAYING / WAIT / UNCERTAIN) in `legacy_summary`. `legacy_window_days` (default 7, clamped 1..=90) sets the lookback. Pass `include_pin_check: true` (T-1708, MCP parity for CLI `--include-pin-check`/T-1666) to also TLS-probe every hub in parallel and report per-profile pin status (match / drift / no-pin / probe-failed) in `pin_check` per hub plus a fleet rollup in `pin_check_summary` — single-call answer to 'auth-mismatch OR cert-drift OR both?'. Pass `topic_durability: true` (T-1709, MCP parity for CLI `--topic-durability`/T-1446) to also probe each hub's `hub.bus_state` and aggregate the G-050 durability verdict (DURABLE / VOLATILE / UNCERTAIN) in `bus_state_summary` — VOLATILE means the hub's runtime_dir lives on a wipe-on-boot mount (the structural cause of PL-021 identity rotation)."
    )]
    async fn termlink_fleet_doctor(&self, Parameters(p): Parameters<FleetDoctorParams>) -> String {
        let profiles = list_all_hub_profiles();
        if profiles.is_empty() {
            return serde_json::to_string_pretty(&serde_json::json!({
                "ok": true,
                "hubs": [],
                "message": "No hubs configured in ~/.termlink/hubs.toml",
            })).unwrap_or_else(json_err);
        }

        let timeout_secs = p.timeout.unwrap_or(10);
        let timeout_dur = std::time::Duration::from_secs(timeout_secs);
        let legacy_usage = p.legacy_usage.unwrap_or(false);
        let legacy_window_days = p.legacy_window_days.unwrap_or(7).clamp(1, 90);
        let include_pin_check = p.include_pin_check.unwrap_or(false);
        let topic_durability = p.topic_durability.unwrap_or(false);
        // T-1713 (G-057 punch-list #4): auto-heal preview opt-in.
        let auto_heal_preview = p.auto_heal_preview.unwrap_or(false);
        // T-1714: anchor-validation extension. Silently ignored when
        // auto_heal_preview=false — validation only makes sense within
        // the preview, and we don't want a stray subprocess invocation
        // on calls that didn't ask for it.
        let validate_anchors = auto_heal_preview && p.validate_anchors.unwrap_or(false);
        let mut hub_results: Vec<serde_json::Value> = Vec::new();
        let mut pass_count: u32 = 0;
        let mut fail_count: u32 = 0;

        // T-1708: parallel TLS probe of every hub BEFORE the connect loop.
        // Mirrors CLI T-1666 — total wall time bounded by slowest probe
        // rather than summed serial probes. Result map keyed by address so
        // the per-hub inject is O(1). Reuses termlink_session::tofu primitives.
        // Tuple shape mirrors fleet_verify: (status, wire, pinned, error).
        type PinCheck = (&'static str, Option<String>, Option<String>, Option<String>);
        let pin_checks: std::collections::HashMap<String, PinCheck> = if include_pin_check {
            let store = termlink_session::tofu::KnownHubStore::default_store();
            let probe_timeout = timeout_dur;
            let probe_tasks: Vec<_> = profiles
                .iter()
                .map(|(_, address, _, _)| {
                    let address = address.clone();
                    tokio::spawn(async move {
                        let result = termlink_session::tofu::probe_cert_with_timeout(
                            &address,
                            probe_timeout,
                        )
                        .await;
                        (address, result)
                    })
                })
                .collect();
            let mut out: std::collections::HashMap<String, PinCheck> =
                std::collections::HashMap::with_capacity(profiles.len());
            for handle in probe_tasks {
                if let Ok((address, probe_result)) = handle.await {
                    let pinned = store.get(&address);
                    let entry: PinCheck = match probe_result {
                        Ok((_, wire)) => match &pinned {
                            Some(pin) if pin == &wire => {
                                ("match", Some(wire), pinned.clone(), None)
                            }
                            Some(_) => ("drift", Some(wire), pinned.clone(), None),
                            None => ("no-pin", Some(wire), None, None),
                        },
                        Err(e) => ("probe-failed", None, pinned.clone(), Some(e)),
                    };
                    out.insert(address, entry);
                }
            }
            out
        } else {
            std::collections::HashMap::new()
        };

        for (name, address, secret_file, secret_hex) in &profiles {
            let connect_start = std::time::Instant::now();
            let result = tokio::time::timeout(
                timeout_dur,
                connect_remote_hub_mcp(
                    address,
                    secret_file.as_deref(),
                    secret_hex.as_deref(),
                    "execute",
                ),
            ).await;

            match result {
                Ok(Ok(mut client)) => {
                    let latency = connect_start.elapsed().as_millis();
                    pass_count += 1;
                    let mut hub_obj = serde_json::json!({
                        "hub": name,
                        "address": address,
                        "status": "ok",
                        "latency_ms": latency,
                    });
                    // T-1707: optional per-hub legacy_usage probe — mirrors CLI's
                    // T-1432 behavior. Pre-T-1432 hubs return method-not-found
                    // and we record audit_unsupported with an upgrade hint.
                    if legacy_usage {
                        let lu_result = client
                            .call(
                                "hub.legacy_usage",
                                serde_json::json!("mcp-fleet-doctor-legacy"),
                                serde_json::json!({
                                    "window_seconds": legacy_window_days * 86400,
                                }),
                            )
                            .await;
                        let lu_value = match lu_result {
                            Ok(termlink_protocol::jsonrpc::RpcResponse::Success(r)) => r.result,
                            _ => serde_json::json!({
                                "audit_unsupported": true,
                                "hint": "hub predates T-1432 (hub.legacy_usage) — upgrade to >=0.9.1640 to measure cut-readiness on this host",
                            }),
                        };
                        if let Some(obj) = hub_obj.as_object_mut() {
                            obj.insert("legacy_usage".to_string(), lu_value);
                        }
                    }
                    // T-1709: per-hub bus_state probe (G-050 durability audit).
                    // Pre-T-1446 hubs return method-not-found → audit_unsupported.
                    if topic_durability {
                        let bs_result = client
                            .call(
                                "hub.bus_state",
                                serde_json::json!("mcp-fleet-doctor-bus-state"),
                                serde_json::json!({}),
                            )
                            .await;
                        let bs_value = match bs_result {
                            Ok(termlink_protocol::jsonrpc::RpcResponse::Success(r)) => r.result,
                            _ => serde_json::json!({
                                "audit_unsupported": true,
                                "hint": "hub predates T-1446 (hub.bus_state) — upgrade to >=0.9.1717 to measure topic-durability on this host",
                            }),
                        };
                        if let Some(obj) = hub_obj.as_object_mut() {
                            obj.insert("bus_state".to_string(), bs_value);
                        }
                    }
                    // T-1708: pin_check is orthogonal to RPC connectivity —
                    // a hub can probe-fail on auth but TLS-handshake fine,
                    // or vice versa. Inject on every path.
                    inject_pin_check(&mut hub_obj, address, &pin_checks);
                    hub_results.push(hub_obj);
                }
                Ok(Err(err_json)) => {
                    fail_count += 1;
                    let mut hub_obj = serde_json::json!({"hub": name, "address": address, "status": "error", "error": err_json});
                    inject_pin_check(&mut hub_obj, address, &pin_checks);
                    hub_results.push(hub_obj);
                }
                Err(_) => {
                    fail_count += 1;
                    let mut hub_obj = serde_json::json!({"hub": name, "address": address, "status": "timeout", "error": format!("Timeout after {}s", timeout_secs)});
                    inject_pin_check(&mut hub_obj, address, &pin_checks);
                    hub_results.push(hub_obj);
                }
            }
        }

        // T-1707: aggregate fleet-wide cut-readiness verdict from per-hub
        // legacy_usage payloads. Logic mirrors CLI's
        // `compute_cut_readiness_verdict` in remote.rs — replicated inline
        // (G-057 pattern: MCP and CLI doctor have parallel implementations;
        // shared logic across crates is not yet the convention here).
        let legacy_summary = if legacy_usage {
            Some(aggregate_legacy_summary(&hub_results, legacy_window_days))
        } else {
            None
        };

        // T-1708: aggregate fleet-wide pin-check verdict from per-hub
        // pin_check fields. Pulls from `hub_results` so we exercise the same
        // shape an external consumer would parse.
        let pin_check_summary = if include_pin_check {
            let pin_profiles: Vec<serde_json::Value> = hub_results
                .iter()
                .filter_map(|h| {
                    let pc = h.get("pin_check")?.clone();
                    let mut obj = pc;
                    if let Some(map) = obj.as_object_mut() {
                        if let Some(name) = h.get("hub").cloned() {
                            map.insert("name".to_string(), name);
                        }
                        if let Some(addr) = h.get("address").cloned() {
                            map.insert("address".to_string(), addr);
                        }
                    }
                    Some(obj)
                })
                .collect();
            Some(aggregate_pin_check_summary(&pin_profiles))
        } else {
            None
        };

        let mut response = serde_json::json!({
            "ok": fail_count == 0,
            "hubs": hub_results,
            "summary": {"total": pass_count + fail_count, "pass": pass_count, "fail": fail_count},
        });
        if let Some(ls) = legacy_summary
            && let Some(obj) = response.as_object_mut()
        {
            obj.insert("legacy_summary".to_string(), ls);
        }
        if let Some(ps) = pin_check_summary
            && let Some(obj) = response.as_object_mut()
        {
            obj.insert("pin_check_summary".to_string(), ps);
        }
        // T-1709: aggregate G-050 audit-sweep verdict from per-hub bus_state.
        if topic_durability
            && let Some(obj) = response.as_object_mut()
        {
            obj.insert(
                "bus_state_summary".to_string(),
                aggregate_bus_state_summary(&hub_results),
            );
        }
        // T-1713: emit auto_heal_preview (MCP parity for CLI T-1684 dry-run).
        // Pure classification — no heal subprocesses spawned. Gates on
        // declared bootstrap_from per profile (R2). Same OR-gate as CLI
        // T-1681 (cert-drift OR auth-mismatch). One classification per hub;
        // PL-021's "both rotate" case dedups via Trigger::Both.
        if auto_heal_preview
            && let Some(obj) = response.as_object_mut()
        {
            let anchors = read_bootstrap_from_map();
            let mut would_fire: Vec<serde_json::Value> = Vec::new();
            let mut skipped_no_anchor: Vec<serde_json::Value> = Vec::new();
            let mut no_action: Vec<serde_json::Value> = Vec::new();
            for hub in &hub_results {
                let name = hub
                    .get("hub")
                    .and_then(|s| s.as_str())
                    .unwrap_or("?")
                    .to_string();
                let pin_status = hub
                    .get("pin_check")
                    .and_then(|pc| pc.get("status"))
                    .and_then(|s| s.as_str());
                let conn = derive_watch_conn_mcp(hub);
                let has_anchor = anchors.contains_key(&name);
                match classify_auto_heal_preview(pin_status, &conn, has_anchor) {
                    AutoHealAction::NoAction => {
                        no_action.push(serde_json::json!({
                            "hub": name,
                            "conn": conn,
                            "pin_status": pin_status,
                        }));
                    }
                    AutoHealAction::WouldFire(t) => {
                        would_fire.push(serde_json::json!({
                            "hub": name,
                            "trigger": t.as_str(),
                            "action": format!(
                                "termlink fleet reauth {} --bootstrap-from auto",
                                name
                            ),
                            "bootstrap_from": anchors.get(&name),
                        }));
                    }
                    AutoHealAction::SkipNoAnchor(t) => {
                        skipped_no_anchor.push(serde_json::json!({
                            "hub": name,
                            "trigger": t.as_str(),
                            "hint": "declare bootstrap_from in hubs.toml or pass an explicit source",
                        }));
                    }
                }
            }
            let total_would_fire = would_fire.len();
            // T-1714: optional anchor-validation pass. Subprocess
            // bootstrap-check ONCE, decorate would_fire entries, fold in
            // summary counts. Failures degrade gracefully — preview is
            // always emitted.
            let (decorated_would_fire, anchor_summary, anchor_error) = if validate_anchors {
                match fetch_anchor_validation_map(timeout_secs).await {
                    Ok(map) => {
                        let (dec, (val, ok_n, broken)) =
                            decorate_preview_with_anchors(&would_fire, &map);
                        (
                            dec,
                            Some(serde_json::json!({
                                "validated": val,
                                "ok": ok_n,
                                "broken": broken,
                            })),
                            None,
                        )
                    }
                    Err(e) => (would_fire.clone(), None, Some(e)),
                }
            } else {
                (would_fire.clone(), None, None)
            };
            let mut preview = serde_json::json!({
                "would_fire": decorated_would_fire,
                "skipped_no_anchor": skipped_no_anchor,
                "no_action": no_action,
                "total_would_fire": total_would_fire,
                // T-1713: mirrors CLI T-1683 stderr info hint. Without
                // include_pin_check=true, the cert-drift path can't fire,
                // so this is a meaningful gap signal to the agent.
                "missing_pin_check_warning": !include_pin_check,
                "header": format!(
                    "Auto-heal: would fire {} (dry-run, T-1713 preview)",
                    total_would_fire
                ),
            });
            if let Some(pobj) = preview.as_object_mut() {
                if let Some(summary) = anchor_summary {
                    pobj.insert("anchor_validation_summary".to_string(), summary);
                }
                if let Some(err) = anchor_error {
                    pobj.insert(
                        "anchor_validation_error".to_string(),
                        serde_json::Value::String(err),
                    );
                }
            }
            obj.insert("auto_heal_preview".to_string(), preview);
        }
        serde_json::to_string_pretty(&response).unwrap_or_else(json_err)
    }

    // === Fleet history (T-1687: MCP parity for T-1671 + T-1686) ===

    #[tool(
        name = "termlink_fleet_history",
        description = "Read-only retrospective over hub rotation events. Reads ~/.termlink/rotation.log (populated by `fleet doctor --watch`) and optionally ~/.termlink/heal.log (populated by `--auto-heal`). Answers 'is this hub's drift the first or Nth time, and what did we do about it?' Returns merged entries sorted chronologically with per-hub counts. No auth, no network. T-1710: pass `analyze: true` to short-circuit the chronological listing and return a per-hub PL-021 flap classification (CLI T-1690 parity) — verdicts: clean / cert-only / secret-only / single-double-rotation / pl021-candidate (≥2 simultaneous cert+secret rotations = volatile runtime_dir signature)."
    )]
    async fn termlink_fleet_history(
        &self,
        Parameters(p): Parameters<FleetHistoryParams>,
    ) -> String {
        let since_days = p.since_days.unwrap_or(7);
        if !(1..=365).contains(&since_days) {
            return json_err(format!("since_days must be 1..=365 (got {since_days})"));
        }
        let analyze = p.analyze.unwrap_or(false);
        // T-1710: analyze is rotation-only — heal log is irrelevant to PL-021
        // classification. Ignore include_heals when analyze=true so the caller
        // can't accidentally inflate the classifier with non-rotation rows.
        let include_heals = if analyze {
            false
        } else {
            p.include_heals.unwrap_or(false)
        };

        let Some(home) = std::env::var("HOME").ok() else {
            return json_err("HOME env var not set; cannot resolve rotation.log");
        };
        let rotation_path = std::path::PathBuf::from(&home)
            .join(".termlink")
            .join("rotation.log");
        let heal_path = std::path::PathBuf::from(&home)
            .join(".termlink")
            .join("heal.log");

        // Empty-state path: no logs to read at all.
        // T-1710: when analyze=true, return the CLI T-1690 analyze shape with
        // an empty hubs[] instead of the chronological-listing shape.
        if !rotation_path.exists() && (!include_heals || !heal_path.exists()) {
            if analyze {
                return serde_json::to_string_pretty(&serde_json::json!({
                    "ok": true,
                    "since_days": since_days,
                    "hub_filter": p.hub,
                    "log_path": rotation_path.display().to_string(),
                    "hubs": [],
                    "pl021_candidates": false,
                    "hint": "no rotation history yet — run `fleet doctor --watch` to start capturing",
                }))
                .unwrap_or_else(json_err);
            }
            return serde_json::to_string_pretty(&serde_json::json!({
                "ok": true,
                "entries": [],
                "summary": {
                    "total": 0,
                    "per_hub": {},
                    "since_days": since_days,
                    "hub_filter": p.hub,
                    "log_path": rotation_path.display().to_string(),
                },
                "hint": "no rotation history yet — run `fleet doctor --watch` to start capturing",
            }))
            .unwrap_or_else(json_err);
        }

        let now_secs = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_secs() as i64)
            .unwrap_or(0);
        let cutoff = now_secs - (since_days as i64) * 86_400;

        let mut entries: Vec<serde_json::Value> = Vec::new();
        let mut malformed = 0usize;
        if rotation_path.exists() {
            match std::fs::read_to_string(&rotation_path) {
                Ok(text) => fleet_history_parse_log(
                    &text,
                    "rotation",
                    cutoff,
                    p.hub.as_deref(),
                    &mut entries,
                    &mut malformed,
                ),
                Err(e) => return json_err(format!("cannot read rotation.log: {e}")),
            }
        }

        let mut heal_malformed = 0usize;
        if include_heals && heal_path.exists() {
            match std::fs::read_to_string(&heal_path) {
                Ok(text) => fleet_history_parse_log(
                    &text,
                    "heal",
                    cutoff,
                    p.hub.as_deref(),
                    &mut entries,
                    &mut heal_malformed,
                ),
                Err(e) => return json_err(format!("cannot read heal.log: {e}")),
            }
        }

        // T-1710 (G-057 punch-list #1): short-circuit chronological listing
        // when analyze=true. Returns the same JSON shape the CLI emits with
        // `fleet history --analyze --json` (see emit_pl021_report in remote.rs).
        // Entries here are rotation-only — include_heals was forced to false
        // above when analyze=true, so the classifier sees only transitions.
        if analyze {
            let report = analyze_pl021_mcp(&entries);
            let arr: Vec<serde_json::Value> = report
                .iter()
                .map(|r| {
                    serde_json::json!({
                        "hub": r.hub,
                        "verdict": r.verdict.as_str(),
                        "cert_transitions": r.cert_transitions,
                        "secret_transitions": r.secret_transitions,
                        "double_rotations": r.double_rotations,
                        "last_double_rotation": r.last_double_rotation,
                    })
                })
                .collect();
            let any_candidate = report
                .iter()
                .any(|h| h.verdict == FleetHistoryFlapVerdict::Pl021Candidate);
            return serde_json::to_string_pretty(&serde_json::json!({
                "ok": true,
                "since_days": since_days,
                "hub_filter": p.hub,
                "log_path": rotation_path.display().to_string(),
                "hubs": arr,
                "pl021_candidates": any_candidate,
                "malformed_lines_skipped": malformed,
            }))
            .unwrap_or_else(json_err);
        }

        if include_heals {
            entries.sort_by_key(|e| {
                let ts = e.get("ts").and_then(|v| v.as_str()).unwrap_or("");
                fleet_history_rfc3339_to_unix(ts)
            });
        }

        let mut per_hub_rot: std::collections::BTreeMap<String, u32> =
            std::collections::BTreeMap::new();
        let mut per_hub_heal: std::collections::BTreeMap<String, u32> =
            std::collections::BTreeMap::new();
        for e in &entries {
            let h = e
                .get("hub")
                .and_then(|v| v.as_str())
                .unwrap_or("?")
                .to_string();
            let et = e
                .get("event_type")
                .and_then(|v| v.as_str())
                .unwrap_or("rotation");
            if et == "heal" {
                *per_hub_heal.entry(h).or_insert(0) += 1;
            } else {
                *per_hub_rot.entry(h).or_insert(0) += 1;
            }
        }

        let summary = if include_heals {
            serde_json::json!({
                "total": entries.len(),
                "per_hub_rotation": per_hub_rot,
                "per_hub_heal": per_hub_heal,
                "since_days": since_days,
                "hub_filter": p.hub,
                "malformed_lines_skipped": malformed,
                "heal_malformed_lines_skipped": heal_malformed,
                "rotation_log_path": rotation_path.display().to_string(),
                "heal_log_path": heal_path.display().to_string(),
            })
        } else {
            serde_json::json!({
                "total": entries.len(),
                "per_hub": per_hub_rot,
                "since_days": since_days,
                "hub_filter": p.hub,
                "malformed_lines_skipped": malformed,
                "log_path": rotation_path.display().to_string(),
            })
        };

        serde_json::to_string_pretty(&serde_json::json!({
            "ok": true,
            "entries": entries,
            "summary": summary,
        }))
        .unwrap_or_else(json_err)
    }

    // === Fleet governor-history (T-2069: MCP parity for T-2068) ===

    #[tool(
        name = "termlink_fleet_governor_history",
        description = "T-2069 / T-2068 / T-2028 §6 #10 closure: retrospective read of the governor.log NDJSON audit trail produced by `fleet governor-status --watch --log <path>` (Track G). Walks `~/.termlink/governor.log` (or `log_path` override matching the watch loop's destination), filters by `since_days` window and optional `hub` name, and returns `{ok, entries[], summary{total, per_hub:{<hub>:{events, cap_hits_total, rate_hits_total, dedupe_hits_total}}, since_days, hub_filter, malformed_lines_skipped, log_path}}`. Per-hub aggregates sum the Track G `cap_hits_delta` / `rate_hits_delta` / `dedupe_hits_delta` fields so a caller can answer 'has this hub been refused / rate-limited / had retries absorbed in the window?' in one call. Empty/missing log returns `{ok: true, entries: [], summary: ..., hint: 'no governor history yet — run `fleet governor-status --watch --log <path>` to start capturing'}`. Pure read; no auth; no network; no log mutation. Mirror of `termlink_fleet_history` (T-1687) but pointed at the substrate-governor audit trail. CLI parity: `termlink fleet governor-history`. See `docs/operations/substrate-governor.md`."
    )]
    async fn termlink_fleet_governor_history(
        &self,
        Parameters(p): Parameters<FleetGovernorHistoryParams>,
    ) -> String {
        let since_days = p.since_days.unwrap_or(7);
        if !(1..=365).contains(&since_days) {
            return json_err(format!("since_days must be 1..=365 (got {since_days})"));
        }

        let log_path: std::path::PathBuf = match p.log_path.as_deref() {
            Some(s) => std::path::PathBuf::from(s),
            None => {
                let Some(home) = std::env::var("HOME").ok() else {
                    return json_err(
                        "HOME env var not set; cannot resolve governor.log default path",
                    );
                };
                std::path::PathBuf::from(home)
                    .join(".termlink")
                    .join("governor.log")
            }
        };

        if !log_path.exists() {
            return serde_json::to_string_pretty(&serde_json::json!({
                "ok": true,
                "entries": [],
                "summary": {
                    "total": 0,
                    "per_hub": {},
                    "since_days": since_days,
                    "hub_filter": p.hub,
                    "log_path": log_path.display().to_string(),
                },
                "hint": "no governor history yet — run `fleet governor-status --watch --log <path>` to start capturing",
            }))
            .unwrap_or_else(json_err);
        }

        let text = match std::fs::read_to_string(&log_path) {
            Ok(t) => t,
            Err(e) => return json_err(format!("cannot read {}: {e}", log_path.display())),
        };

        let now_secs = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_secs() as i64)
            .unwrap_or(0);
        let cutoff = now_secs - (since_days as i64) * 86_400;

        let (entries, malformed) =
            parse_governor_log(&text, cutoff, p.hub.as_deref());

        let per_hub = aggregate_governor_entries(&entries);

        let per_hub_json: serde_json::Map<String, serde_json::Value> = per_hub
            .iter()
            .map(|(k, v)| {
                (
                    k.clone(),
                    serde_json::json!({
                        "events": v.events,
                        "cap_hits_total": v.cap_hits,
                        "rate_hits_total": v.rate_hits,
                        "dedupe_hits_total": v.dedupe_hits,
                    }),
                )
            })
            .collect();

        serde_json::to_string_pretty(&serde_json::json!({
            "ok": true,
            "entries": entries,
            "summary": {
                "total": entries.len(),
                "per_hub": per_hub_json,
                "since_days": since_days,
                "hub_filter": p.hub,
                "malformed_lines_skipped": malformed,
                "log_path": log_path.display().to_string(),
            }
        }))
        .unwrap_or_else(json_err)
    }

    // === Channel claims-history (T-2075: MCP parity for T-2074) ===

    #[tool(
        name = "termlink_channel_claims_history",
        description = "T-2075 / T-2074 — retrospective read of the claims.log NDJSON audit trail produced by `channel claims-summary --watch --log <path>`. Walks `~/.termlink/claims.log` (or `log_path` override matching the watch loop's destination), filters by `since_days` window and optional `topic` exact-match, and returns `{ok, entries[], summary{total, per_topic:{<topic>:{transitions, new_events, removed_events}}, since_days, topic_filter, malformed_lines_skipped, log_path}}`. Per-topic aggregates count each change-event kind independently so a caller can answer 'has this topic been flapping (high transitions)?' / 'churning (high new+removed)?' / 'merely transitioned once?' in one call. Empty/missing log returns `{ok: true, entries: [], summary: ..., hint: 'no claim history yet — run `channel claims-summary --watch --log <path>` to start capturing'}`. Pure read; no auth; no network; no log mutation. Mirror of `termlink_fleet_governor_history` (T-2069) but pointed at the substrate claim-primitive observability audit trail. CLI parity: `termlink channel claims-history`."
    )]
    async fn termlink_channel_claims_history(
        &self,
        Parameters(p): Parameters<ChannelClaimsHistoryParams>,
    ) -> String {
        let since_days = p.since_days.unwrap_or(7);
        if !(1..=365).contains(&since_days) {
            return json_err(format!("since_days must be 1..=365 (got {since_days})"));
        }

        let log_path: std::path::PathBuf = match p.log_path.as_deref() {
            Some(s) => std::path::PathBuf::from(s),
            None => {
                let Some(home) = std::env::var("HOME").ok() else {
                    return json_err(
                        "HOME env var not set; cannot resolve claims.log default path",
                    );
                };
                std::path::PathBuf::from(home)
                    .join(".termlink")
                    .join("claims.log")
            }
        };

        if !log_path.exists() {
            return serde_json::to_string_pretty(&serde_json::json!({
                "ok": true,
                "entries": [],
                "summary": {
                    "total": 0,
                    "per_topic": {},
                    "since_days": since_days,
                    "topic_filter": p.topic,
                    "log_path": log_path.display().to_string(),
                },
                "hint": "no claim history yet — run `channel claims-summary --watch --log <path>` to start capturing",
            }))
            .unwrap_or_else(json_err);
        }

        let text = match std::fs::read_to_string(&log_path) {
            Ok(t) => t,
            Err(e) => return json_err(format!("cannot read {}: {e}", log_path.display())),
        };

        let now_secs = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_secs() as i64)
            .unwrap_or(0);
        let cutoff = now_secs - (since_days as i64) * 86_400;

        let (entries, malformed) =
            parse_claims_log(&text, cutoff, p.topic.as_deref());

        let per_topic = aggregate_claims_entries(&entries);

        let per_topic_json: serde_json::Map<String, serde_json::Value> = per_topic
            .iter()
            .map(|(k, v)| {
                (
                    k.clone(),
                    serde_json::json!({
                        "transitions": v.transitions,
                        "new_events": v.new_events,
                        "removed_events": v.removed_events,
                    }),
                )
            })
            .collect();

        serde_json::to_string_pretty(&serde_json::json!({
            "ok": true,
            "entries": entries,
            "summary": {
                "total": entries.len(),
                "per_topic": per_topic_json,
                "since_days": since_days,
                "topic_filter": p.topic,
                "malformed_lines_skipped": malformed,
                "log_path": log_path.display().to_string(),
            }
        }))
        .unwrap_or_else(json_err)
    }

    // === Fleet bootstrap-check (T-1689: MCP parity for T-1688) ===

    #[tool(
        name = "termlink_fleet_bootstrap_check",
        description = "Preflight-validate declared `bootstrap_from` anchors WITHOUT performing any heal. Reuses the live heal fetch+validate path so the check exercises the exact same code path that `--auto-heal` would use. Pass either `profile` for a single hub or `all=true` for the whole fleet. `timeout_secs` (default 10, max 120) caps how long an interactive ssh: anchor can hang the call. Returns the same JSON the CLI emits: {verdict, profiles: [{name, address, bootstrap_from, status, error?}]}."
    )]
    async fn termlink_fleet_bootstrap_check(
        &self,
        Parameters(p): Parameters<FleetBootstrapCheckParams>,
    ) -> String {
        // T-1689 R1: exactly one of profile/all
        let all = p.all.unwrap_or(false);
        match (&p.profile, all) {
            (Some(_), true) => {
                return json_err("pass either `profile` or `all: true`, not both");
            }
            (None, false) => {
                return json_err("must pass either `profile: <name>` or `all: true`");
            }
            _ => {}
        }

        // T-1689 R2: timeout clamp
        let timeout = p.timeout_secs.unwrap_or(10).clamp(1, 120);

        // Resolve own binary path. `current_exe()` returns the running
        // `termlink mcp` binary; same binary handles `fleet bootstrap-check`.
        let exe = match std::env::current_exe() {
            Ok(p) => p,
            Err(e) => return json_err(format!("cannot resolve termlink binary path: {e}")),
        };

        let mut cmd = tokio::process::Command::new(&exe);
        cmd.arg("fleet").arg("bootstrap-check").arg("--json");
        if let Some(name) = p.profile.as_deref() {
            cmd.arg(name);
        } else {
            cmd.arg("--all");
        }
        // T-1689: kill the child on parent drop so a hanging ssh doesn't leak.
        cmd.kill_on_drop(true);
        // Don't inherit stdin; ssh: anchors that would prompt will get EOF + fail.
        cmd.stdin(std::process::Stdio::null());

        let fut = cmd.output();
        let output = match tokio::time::timeout(std::time::Duration::from_secs(timeout), fut).await
        {
            Ok(Ok(o)) => o,
            Ok(Err(e)) => return json_err(format!("subprocess spawn failed: {e}")),
            Err(_) => {
                return serde_json::to_string_pretty(&serde_json::json!({
                    "ok": false,
                    "verdict": "timeout",
                    "error": format!("timeout after {}s", timeout),
                    "hint": "interactive ssh: anchors can hang the subprocess; raise timeout_secs or use a file: anchor",
                }))
                .unwrap_or_else(json_err);
            }
        };

        // CLI's --json path writes verdict+profiles to stdout. On classify
        // failures it sets exit code 1 or 2 but stdout JSON is still valid.
        // If stdout isn't parseable, surface the raw output so the caller
        // can see what went wrong.
        let stdout = String::from_utf8_lossy(&output.stdout).into_owned();
        let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
        let exit_code = output.status.code();

        match serde_json::from_str::<serde_json::Value>(stdout.trim()) {
            Ok(mut parsed) => {
                // Decorate with `ok` for caller convenience and the exit code
                // so the agent can distinguish "0 = all good", "1 = anchor
                // broken", "2 = no anchor declared at all".
                if let Some(obj) = parsed.as_object_mut() {
                    obj.entry("ok".to_string())
                        .or_insert(serde_json::Value::Bool(matches!(exit_code, Some(0))));
                    obj.insert(
                        "exit_code".to_string(),
                        serde_json::json!(exit_code.unwrap_or(-1)),
                    );
                }
                serde_json::to_string_pretty(&parsed).unwrap_or_else(json_err)
            }
            Err(parse_err) => json_err(format!(
                "subprocess returned non-JSON output (exit={:?}): {parse_err}\nstdout: {}\nstderr: {}",
                exit_code,
                stdout.chars().take(300).collect::<String>(),
                stderr.chars().take(300).collect::<String>()
            )),
        }
    }

    // === Fleet secrets-audit (T-1821: MCP parity for T-1820) ===

    #[tool(
        name = "termlink_fleet_secrets_audit",
        description = "Audit local secrets cache (`~/.termlink/secrets/*.hex` by default) for security hygiene. Per-file taxonomy: ok / ok-mirror (matches authoritative) / warn-perms (mode > 0o600 — G-011 incident proxmox4.hex@0o644) / warn-format (not 64 hex chars) / warn-drift (T-1822: content differs from authoritative hub.secret) / info-orphan (not referenced by any hubs.toml profile). Read-only — no auth, no network, no writes. `dir` overrides the default scan path. `check_drift` (T-1823) names the authoritative `<runtime_dir>/hub.secret` for content-comparison; when set, the envelope gains an `authoritative` block. `target_cache` (T-1825) narrows drift comparison to ONE named cache file — non-target rows skip drift and fall back to plain perms/format/orphan verdict; eliminates broad-mode false positives when the scan dir has caches for multiple hubs. `timeout_secs` (default 10, clamped 1..=120) caps the subprocess. Returns the CLI's JSON envelope decorated with `exit_code`: `{ok, dir, target_cache, files: [{path, mode, size, status, reasons}], summary: {total, ok, ok_mirror, warn_perms, warn_format, warn_drift, info_orphan}, authoritative?: {...}, authoritative_error?: \"...\", target_cache_error?: \"...\", exit_code}`. `ok: true` means zero warn-perms AND zero warn-format AND zero warn-drift (orphan is informational)."
    )]
    async fn termlink_fleet_secrets_audit(
        &self,
        Parameters(p): Parameters<FleetSecretsAuditParams>,
    ) -> String {
        let timeout = p.timeout_secs.unwrap_or(10).clamp(1, 120);

        let exe = match std::env::current_exe() {
            Ok(p) => p,
            Err(e) => return json_err(format!("cannot resolve termlink binary path: {e}")),
        };

        let mut cmd = tokio::process::Command::new(&exe);
        cmd.arg("fleet").arg("secrets-audit").arg("--json");
        if let Some(d) = p.dir.as_deref() {
            cmd.arg("--dir").arg(d);
        }
        // T-1823: forward --check-drift when set. The CLI flag takes a path;
        // we pass it through verbatim (the CLI handles `~/`-expansion).
        if let Some(auth) = p.check_drift.as_deref() {
            cmd.arg("--check-drift").arg(auth);
        }
        // T-1825: forward --target-cache when set. CLI enforces it must be
        // paired with --check-drift (rejects standalone with exit 2).
        if let Some(tgt) = p.target_cache.as_deref() {
            cmd.arg("--target-cache").arg(tgt);
        }
        cmd.kill_on_drop(true);
        cmd.stdin(std::process::Stdio::null());

        let fut = cmd.output();
        let output = match tokio::time::timeout(std::time::Duration::from_secs(timeout), fut).await
        {
            Ok(Ok(o)) => o,
            Ok(Err(e)) => return json_err(format!("subprocess spawn failed: {e}")),
            Err(_) => {
                return serde_json::to_string_pretty(&serde_json::json!({
                    "ok": false,
                    "verdict": "timeout",
                    "error": format!("timeout after {}s", timeout),
                    "hint": "audit is filesystem-only; a timeout here implies a stuck FS or excessive directory size — investigate the scan path",
                }))
                .unwrap_or_else(json_err);
            }
        };

        let stdout = String::from_utf8_lossy(&output.stdout).into_owned();
        let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
        let exit_code = output.status.code();

        // CLI emits the envelope to stdout. Exit 1 == any warn-perms or
        // warn-format (per cmd_fleet_secrets_audit). Decorate the parsed
        // JSON with `exit_code` so the caller can tell "0 = clean", "1 =
        // actionable warning" without re-counting.
        match serde_json::from_str::<serde_json::Value>(stdout.trim()) {
            Ok(mut parsed) => {
                if let Some(obj) = parsed.as_object_mut() {
                    obj.insert(
                        "exit_code".to_string(),
                        serde_json::json!(exit_code.unwrap_or(-1)),
                    );
                }
                serde_json::to_string_pretty(&parsed).unwrap_or_else(json_err)
            }
            Err(parse_err) => json_err(format!(
                "subprocess returned non-JSON output (exit={:?}): {parse_err}\nstdout: {}\nstderr: {}",
                exit_code,
                stdout.chars().take(300).collect::<String>(),
                stderr.chars().take(300).collect::<String>()
            )),
        }
    }

    // === Fleet reauth (T-1728) — single-profile rotation heal RPC ===

    #[tool(
        name = "termlink_fleet_reauth",
        description = "Single-profile rotation heal RPC — MCP parity for `termlink fleet reauth <profile>` (T-1054/T-1055/T-1291). Modes: omit `bootstrap_from` for Tier-1 plan-only (returns the SSH-read → file-write incantation as `plan_text`, no writes); pass `\"auto\"` to use the profile's declared `bootstrap_from` in hubs.toml; pass `file:<path>` or `ssh:<host>` for an explicit Tier-2 heal. The Tier-2 path fetches the new secret out-of-band, validates 64-char hex, backs up the existing secret_file to `.hex.bak`, atomically writes the new file at chmod 600, and returns a 12-char fingerprint preview. R2: `command:<shell>` scheme rejected (security review pending). Refuses profiles with inline `secret = ...` (must convert to `secret_file` first). Returns: `{ok, profile, mode, source, secret_file, fingerprint_preview, plan_text, error, exit_code}`."
    )]
    async fn termlink_fleet_reauth(
        &self,
        Parameters(p): Parameters<FleetReauthParams>,
    ) -> String {
        // R2: reject command: scheme explicitly (Tier-2 has the same exclusion).
        if let Some(src) = p.bootstrap_from.as_deref() {
            if src.starts_with("command:") {
                return json_err(
                    "bootstrap_from scheme `command:` rejected (R2 — arbitrary shell anchor requires explicit security review; not yet allowed). Use `file:<path>` or `ssh:<host>`.",
                );
            }
        }

        let timeout = p.timeout_secs.unwrap_or(10).clamp(1, 120);

        // Resolve own binary path. `current_exe()` returns the running
        // `termlink mcp` binary; same binary handles `fleet reauth --json`.
        let exe = match std::env::current_exe() {
            Ok(p) => p,
            Err(e) => return json_err(format!("cannot resolve termlink binary path: {e}")),
        };

        let mut cmd = tokio::process::Command::new(&exe);
        cmd.arg("fleet").arg("reauth").arg(&p.profile).arg("--json");
        if let Some(src) = p.bootstrap_from.as_deref() {
            cmd.arg("--bootstrap-from").arg(src);
        }
        cmd.kill_on_drop(true);
        cmd.stdin(std::process::Stdio::null());

        let fut = cmd.output();
        let output = match tokio::time::timeout(std::time::Duration::from_secs(timeout), fut).await
        {
            Ok(Ok(o)) => o,
            Ok(Err(e)) => return json_err(format!("subprocess spawn failed: {e}")),
            Err(_) => {
                return serde_json::to_string_pretty(&serde_json::json!({
                    "ok": false,
                    "verdict": "timeout",
                    "error": format!("timeout after {}s", timeout),
                    "hint": "interactive ssh: anchors can hang the subprocess; raise timeout_secs or use a file: anchor",
                }))
                .unwrap_or_else(json_err);
            }
        };

        let stdout = String::from_utf8_lossy(&output.stdout).into_owned();
        let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
        let exit_code = output.status.code();

        // CLI --json emits the structured outcome to stdout. On non-zero
        // exit (e.g. unknown profile, fetch failure, invalid hex) the CLI
        // bails with anyhow::bail! BEFORE printing JSON — so stdout is
        // empty and we surface the stderr as `error`.
        if stdout.trim().is_empty() {
            return serde_json::to_string_pretty(&serde_json::json!({
                "ok": false,
                "profile": p.profile,
                "mode": serde_json::Value::Null,
                "source": p.bootstrap_from,
                "secret_file": serde_json::Value::Null,
                "fingerprint_preview": serde_json::Value::Null,
                "plan_text": serde_json::Value::Null,
                "error": stderr.trim(),
                "exit_code": exit_code.unwrap_or(-1),
            }))
            .unwrap_or_else(json_err);
        }

        match serde_json::from_str::<serde_json::Value>(stdout.trim()) {
            Ok(mut parsed) => {
                if let Some(obj) = parsed.as_object_mut() {
                    obj.insert(
                        "exit_code".to_string(),
                        serde_json::json!(exit_code.unwrap_or(-1)),
                    );
                }
                serde_json::to_string_pretty(&parsed).unwrap_or_else(json_err)
            }
            Err(parse_err) => json_err(format!(
                "subprocess returned non-JSON stdout (exit={:?}): {parse_err}\nstdout: {}\nstderr: {}",
                exit_code,
                stdout.chars().take(300).collect::<String>(),
                stderr.chars().take(300).collect::<String>()
            )),
        }
    }

    // === Hub restart (T-1040) ===

    #[tool(
        name = "termlink_hub_restart",
        description = "Restart the local termlink hub. Stops the running hub process and starts a new one, preserving TCP binding and runtime directory. Returns the new hub PID on success."
    )]
    async fn termlink_hub_restart(&self, Parameters(_p): Parameters<HubRestartParams>) -> String {
        use termlink_hub::pidfile;

        let (pidfile_path, _) = resolve_hub_paths();

        let old_pid = match pidfile::check(&pidfile_path) {
            pidfile::PidfileStatus::Running(pid) => pid,
            pidfile::PidfileStatus::Stale(pid) => {
                return serde_json::to_string_pretty(&serde_json::json!({
                    "ok": false,
                    "error": format!("Hub PID {} is stale (dead). Use hub start instead.", pid),
                })).unwrap_or_else(json_err);
            }
            pidfile::PidfileStatus::NotRunning => {
                return serde_json::to_string_pretty(&serde_json::json!({
                    "ok": false,
                    "error": "Hub is not running. Use hub start to start it.",
                })).unwrap_or_else(json_err);
            }
        };

        // Determine TCP address from existing hub config
        let runtime_dir = pidfile_path.parent().unwrap_or(std::path::Path::new("/tmp"));
        let tcp_flag_path = runtime_dir.join("hub.tcp");
        let tcp_addr = std::fs::read_to_string(&tcp_flag_path)
            .ok()
            .map(|s| s.trim().to_string());

        // Find our own binary path
        let self_exe = match std::env::current_exe() {
            Ok(p) => p,
            Err(e) => return json_err(format!("Cannot determine own binary path: {e}")),
        };

        // Build the hub start command
        let mut cmd = std::process::Command::new(&self_exe);
        cmd.arg("hub").arg("start");
        if let Some(ref addr) = tcp_addr {
            cmd.arg("--tcp").arg(addr);
        }

        // Preserve non-default runtime dir (e.g., /var/lib/termlink)
        let default_runtime = termlink_session::discovery::runtime_dir();
        if pidfile_path.parent().is_some_and(|d| d != default_runtime.as_path()) {
            cmd.env("TERMLINK_RUNTIME_DIR", pidfile_path.parent().unwrap());
        }

        cmd.stdin(std::process::Stdio::null());
        cmd.stdout(std::process::Stdio::null());
        cmd.stderr(std::process::Stdio::null());

        // Stop the old hub
        unsafe { libc::kill(old_pid as i32, libc::SIGTERM) };

        // Wait for old hub to die (up to 3s)
        for _ in 0..30 {
            std::thread::sleep(std::time::Duration::from_millis(100));
            if !termlink_session::liveness::process_exists(old_pid) {
                break;
            }
        }

        if termlink_session::liveness::process_exists(old_pid) {
            return serde_json::to_string_pretty(&serde_json::json!({
                "ok": false,
                "error": format!("Old hub (PID {}) did not stop within 3s", old_pid),
            })).unwrap_or_else(json_err);
        }

        // Spawn new hub
        match cmd.spawn() {
            Ok(_child) => {
                // Wait briefly for new hub to start
                std::thread::sleep(std::time::Duration::from_millis(500));

                // Check if new hub is running
                let new_status = pidfile::check(&pidfile_path);
                match new_status {
                    pidfile::PidfileStatus::Running(new_pid) => {
                        serde_json::to_string_pretty(&serde_json::json!({
                            "ok": true,
                            "old_pid": old_pid,
                            "new_pid": new_pid,
                            "tcp": tcp_addr,
                            "message": format!("Hub restarted: {} -> {}", old_pid, new_pid),
                        })).unwrap_or_else(json_err)
                    }
                    _ => {
                        serde_json::to_string_pretty(&serde_json::json!({
                            "ok": false,
                            "old_pid": old_pid,
                            "error": "New hub process started but pidfile not yet written. Check hub logs.",
                        })).unwrap_or_else(json_err)
                    }
                }
            }
            Err(e) => json_err(format!("Failed to spawn new hub: {e}")),
        }
    }

    // === Events (T-1040) ===

    #[tool(
        name = "termlink_events",
        description = "Query event history from a local session. Returns events with sequence numbers, topics, timestamps, and payloads. Use 'since' to get events after a specific sequence number."
    )]
    async fn termlink_events(&self, Parameters(p): Parameters<EventsParams>) -> String {
        let reg = match manager::find_session(&p.target) {
            Ok(r) => r,
            Err(e) => return json_err(format!("Session '{}' not found: {e}", p.target)),
        };

        let mut params = serde_json::json!({});
        if let Some(s) = p.since {
            params["since"] = serde_json::json!(s);
        }
        if let Some(ref t) = p.topic {
            params["topic"] = serde_json::json!(t);
        }

        let timeout_secs = p.timeout.unwrap_or(5);
        let timeout_dur = std::time::Duration::from_secs(timeout_secs);
        let rpc = client::rpc_call(reg.socket_path(), "event.poll", params);

        let resp = match tokio::time::timeout(timeout_dur, rpc).await {
            Ok(Ok(v)) => v,
            Ok(Err(e)) => return json_err(format!("Failed to connect to session: {e}")),
            Err(_) => return json_err(format!("Event poll timed out after {timeout_secs}s")),
        };

        match client::unwrap_result(resp) {
            Ok(result) => {
                let events = result["events"].as_array();
                let count = events.map(|e| e.len()).unwrap_or(0);
                serde_json::to_string_pretty(&serde_json::json!({
                    "ok": true,
                    "target": p.target,
                    "count": count,
                    "next_seq": result["next_seq"],
                    "events": result["events"],
                })).unwrap_or_else(json_err)
            }
            Err(e) => json_err(format!("Event poll failed: {e}")),
        }
    }

    // === Channel Bus Tools (T-1160, T-1155) ===

    #[tool(
        name = "termlink_channel_create",
        description = "Create a T-1155 bus topic with a retention policy on the local hub. Idempotent on name — a second call with the same policy is a no-op; a conflicting policy returns an error."
    )]
    async fn termlink_channel_create(
        &self,
        Parameters(p): Parameters<ChannelCreateParams>,
    ) -> String {
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }
        let retention = match p.retention_kind.as_deref().unwrap_or("forever") {
            "forever" => serde_json::json!({"kind": "forever"}),
            "days" => serde_json::json!({"kind": "days", "value": p.retention_value.unwrap_or(30)}),
            "messages" => serde_json::json!({"kind": "messages", "value": p.retention_value.unwrap_or(1000)}),
            other => return json_err(format!("unknown retention_kind: {other}")),
        };
        match termlink_session::client::rpc_call(
            &hub_socket,
            termlink_protocol::control::method::CHANNEL_CREATE,
            serde_json::json!({"name": p.name, "retention": retention}),
        )
        .await
        {
            Ok(resp) => match termlink_session::client::unwrap_result(resp) {
                Ok(result) => serde_json::to_string_pretty(&result).unwrap_or_else(json_err),
                Err(e) => json_err(format!("channel.create error: {e}")),
            },
            Err(e) => json_err(format!("RPC call failed: {e}")),
        }
    }

    #[tool(
        name = "termlink_channel_post",
        description = "Post a signed envelope to a T-1155 bus topic on the local hub. The post is signed with the caller's ed25519 identity (auto-initialized at ~/.termlink/identity.key on first use)."
    )]
    async fn termlink_channel_post(
        &self,
        Parameters(p): Parameters<ChannelPostParams>,
    ) -> String {
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }
        let payload_bytes = match (p.payload, p.payload_b64) {
            (Some(s), None) => s.into_bytes(),
            (None, Some(b64)) => match base64::engine::general_purpose::STANDARD.decode(&b64) {
                Ok(b) => b,
                Err(e) => return json_err(format!("payload_b64 decode: {e}")),
            },
            (Some(_), Some(_)) => return json_err("pass either 'payload' or 'payload_b64', not both"),
            (None, None) => return json_err("pass 'payload' (string) or 'payload_b64' (base64)"),
        };
        let msg_type = p.msg_type.unwrap_or_else(|| "note".to_string());
        let home = match std::env::var("HOME") {
            Ok(h) => h,
            Err(_) => return json_err("HOME not set"),
        };
        let identity_dir = std::path::PathBuf::from(home).join(".termlink");
        let identity = match termlink_session::agent_identity::Identity::load_or_create(&identity_dir) {
            Ok(i) => i,
            Err(e) => return json_err(format!("identity load: {e}")),
        };
        let ts_unix_ms = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_millis() as i64)
            .unwrap_or(0);
        let signed = termlink_protocol::control::channel::canonical_sign_bytes(
            &p.topic,
            &msg_type,
            &payload_bytes,
            p.artifact_ref.as_deref(),
            ts_unix_ms,
        );
        let sig = identity.sign(&signed);
        let mut sig_hex = String::with_capacity(128);
        for b in sig.to_bytes() {
            use std::fmt::Write;
            let _ = write!(&mut sig_hex, "{b:02x}");
        }
        let sender_id = p.sender_id.unwrap_or_else(|| identity.fingerprint().to_string());
        let mut params = serde_json::json!({
            "topic": p.topic,
            "msg_type": msg_type,
            "payload_b64": base64::engine::general_purpose::STANDARD.encode(&payload_bytes),
            "artifact_ref": p.artifact_ref,
            "ts": ts_unix_ms,
            "sender_id": sender_id,
            "sender_pubkey_hex": identity.public_key_hex(),
            "signature_hex": sig_hex,
        });
        // T-1694: pass-through metadata when the caller supplied any. The hub
        // parses params["metadata"] as a string→string map; omitting the key
        // preserves the prior behavior (empty envelope.metadata).
        if let Some(md) = p.metadata
            && !md.is_empty()
            && let Some(obj) = params.as_object_mut() {
            obj.insert(
                "metadata".to_string(),
                serde_json::to_value(&md).unwrap_or_else(|_| serde_json::json!({})),
            );
        }
        match termlink_session::client::rpc_call(
            &hub_socket,
            termlink_protocol::control::method::CHANNEL_POST,
            params,
        )
        .await
        {
            Ok(resp) => match termlink_session::client::unwrap_result(resp) {
                Ok(result) => serde_json::to_string_pretty(&result).unwrap_or_else(json_err),
                Err(e) => json_err(format!("channel.post error: {e}")),
            },
            Err(e) => json_err(format!("RPC call failed: {e}")),
        }
    }

    #[tool(
        name = "termlink_agent_post",
        description = "Post a note to agent-chat-arc — the canonical termlink agent-to-agent visibility topic. Defaults topic to 'agent-chat-arc' and msg_type to 'note'. Optional thread/project metadata is recorded under `metadata._thread` / `metadata._project`. Companion to the `agent post` CLI verb (T-1503): both auto-sign with the local ed25519 identity. Use this from any MCP-aware client to broadcast progress / reach the fleet without shelling out (T-1560)."
    )]
    async fn termlink_agent_post(
        &self,
        Parameters(p): Parameters<AgentPostParams>,
    ) -> String {
        use base64::Engine;
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }
        let topic = "agent-chat-arc";
        let msg_type = p.msg_type.unwrap_or_else(|| "note".to_string());
        let payload_bytes = p.text.into_bytes();
        let home = match std::env::var("HOME") {
            Ok(h) => h,
            Err(_) => return json_err("HOME not set"),
        };
        let identity_dir = std::path::PathBuf::from(home).join(".termlink");
        let identity = match termlink_session::agent_identity::Identity::load_or_create(&identity_dir) {
            Ok(i) => i,
            Err(e) => return json_err(format!("identity load: {e}")),
        };
        let ts_unix_ms = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_millis() as i64)
            .unwrap_or(0);
        let signed = termlink_protocol::control::channel::canonical_sign_bytes(
            topic,
            &msg_type,
            &payload_bytes,
            None,
            ts_unix_ms,
        );
        let sig = identity.sign(&signed);
        let mut sig_hex = String::with_capacity(128);
        for b in sig.to_bytes() {
            use std::fmt::Write;
            let _ = write!(&mut sig_hex, "{b:02x}");
        }
        let sender_id = p.sender_id.unwrap_or_else(|| identity.fingerprint().to_string());
        let mut metadata = serde_json::Map::new();
        if let Some(t) = p.thread.as_ref() {
            metadata.insert("_thread".to_string(), serde_json::Value::String(t.clone()));
            metadata.insert("thread".to_string(), serde_json::Value::String(t.clone()));
        }
        if let Some(pr) = p.project.as_ref() {
            metadata.insert("_project".to_string(), serde_json::Value::String(pr.clone()));
            metadata.insert("from_project".to_string(), serde_json::Value::String(pr.clone()));
        }
        let mut params = serde_json::json!({
            "topic": topic,
            "msg_type": msg_type,
            "payload_b64": base64::engine::general_purpose::STANDARD.encode(&payload_bytes),
            "ts": ts_unix_ms,
            "sender_id": sender_id,
            "sender_pubkey_hex": identity.public_key_hex(),
            "signature_hex": sig_hex,
        });
        if !metadata.is_empty() {
            params["metadata"] = serde_json::Value::Object(metadata);
        }
        match termlink_session::client::rpc_call(
            &hub_socket,
            termlink_protocol::control::method::CHANNEL_POST,
            params,
        )
        .await
        {
            Ok(resp) => match termlink_session::client::unwrap_result(resp) {
                Ok(result) => serde_json::to_string_pretty(&result).unwrap_or_else(json_err),
                Err(e) => json_err(format!("agent.post error: {e}")),
            },
            Err(e) => json_err(format!("RPC call failed: {e}")),
        }
    }

    #[tool(
        name = "termlink_agent_contact",
        description = "Contact a peer agent on its canonical `dm:<sorted_a>:<sorted_b>` topic — MCP parity for the `termlink agent contact` CLI verb (T-1429 Phase-2). Resolves `target` (display name) via local `session.discover` to read `identity_fingerprint` (T-1436), OR uses `target_fp` (hex) directly for cross-host peers. Auto-creates the dm topic with `retention=forever` (idempotent), signs the envelope with local ed25519 identity, and posts with `msg_type=chat`. Optional `thread` stamps `metadata._thread` for agent-chat-arc protocol canon routing. `:project` suffix on `target` stamps `metadata.to_project` (T-1448 (b)). `dry_run=true` returns the resolved topic + metadata preview without posting. Mutually exclusive: exactly one of `target` / `target_fp` required. **Body sources (T-1717):** exactly one of `message` (inline string) / `body_file` (path read at the MCP server's cwd — mirror of CLI `--file PATH`, T-1646). Empty file rejected. **Synchronous-engagement flags (T-1716):** `require_online=true` probes agent-chat-arc within `online_window_secs` (default 300, clamped [10, 86400]) before posting — fail-fast with `{ok: false, online_check, error}` if peer has zero posts in window (CLI exit-9 semantic). `ack_required=true` polls the dm topic at ~1s cadence up to `ack_timeout_secs` (default 60, clamped [5, 600]) for a non-meta peer reply — returns `ack: {received, ts_ms?, wait_secs}` on the success envelope (CLI exit-10 semantic mapped to `received=false`)."
    )]
    async fn termlink_agent_contact(
        &self,
        Parameters(p): Parameters<AgentContactParams>,
    ) -> String {
        use base64::Engine;

        // Mutex validation: exactly one of target / target_fp required.
        match (&p.target, &p.target_fp) {
            (Some(_), Some(_)) => {
                return json_err("specify either 'target' or 'target_fp', not both");
            }
            (None, None) => {
                return json_err("must specify either 'target' (display name) or 'target_fp' (hex)");
            }
            _ => {}
        }

        // T-1717: resolve message / body_file into a single body String.
        // Mirror of CLI `resolve_contact_message` (commands/agent.rs:698).
        let body = match resolve_message_or_file_mcp(
            p.message.as_deref(),
            p.body_file.as_deref(),
        ) {
            Ok(b) => b,
            Err(e) => return json_err(format!("T-1717: {e}")),
        };

        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }

        // Parse positional target for `:project` suffix (T-1448 (b)).
        // Mirrors `commands::agent::parse_contact_target` semantics.
        let (target_name, to_project): (Option<String>, Option<String>) = if let Some(raw) = &p.target {
            match split_target_project(raw) {
                Ok((name, proj)) => (Some(name), proj),
                Err(e) => return json_err(e),
            }
        } else {
            (None, None)
        };

        // Resolve peer_fp: either trust target_fp directly (after hex
        // validation), or look up via session.discover (local-only).
        let peer_fp: String = if let Some(fp) = &p.target_fp {
            if fp.len() < 8 || !fp.chars().all(|c| c.is_ascii_hexdigit()) {
                return json_err(format!("target_fp must be hex (got {fp:?})"));
            }
            fp.clone()
        } else {
            let name = target_name.as_deref().expect("checked above");
            let reg = match manager::find_session(name) {
                Ok(r) => r,
                Err(e) => return json_err(format!("session '{name}' not found: {e}")),
            };
            match reg.metadata.identity_fingerprint.clone() {
                Some(fp) => fp,
                None => return json_err(format!(
                    "peer '{name}' has no identity_fingerprint in metadata — likely registered before T-1436. Three recovery paths: (1) upgrade the peer's termlink binary and restart the session; (2) pass 'target_fp' (hex) directly; (3) use `termlink_channel_post` against agent-chat-arc with --mention to reach the peer broadcast-style."
                )),
            }
        };

        // Load identity (mirror of termlink_agent_post).
        let home = match std::env::var("HOME") {
            Ok(h) => h,
            Err(_) => return json_err("HOME not set"),
        };
        let identity_dir = std::path::PathBuf::from(home).join(".termlink");
        let identity = match termlink_session::agent_identity::Identity::load_or_create(&identity_dir) {
            Ok(i) => i,
            Err(e) => return json_err(format!("identity load: {e}")),
        };
        let my_fp = identity.fingerprint().to_string();

        // Compute canonical dm topic (mirror of commands::channel::dm_topic).
        let topic = dm_topic_canonical(&my_fp, &peer_fp);

        // Build metadata block.
        let mut metadata = serde_json::Map::new();
        if let Some(t) = &p.thread {
            metadata.insert("_thread".to_string(), serde_json::Value::String(t.clone()));
        }
        if let Some(proj) = &to_project {
            metadata.insert("to_project".to_string(), serde_json::Value::String(proj.clone()));
        }

        // Dry-run path: render preview JSON, no hub round-trip.
        if p.dry_run.unwrap_or(false) {
            return serde_json::to_string_pretty(&serde_json::json!({
                "ok": true,
                "dry_run": true,
                "topic": topic,
                "peer_fp": peer_fp,
                "my_fp": my_fp,
                "metadata": metadata,
                "would_post": {
                    "msg_type": "chat",
                    "body_preview": preview_body(&body, 80),
                    "body_bytes": body.len(),
                }
            }))
            .unwrap_or_else(json_err);
        }

        // T-1716: pre-flight presence probe when require_online is set.
        // Mirrors CLI exit-9 semantics (T-1480) — fail-fast without posting.
        if p.require_online.unwrap_or(false) {
            let window_secs = p.online_window_secs.unwrap_or(300).clamp(10, 86_400);
            let chat_arc_msgs = match fetch_topic_msgs_mcp(&hub_socket, "agent-chat-arc", 500).await
            {
                Ok(m) => m,
                Err(e) => return json_err(format!("require_online: agent-chat-arc probe failed: {e}")),
            };
            let now_ms = std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .map(|d| d.as_millis() as i64)
                .unwrap_or(0);
            let window_ms = (window_secs as i64).saturating_mul(1000);
            let presence = evaluate_presence_msgs(&chat_arc_msgs, &peer_fp, now_ms, window_ms);
            if !presence.online {
                let last_seen_phrase = match presence.last_seen_ms {
                    Some(ms) => {
                        let age_secs = ((now_ms - ms) / 1000).max(0);
                        format!("last seen {age_secs}s ago (ts_ms={ms})")
                    }
                    None => "last seen: never (no posts on agent-chat-arc)".to_string(),
                };
                return serde_json::to_string_pretty(&serde_json::json!({
                    "ok": false,
                    "peer_fp": peer_fp,
                    "online_check": {
                        "online": presence.online,
                        "last_seen_ms": presence.last_seen_ms,
                        "posts_in_window": presence.posts_in_window,
                        "window_secs": presence.window_secs,
                    },
                    "error": format!(
                        "peer fp={} not online — {last_seen_phrase}, window={window_secs}s. Re-run without require_online to queue the post (chat-arc is offset-durable), or wait for the peer's next heartbeat.",
                        peer_fp
                    ),
                }))
                .unwrap_or_else(json_err);
            }
        }

        // Capture send timestamp BEFORE posting so the ack-wait poll only
        // matches messages strictly after our post. T-1485 / T-1716 parity.
        let send_ts_ms_for_ack = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_millis() as i64)
            .unwrap_or(0);

        // Ensure dm topic exists (idempotent, retention=forever).
        let create_result = termlink_session::client::rpc_call(
            &hub_socket,
            termlink_protocol::control::method::CHANNEL_CREATE,
            serde_json::json!({"name": topic, "retention": {"kind": "forever"}}),
        )
        .await;
        if let Err(e) = create_result {
            return json_err(format!("channel.create transport: {e}"));
        }

        // Sign + post.
        let msg_type = "chat";
        let payload_bytes = body.as_bytes();
        let ts_unix_ms = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_millis() as i64)
            .unwrap_or(0);
        let signed = termlink_protocol::control::channel::canonical_sign_bytes(
            &topic,
            msg_type,
            payload_bytes,
            None,
            ts_unix_ms,
        );
        let sig = identity.sign(&signed);
        let mut sig_hex = String::with_capacity(128);
        for b in sig.to_bytes() {
            use std::fmt::Write;
            let _ = write!(&mut sig_hex, "{b:02x}");
        }
        let sender_id = p.sender_id.unwrap_or(my_fp.clone());
        let mut post_params = serde_json::json!({
            "topic": topic,
            "msg_type": msg_type,
            "payload_b64": base64::engine::general_purpose::STANDARD.encode(payload_bytes),
            "ts": ts_unix_ms,
            "sender_id": sender_id,
            "sender_pubkey_hex": identity.public_key_hex(),
            "signature_hex": sig_hex,
        });
        if !metadata.is_empty()
            && let Some(obj) = post_params.as_object_mut()
        {
            obj.insert("metadata".to_string(), serde_json::Value::Object(metadata));
        }
        let post_result = match termlink_session::client::rpc_call(
            &hub_socket,
            termlink_protocol::control::method::CHANNEL_POST,
            post_params,
        )
        .await
        {
            Ok(resp) => match termlink_session::client::unwrap_result(resp) {
                Ok(result) => result,
                Err(e) => return json_err(format!("agent contact: channel.post error: {e}")),
            },
            Err(e) => return json_err(format!("agent contact: RPC failed: {e}")),
        };

        // Decorate hub's reply with topic + peer_fp for caller convenience.
        let mut envelope = serde_json::json!({
            "ok": true,
            "topic": topic,
            "peer_fp": peer_fp,
            "my_fp": my_fp,
        });
        if let Some(obj) = envelope.as_object_mut()
            && let Some(post_obj) = post_result.as_object()
        {
            for (k, v) in post_obj {
                obj.insert(k.clone(), v.clone());
            }
        }

        // T-1716: synchronous-engagement — poll dm topic for an ack.
        // Mirrors CLI exit-10 semantics (T-1485); MCP returns
        // `ack.received=false` on timeout instead of an exit code.
        if p.ack_required.unwrap_or(false) {
            let timeout_secs = p.ack_timeout_secs.unwrap_or(60).clamp(5, 600);
            let start = std::time::Instant::now();
            let mut ack_ts: Option<i64> = None;
            loop {
                match fetch_topic_msgs_mcp(&hub_socket, &topic, 200).await {
                    Ok(msgs) => {
                        if let Some(ts) = detect_ack_in_msgs_mcp(&msgs, &peer_fp, send_ts_ms_for_ack)
                        {
                            ack_ts = Some(ts);
                            break;
                        }
                    }
                    Err(e) => {
                        // Hub unreachable mid-poll — surface as ack.error but
                        // preserve the successful post envelope.
                        if let Some(obj) = envelope.as_object_mut() {
                            obj.insert(
                                "ack".to_string(),
                                serde_json::json!({
                                    "received": false,
                                    "wait_secs": start.elapsed().as_secs(),
                                    "error": format!("ack poll failed: {e}"),
                                }),
                            );
                        }
                        return serde_json::to_string_pretty(&envelope).unwrap_or_else(json_err);
                    }
                }
                if start.elapsed().as_secs() >= timeout_secs {
                    break;
                }
                tokio::time::sleep(std::time::Duration::from_secs(1)).await;
            }
            let wait_secs = start.elapsed().as_secs();
            let ack_obj = match ack_ts {
                Some(ts) => serde_json::json!({
                    "received": true,
                    "ts_ms": ts,
                    "wait_secs": wait_secs,
                }),
                None => serde_json::json!({
                    "received": false,
                    "wait_secs": wait_secs,
                    "timeout_secs": timeout_secs,
                }),
            };
            if let Some(obj) = envelope.as_object_mut() {
                obj.insert("ack".to_string(), ack_obj);
            }
        }

        serde_json::to_string_pretty(&envelope).unwrap_or_else(json_err)
    }

    #[tool(
        name = "termlink_agent_ping",
        description = "Single-peer liveness probe — MCP parity for the `termlink agent ping` CLI verb (T-1487). Walks `agent-chat-arc` for the peer's recent activity over `window_secs` (default 300, clamped [10, 86_400]); returns a presence envelope `{ok, target_or_fp, peer_fp, online, last_seen_ms, last_seen, window_secs, posts_in_window}`. NEVER posts — pure read. Companion to fleet-wide `termlink_agent_presence_now` / `termlink_agent_active_now`: those answer 'who's around?'; ping answers 'is THIS peer around?'. Mutually exclusive: exactly one of `target` (display name, resolved via local session.discover) / `target_fp` (hex, cross-host bypass). Reuses the T-1716 `fetch_topic_msgs_mcp` + `evaluate_presence_msgs` helpers — no new RPC surface."
    )]
    async fn termlink_agent_ping(
        &self,
        Parameters(p): Parameters<AgentPingParams>,
    ) -> String {
        // Mutex validation — same shape as agent_contact.
        match (&p.target, &p.target_fp) {
            (Some(_), Some(_)) => {
                return json_err("specify either 'target' or 'target_fp', not both");
            }
            (None, None) => {
                return json_err("must specify either 'target' (display name) or 'target_fp' (hex)");
            }
            _ => {}
        }

        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }

        // Resolve peer_fp: trust target_fp after hex validation, or look up
        // via session.discover (local-only).
        let display_target = match (&p.target, &p.target_fp) {
            (Some(t), _) => t.clone(),
            (None, Some(fp)) => fp.clone(),
            _ => unreachable!("mutex above"),
        };
        let peer_fp: String = if let Some(fp) = &p.target_fp {
            if fp.len() < 8 || !fp.chars().all(|c| c.is_ascii_hexdigit()) {
                return json_err(format!("target_fp must be hex (got {fp:?})"));
            }
            fp.clone()
        } else {
            let raw = p.target.as_deref().expect("checked above");
            // Strip any `:project` suffix — for ping, project is ignored.
            // (CLI `agent ping` doesn't accept `:project`; we mirror that.)
            let name = raw.split(':').next().unwrap_or(raw);
            let reg = match manager::find_session(name) {
                Ok(r) => r,
                Err(e) => return json_err(format!("session '{name}' not found: {e}")),
            };
            match reg.metadata.identity_fingerprint.clone() {
                Some(fp) => fp,
                None => return json_err(format!(
                    "peer '{name}' has no identity_fingerprint in metadata — likely registered before T-1436. Pass 'target_fp' (hex) directly to bypass session.discover."
                )),
            }
        };

        // Default + clamp window — mirror CLI default 300, [10, 86400].
        let window_secs = p.window_secs.unwrap_or(300).clamp(10, 86_400);

        // Probe agent-chat-arc.
        let chat_arc_msgs = match fetch_topic_msgs_mcp(&hub_socket, "agent-chat-arc", 500).await {
            Ok(m) => m,
            Err(e) => return json_err(format!("agent-chat-arc probe failed: {e}")),
        };
        let now_ms = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_millis() as i64)
            .unwrap_or(0);
        let window_ms = (window_secs as i64).saturating_mul(1000);
        let presence = evaluate_presence_msgs(&chat_arc_msgs, &peer_fp, now_ms, window_ms);
        let last_seen_human = format_last_seen_human(now_ms, presence.last_seen_ms);

        serde_json::to_string_pretty(&serde_json::json!({
            "ok": true,
            "target_or_fp": display_target,
            "peer_fp": peer_fp,
            "online": presence.online,
            "last_seen_ms": presence.last_seen_ms,
            "last_seen": last_seen_human,
            "window_secs": window_secs,
            "posts_in_window": presence.posts_in_window,
        }))
        .unwrap_or_else(json_err)
    }

    #[tool(
        name = "termlink_agent_listen",
        description = "One-shot polling wrapper around `event.subscribe(topic=agent.request)` — MCP parity for the `termlink agent listen --json` CLI verb. Closes the agent.rs CLI surface gap (S-2026-0521 handover). Streaming-style loops don't fit MCP's request/response model; instead each call performs ONE subscribe iteration: pass optional `since` cursor + `timeout_ms`, get back `{ok, target, agent_topic, events, next_seq}` where `events` is a list of `{ok, seq, from, action, request_id, params, timeout_secs}` shapes matching CLI `--json` output. Iterate by passing the returned `next_seq` as the next `since`. Empty `events` array is normal (no requests in the timeout window). Target resolution: session ID or display name via `manager::find_session`."
    )]
    async fn termlink_agent_listen(
        &self,
        Parameters(p): Parameters<AgentListenParams>,
    ) -> String {
        let reg = match manager::find_session(&p.target) {
            Ok(r) => r,
            Err(e) => {
                return serde_json::to_string_pretty(&serde_json::json!({
                    "ok": false,
                    "target": p.target,
                    "error": format!("session '{}' not found: {e}", p.target),
                }))
                .unwrap_or_else(json_err);
            }
        };

        let timeout_ms = p.timeout_ms.unwrap_or(1_000).clamp(100, 30_000);
        let topic = termlink_protocol::events::agent_topic::REQUEST;

        let mut params = serde_json::json!({
            "topic": topic,
            "timeout_ms": timeout_ms,
        });
        if let Some(since) = p.since {
            params["since"] = serde_json::json!(since);
        }

        match client::rpc_call(reg.socket_path(), "event.subscribe", params).await {
            Ok(resp) => match client::unwrap_result(resp) {
                Ok(result) => {
                    let empty: Vec<serde_json::Value> = Vec::new();
                    let events_raw = result["events"].as_array().unwrap_or(&empty);
                    let shaped = shape_agent_request_events_mcp(events_raw);
                    let next_seq = result["next_seq"].as_u64();
                    serde_json::to_string_pretty(&serde_json::json!({
                        "ok": true,
                        "target": p.target,
                        "agent_topic": topic,
                        "events": shaped,
                        "next_seq": next_seq,
                    }))
                    .unwrap_or_else(json_err)
                }
                Err(e) => json_err(e),
            },
            Err(e) => json_err(format!("connection failed: {e}")),
        }
    }

    #[tool(
        name = "termlink_agent_dms",
        description = "List DM topics for the local identity — MCP parity for the `termlink agent dms` CLI verb (T-1552). Calls `channel.list`, filters to topics of shape `dm:<sorted_a>:<sorted_b>` where one side is the caller's identity_fingerprint. Returns `{ok, my_id, dms: [{topic, peer}, ...]}`. With `unread=true`, additionally computes per-DM unread + first_unread offset via `channel.receipts` (ack frontier) + `channel.subscribe` (paged walk for content envelopes); results sorted unread-first (stable). Operator-style answer to 'what conversations am I in?'. No new RPC surface — uses channel.list / channel.receipts / channel.subscribe only."
    )]
    async fn termlink_agent_dms(
        &self,
        Parameters(p): Parameters<AgentDmsParams>,
    ) -> String {
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }

        // Load identity → my_id (fingerprint).
        let home = match std::env::var("HOME") {
            Ok(h) => h,
            Err(_) => return json_err("HOME not set"),
        };
        let identity_dir = std::path::PathBuf::from(home).join(".termlink");
        let identity = match termlink_session::agent_identity::Identity::load_or_create(&identity_dir) {
            Ok(i) => i,
            Err(e) => return json_err(format!("identity load: {e}")),
        };
        let my_id = identity.fingerprint().to_string();

        // channel.list — full catalog (no prefix filter, mirrors CLI).
        let list_resp = match termlink_session::client::rpc_call(
            &hub_socket,
            termlink_protocol::control::method::CHANNEL_LIST,
            serde_json::json!({}),
        )
        .await
        {
            Ok(r) => r,
            Err(e) => return json_err(format!("channel.list RPC failed: {e}")),
        };
        let list_result = match termlink_session::client::unwrap_result(list_resp) {
            Ok(r) => r,
            Err(e) => return json_err(format!("channel.list error: {e}")),
        };
        let topic_names: Vec<String> = list_result["topics"]
            .as_array()
            .map(|arr| {
                arr.iter()
                    .filter_map(|t| t.get("name").and_then(|v| v.as_str()).map(String::from))
                    .collect()
            })
            .unwrap_or_default();
        let dms = dm_list_filter_mcp(&topic_names, &my_id);

        let want_unread = p.unread.unwrap_or(false);

        if !want_unread {
            let rows: Vec<serde_json::Value> = dms
                .iter()
                .map(|(t, peer)| serde_json::json!({"topic": t, "peer": peer}))
                .collect();
            return serde_json::to_string_pretty(&serde_json::json!({
                "ok": true,
                "my_id": my_id,
                "dms": rows,
            }))
            .unwrap_or_else(json_err);
        }

        // Unread mode — per-DM channel.receipts + walk_topic_full + count_unread.
        let mut rows: Vec<serde_json::Value> = Vec::with_capacity(dms.len());
        for (topic, peer) in &dms {
            // channel.receipts → caller's ack frontier `up_to`.
            let mut up_to: u64 = 0;
            let receipts_resp = termlink_session::client::rpc_call(
                &hub_socket,
                termlink_protocol::control::method::CHANNEL_RECEIPTS,
                serde_json::json!({"topic": topic}),
            )
            .await;
            if let Ok(resp) = receipts_resp
                && let Ok(r) = termlink_session::client::unwrap_result(resp)
                && let Some(entries) = r["receipts"].as_array()
            {
                for entry in entries {
                    if entry.get("sender_id").and_then(|v| v.as_str()) == Some(my_id.as_str()) {
                        up_to = entry.get("up_to").and_then(|v| v.as_u64()).unwrap_or(0);
                        break;
                    }
                }
            }
            // (Receipts failure → up_to stays 0 → all content counts as unread,
            // matching CLI's conservative fallback.)

            let envelopes = match walk_topic_full_mcp(&hub_socket, topic).await {
                Ok(v) => v,
                Err(e) => {
                    // One DM's walk failed — surface per-row error rather than
                    // aborting the whole tool call.
                    rows.push(serde_json::json!({
                        "topic": topic,
                        "peer": peer,
                        "unread": null,
                        "first_unread": null,
                        "error": e,
                    }));
                    continue;
                }
            };
            let (unread, first_unread) = count_unread_mcp(&envelopes, up_to);
            rows.push(serde_json::json!({
                "topic": topic,
                "peer": peer,
                "unread": unread,
                "first_unread": first_unread,
            }));
        }
        // Stable sort: unread > 0 floats to top, original order preserved within groups.
        rows.sort_by(|a, b| {
            let a_unread = a.get("unread").and_then(|v| v.as_u64()).unwrap_or(0);
            let b_unread = b.get("unread").and_then(|v| v.as_u64()).unwrap_or(0);
            let a_has = if a_unread > 0 { 0u8 } else { 1 };
            let b_has = if b_unread > 0 { 0u8 } else { 1 };
            a_has.cmp(&b_has)
        });

        serde_json::to_string_pretty(&serde_json::json!({
            "ok": true,
            "my_id": my_id,
            "dms": rows,
        }))
        .unwrap_or_else(json_err)
    }

    #[tool(
        name = "termlink_agent_inbox",
        description = "Cross-topic unread digest for the local identity — MCP parity for the `termlink agent inbox` CLI verb (T-1553). Walks the local cursor store (`${TERMLINK_IDENTITY_DIR:-${HOME}/.termlink}/cursors.json`, recorded by `subscribe --resume` on prior CLI sessions) and joins with hub-side topic counts from `channel.list`. Returns `{ok, my_id, unread_topics: [{topic, cursor, latest, unread}, ...]}` sorted by descending unread (ties break by topic ascending for determinism). The operator's first-command-of-session — answers 'what needs my attention?' across every subscribed topic, not just `agent-chat-arc` (T-1512 `agent_unread`) or DMs (T-1719 `agent_dms`). When the cursor store is empty (operator has never run `subscribe --resume`) returns `unread_topics: []` with `ok: true` — same conservative early-out as CLI. No new RPC surface — uses `channel.list` only."
    )]
    async fn termlink_agent_inbox(
        &self,
        Parameters(_p): Parameters<AgentInboxParams>,
    ) -> String {
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }

        // Load identity → my_id (fingerprint).
        let home = match std::env::var("HOME") {
            Ok(h) => h,
            Err(_) => return json_err("HOME not set"),
        };
        let identity_dir = std::path::PathBuf::from(home).join(".termlink");
        let identity = match termlink_session::agent_identity::Identity::load_or_create(&identity_dir) {
            Ok(i) => i,
            Err(e) => return json_err(format!("identity load: {e}")),
        };
        let my_id = identity.fingerprint().to_string();

        // Enumerate cursors for this identity. Empty → early-out.
        let cursors = match cursor_list_for_fingerprint_mcp(&my_id) {
            Ok(c) => c,
            Err(e) => return json_err(format!("cursor store: {e}")),
        };
        if cursors.is_empty() {
            return serde_json::to_string_pretty(&serde_json::json!({
                "ok": true,
                "my_id": my_id,
                "unread_topics": [],
            }))
            .unwrap_or_else(json_err);
        }

        // channel.list — full catalog, extract (name, count) into HashMap.
        let list_resp = match termlink_session::client::rpc_call(
            &hub_socket,
            termlink_protocol::control::method::CHANNEL_LIST,
            serde_json::json!({}),
        )
        .await
        {
            Ok(r) => r,
            Err(e) => return json_err(format!("channel.list RPC failed: {e}")),
        };
        let list_result = match termlink_session::client::unwrap_result(list_resp) {
            Ok(r) => r,
            Err(e) => return json_err(format!("channel.list error: {e}")),
        };
        let mut counts: std::collections::HashMap<String, u64> = std::collections::HashMap::new();
        if let Some(arr) = list_result["topics"].as_array() {
            for entry in arr {
                if let Some(name) = entry.get("name").and_then(|v| v.as_str()) {
                    let count = entry.get("count").and_then(|v| v.as_u64()).unwrap_or(0);
                    counts.insert(name.to_string(), count);
                }
            }
        }

        let rows = compute_unread_rows_mcp(&cursors, &counts);
        let rows_json: Vec<serde_json::Value> = rows
            .iter()
            .map(|r| serde_json::json!({
                "topic": r.topic,
                "cursor": r.cursor,
                "latest": r.latest,
                "unread": r.unread,
            }))
            .collect();

        serde_json::to_string_pretty(&serde_json::json!({
            "ok": true,
            "my_id": my_id,
            "unread_topics": rows_json,
        }))
        .unwrap_or_else(json_err)
    }

