    #[tool(
        name = "termlink_agent_timeline",
        description = "Fleet-wide chronological log of recent posts on `agent-chat-arc` — MCP parity for the `termlink agent timeline` CLI verb (T-1500). Returns up to `n` (default 50, clamped 1..=500) content envelopes from within the last `window_secs` (default 3600, clamped 60..=604800) sorted chronologically ascending (oldest first; natural reading flow). Meta types (reaction/edit/redaction/topic_metadata/receipt) are always excluded. Optional filters AND-compose: `filter_thread` (matches `metadata.thread` or `metadata._thread`), `filter_project` (matches `metadata.from_project`), `filter_msg_types` (allowlist applied after meta exclusion), `filter_grep` (case-insensitive substring against rendered content). Content is truncated at 200 chars with `…` suffix. Use this when you want a 'tail -f for the fleet' view — companion to `termlink_agent_recent_window` (single-peer) and `termlink_agent_on_thread` (single-thread). Returns `{ok, verb, window_secs, n, filter_*, posts: [{offset, ts_ms, peer_fp, msg_type, content, thread, project}, ...]}`. NO new RPC surface — uses `channel.list` + `channel.subscribe` only."
    )]
    async fn termlink_agent_timeline(
        &self,
        Parameters(p): Parameters<AgentTimelineParams>,
    ) -> String {
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }
        let clamped_n = p.n.unwrap_or(50).clamp(1, 500);
        let clamped_window_secs = p.window_secs.unwrap_or(3_600).clamp(60, 604_800);
        let msgs = match fetch_topic_msgs_mcp(&hub_socket, "agent-chat-arc", 1000).await {
            Ok(m) => m,
            Err(e) => return json_err(format!("fetch agent-chat-arc: {e}")),
        };
        let now_ms = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_millis() as i64)
            .unwrap_or(0);
        let window_ms = (clamped_window_secs as i64).saturating_mul(1000);
        // Borrow Vec<String> as &[&str] for the helper.
        let msg_type_owned: Option<Vec<String>> = p
            .filter_msg_types
            .as_ref()
            .filter(|v| !v.is_empty())
            .cloned();
        let msg_type_refs: Option<Vec<&str>> = msg_type_owned
            .as_ref()
            .map(|v| v.iter().map(String::as_str).collect());
        let posts = extract_recent_posts_mcp(
            &msgs,
            clamped_n,
            window_ms,
            now_ms,
            None,
            p.filter_thread.as_deref(),
            p.filter_project.as_deref(),
            msg_type_refs.as_deref(),
            p.filter_grep.as_deref(),
        );
        let posts_json: Vec<serde_json::Value> =
            posts.iter().map(RecentPostMcp::to_json_mcp).collect();
        let mut out = serde_json::Map::new();
        out.insert("ok".to_string(), serde_json::Value::Bool(true));
        out.insert(
            "verb".to_string(),
            serde_json::Value::String("agent.timeline".to_string()),
        );
        out.insert(
            "window_secs".to_string(),
            serde_json::Value::from(clamped_window_secs),
        );
        out.insert("n".to_string(), serde_json::Value::from(clamped_n));
        if let Some(t) = p.filter_thread.as_deref() {
            out.insert(
                "filter_thread".to_string(),
                serde_json::Value::String(t.to_string()),
            );
        }
        if let Some(pr) = p.filter_project.as_deref() {
            out.insert(
                "filter_project".to_string(),
                serde_json::Value::String(pr.to_string()),
            );
        }
        if let Some(types) = msg_type_owned.as_ref() {
            out.insert(
                "filter_msg_types".to_string(),
                serde_json::Value::Array(
                    types
                        .iter()
                        .map(|t| serde_json::Value::String(t.clone()))
                        .collect(),
                ),
            );
        }
        if let Some(g) = p.filter_grep.as_deref() {
            if !g.is_empty() {
                out.insert(
                    "filter_grep".to_string(),
                    serde_json::Value::String(g.to_string()),
                );
            }
        }
        out.insert("posts".to_string(), serde_json::Value::Array(posts_json));
        serde_json::to_string_pretty(&serde_json::Value::Object(out)).unwrap_or_else(json_err)
    }

    #[tool(
        name = "termlink_agent_stats",
        description = "Chat-arc activity stats over a time window — MCP parity for the `termlink agent stats` CLI verb (T-1504). Returns counts grouped four ways: by_msg_type (post/chat/note/...), by_peer (sender_id), by_project (metadata.from_project), by_thread (metadata.thread, accepts legacy _thread). Each bucket sorted desc by count + asc by key (stable tie-break) and truncated to `top`. Excludes META msg_types (reaction/edit/redaction/topic_metadata/receipt) and envelopes lacking sender_id; window cutoff drops `ts < now - window_secs` and future-clock `ts > now_ms`. Use this for 'who's talking, about what, where' digests — feeds dashboards or quick health checks. Returns `{ok, verb, window_secs, top, total, by_msg_type, by_peer, by_project, by_thread}` where each bucket is `[{key, count}, ...]`. NO new RPC surface — uses `channel.list` + `channel.subscribe` only."
    )]
    async fn termlink_agent_stats(
        &self,
        Parameters(p): Parameters<AgentStatsParams>,
    ) -> String {
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }
        let clamped_window_secs = p.window_secs.unwrap_or(86_400).clamp(60, 604_800);
        let clamped_top = p.top.unwrap_or(10).clamp(1, 100);
        let msgs = match fetch_topic_msgs_mcp(&hub_socket, "agent-chat-arc", 1000).await {
            Ok(m) => m,
            Err(e) => return json_err(format!("fetch agent-chat-arc: {e}")),
        };
        let now_ms = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_millis() as i64)
            .unwrap_or(0);
        let window_ms = (clamped_window_secs as i64).saturating_mul(1000);
        let stats = summarize_chat_arc_stats_mcp(&msgs, now_ms, window_ms);
        let mk_pairs = |v: &[(String, usize)]| -> serde_json::Value {
            let truncated: Vec<&(String, usize)> = v.iter().take(clamped_top).collect();
            serde_json::Value::Array(
                truncated
                    .iter()
                    .map(|(k, c)| serde_json::json!({"key": k, "count": c}))
                    .collect(),
            )
        };
        serde_json::to_string_pretty(&serde_json::json!({
            "ok": true,
            "verb": "agent.stats",
            "window_secs": clamped_window_secs,
            "top": clamped_top,
            "total": stats.total,
            "by_msg_type": mk_pairs(&stats.by_msg_type),
            "by_peer": mk_pairs(&stats.by_peer),
            "by_project": mk_pairs(&stats.by_project),
            "by_thread": mk_pairs(&stats.by_thread),
        }))
        .unwrap_or_else(json_err)
    }

    #[tool(
        name = "termlink_agent_overview",
        description = "Composite fleet digest on `agent-chat-arc` — MCP parity for the `termlink agent overview` CLI verb (T-1495). One round-trip; three sections in one envelope: (1) `peers` — fleet presence sorted by in-window posts desc, with `top_project` per peer; (2) `projects` — by-project aggregation with `top_peer_fp` and `distinct_peers`; (3) `recent_posts` — last N content posts chronologically. Use this as a single-shot 'first look' at the fleet: who's active, what they're working on, what was just said. Defaults: window=3600s (1h, clamped 60..=604800), top=5 (clamped 1..=50). META msg_types (reaction/edit/redaction/topic_metadata/receipt) excluded throughout. Untagged posts excluded from `projects` (project IS the key) but counted in `peers` and `recent_posts`. Returns `{ok, verb, window_secs, top, peers, projects, recent_posts, total_peers, total_projects}`. NO new RPC surface — uses `channel.list` + `channel.subscribe` only, with a wider 2000-envelope slice for fleet coverage."
    )]
    async fn termlink_agent_overview(
        &self,
        Parameters(p): Parameters<AgentOverviewParams>,
    ) -> String {
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }
        let clamped_window_secs = p.window_secs.unwrap_or(3_600).clamp(60, 604_800);
        let clamped_top = p.top.unwrap_or(5).clamp(1, 50);
        // Wider slice (2000) than stats/timeline — overview wants enough
        // fleet coverage for both presence and recent posts.
        let msgs = match fetch_topic_msgs_mcp(&hub_socket, "agent-chat-arc", 2000).await {
            Ok(m) => m,
            Err(e) => return json_err(format!("fetch agent-chat-arc: {e}")),
        };
        let now_ms = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_millis() as i64)
            .unwrap_or(0);
        let window_ms = (clamped_window_secs as i64).saturating_mul(1000);
        let peer_rows = summarize_fleet_presence_mcp(&msgs, now_ms, window_ms, None, None);
        let project_rows = summarize_fleet_by_project_mcp(&msgs, now_ms, window_ms, None, None);
        let recent = extract_recent_posts_mcp(
            &msgs,
            clamped_top,
            window_ms,
            now_ms,
            None,
            None,
            None,
            None,
            None,
        );
        let total_peers = peer_rows.len();
        let total_projects = project_rows.len();
        let display_peers = &peer_rows[..peer_rows.len().min(clamped_top)];
        let display_projects = &project_rows[..project_rows.len().min(clamped_top)];
        serde_json::to_string_pretty(&serde_json::json!({
            "ok": true,
            "verb": "agent.overview",
            "window_secs": clamped_window_secs,
            "top": clamped_top,
            "peers": display_peers.iter().map(FleetPeerRowMcp::to_json_mcp).collect::<Vec<_>>(),
            "projects": display_projects.iter().map(FleetProjectRowMcp::to_json_mcp).collect::<Vec<_>>(),
            "recent_posts": recent.iter().map(RecentPostMcp::to_json_mcp).collect::<Vec<_>>(),
            "total_peers": total_peers,
            "total_projects": total_projects,
        }))
        .unwrap_or_else(json_err)
    }

    #[tool(
        name = "termlink_agent_mentions",
        description = "Find every envelope on `agent-chat-arc` whose `metadata.mentions` CSV matches the named user — MCP parity for the `termlink agent mentions <USER>` CLI verb (T-1513). Distinct from `termlink_agent_search` (substring grep across payload): this verb filters on the structured `metadata.mentions` array — finds rows that *explicitly* tagged the user, regardless of body content. Pass `\"*\"` as user to match any non-empty mentions CSV (the 'anyone tagged at all?' query). Returns `{ok, topic: \"agent-chat-arc\", user, mentions: [{mention_offset, sender_id, payload, mentions_csv, ts_ms}, ...]}` sorted by descending offset (newest first). Skips redacted envelopes and meta msg-types (reaction/edit/redaction/topic_metadata/receipt). NO new RPC surface — walks the topic via `channel.subscribe` only."
    )]
    async fn termlink_agent_mentions(
        &self,
        Parameters(p): Parameters<AgentMentionsParams>,
    ) -> String {
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }
        let user = p.user.trim();
        if user.is_empty() {
            return json_err("user is required and must be non-empty (use \"*\" to match any tag)");
        }

        let topic = "agent-chat-arc";
        let envelopes = match walk_topic_full_mcp(&hub_socket, topic).await {
            Ok(v) => v,
            Err(e) => return json_err(format!("walk_topic_full({topic}): {e}")),
        };
        let rows = compute_mentions_of_mcp(&envelopes, user);
        let rows_json: Vec<serde_json::Value> = rows
            .iter()
            .map(|r| serde_json::json!({
                "mention_offset": r.mention_offset,
                "sender_id": r.sender_id,
                "payload": r.payload,
                "mentions_csv": r.mentions_csv,
                "ts_ms": r.ts_ms,
            }))
            .collect();

        serde_json::to_string_pretty(&serde_json::json!({
            "ok": true,
            "topic": topic,
            "user": user,
            "mentions": rows_json,
        }))
        .unwrap_or_else(json_err)
    }

    #[tool(
        name = "termlink_agent_identity",
        description = "Local-identity self-introspection — MCP parity for the `termlink agent identity` CLI verb (T-1554). Reads `${HOME}/.termlink/identity.json` (loaded or created via `Identity::load_or_create`) and returns `{ok, fingerprint, public_key_hex, path}`. Operator answer to 'what FP do I sign as?' without the side effect of posting an envelope and reading back `my_fp` from the echo. No I/O beyond the local identity file read — never hits the hub, never posts. Parameter-less."
    )]
    async fn termlink_agent_identity(&self) -> String {
        let home = match std::env::var("HOME") {
            Ok(h) => h,
            Err(_) => return json_err("HOME not set"),
        };
        let identity_dir = std::path::PathBuf::from(home).join(".termlink");
        let identity = match termlink_session::agent_identity::Identity::load_or_create(&identity_dir) {
            Ok(i) => i,
            Err(e) => return json_err(format!("identity load: {e}")),
        };
        let path = identity_dir.join("identity.json");
        serde_json::to_string_pretty(&serde_json::json!({
            "ok": true,
            "fingerprint": identity.fingerprint().to_string(),
            "public_key_hex": identity.public_key_hex(),
            "path": path.display().to_string(),
        }))
        .unwrap_or_else(json_err)
    }

    #[tool(
        name = "termlink_agent_typing",
        description = "Emit a typing indicator on agent-chat-arc — signals 'I'm composing' to peers reading `agent typers` (T-1551) or `agent typers --watch` (T-1557). Posts a `msg_type=typing` envelope with `metadata.expires_at_ms = now + ttl_ms` (default ttl: 5000ms). Companion to `termlink_agent_post` (typed text). MCP-side equivalent of the `agent typing` CLI verb (T-1550)."
    )]
    async fn termlink_agent_typing(
        &self,
        Parameters(p): Parameters<AgentTypingParams>,
    ) -> String {
        use base64::Engine;
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }
        let topic = "agent-chat-arc";
        let msg_type = "typing";
        let ttl_ms = p.ttl_ms.unwrap_or(5000);
        let payload_bytes: Vec<u8> = Vec::new();
        let home = match std::env::var("HOME") {
            Ok(h) => h,
            Err(_) => return json_err("HOME not set"),
        };
        let identity_dir = std::path::PathBuf::from(home).join(".termlink");
        let identity = match termlink_session::agent_identity::Identity::load_or_create(&identity_dir) {
            Ok(i) => i,
            Err(e) => return json_err(format!("identity load: {e}")),
        };
        let ts_unix_ms = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_millis() as i64)
            .unwrap_or(0);
        let expires_at_ms = ts_unix_ms + (ttl_ms as i64);
        let signed = termlink_protocol::control::channel::canonical_sign_bytes(
            topic,
            msg_type,
            &payload_bytes,
            None,
            ts_unix_ms,
        );
        let sig = identity.sign(&signed);
        let mut sig_hex = String::with_capacity(128);
        for b in sig.to_bytes() {
            use std::fmt::Write;
            let _ = write!(&mut sig_hex, "{b:02x}");
        }
        let sender_id = p.sender_id.unwrap_or_else(|| identity.fingerprint().to_string());
        let mut metadata = serde_json::Map::new();
        metadata.insert("expires_at_ms".to_string(), serde_json::Value::from(expires_at_ms));
        let params = serde_json::json!({
            "topic": topic,
            "msg_type": msg_type,
            "payload_b64": base64::engine::general_purpose::STANDARD.encode(&payload_bytes),
            "ts": ts_unix_ms,
            "sender_id": sender_id,
            "sender_pubkey_hex": identity.public_key_hex(),
            "signature_hex": sig_hex,
            "metadata": serde_json::Value::Object(metadata),
        });
        match termlink_session::client::rpc_call(
            &hub_socket,
            termlink_protocol::control::method::CHANNEL_POST,
            params,
        )
        .await
        {
            Ok(resp) => match termlink_session::client::unwrap_result(resp) {
                Ok(result) => serde_json::to_string_pretty(&result).unwrap_or_else(json_err),
                Err(e) => json_err(format!("agent.typing error: {e}")),
            },
            Err(e) => json_err(format!("RPC call failed: {e}")),
        }
    }

