    #[tool(
        name = "termlink_channel_quote",
        description = "Fetch an envelope by offset on an arbitrary topic AND resolve its parent (via `metadata.in_reply_to`) — MCP parity for `termlink channel quote <topic> <offset>` CLI verb (T-1785 of T-1166). Topic-flexible read helper. Note: diverges from `termlink_agent_quote` (tools.rs:23242) which returns only the single envelope — channel_quote mirrors the CLI's quote-with-parent semantics (more useful for rendering quote-in-context views). Returns JSON `{topic, child, parent}` where child has `{offset, sender_id, msg_type, ts, payload}` and parent is the same shape or null. Walks the topic via `channel.subscribe` paginated by 1000 — read-side, no auth, no emit. Pairs with `termlink_channel_reply` (T-1784) for full thread-mutation surface."
    )]
    async fn termlink_channel_quote(
        &self,
        Parameters(p): Parameters<ChannelQuoteParams>,
    ) -> String {
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }
        let envelopes = match walk_topic_full_mcp(&hub_socket, &p.topic).await {
            Ok(envs) => envs,
            Err(e) => return json_err(format!("walk_topic_full failed: {e}")),
        };
        use std::collections::HashMap;
        let mut by_off: HashMap<u64, serde_json::Value> = HashMap::with_capacity(envelopes.len());
        for env in envelopes {
            if let Some(off) = env.get("offset").and_then(|v| v.as_u64()) {
                by_off.insert(off, env);
            }
        }
        let child = match by_off.get(&p.offset) {
            Some(c) => c.clone(),
            None => {
                return json_err(format!(
                    "Topic '{}' has no envelope at offset {}",
                    p.topic, p.offset
                ));
            }
        };
        let parent = parent_offset_of_mcp(&child).and_then(|po| by_off.get(&po).cloned());

        let render = |m: &serde_json::Value| -> serde_json::Value {
            let off = m.get("offset").and_then(|v| v.as_u64()).unwrap_or(0);
            let sender = m.get("sender_id").and_then(|v| v.as_str()).unwrap_or("?");
            let msg_type = m.get("msg_type").and_then(|v| v.as_str()).unwrap_or("?");
            let ts = m
                .get("ts_unix_ms")
                .and_then(|v| v.as_i64())
                .or_else(|| m.get("ts").and_then(|v| v.as_i64()));
            serde_json::json!({
                "offset": off,
                "sender_id": sender,
                "msg_type": msg_type,
                "ts": ts,
                "payload": decode_payload_lossy_mcp(m),
            })
        };
        let parent_json = parent
            .as_ref()
            .map(render)
            .unwrap_or(serde_json::Value::Null);
        let body = serde_json::json!({
            "topic": p.topic,
            "child": render(&child),
            "parent": parent_json,
        });
        serde_json::to_string_pretty(&body).unwrap_or_else(json_err)
    }

    #[tool(
        name = "termlink_channel_forward",
        description = "Re-post an envelope from one topic to another — MCP parity for `termlink channel forward <src> <offset> <dst>` CLI verb (T-1786 of T-1166). NEW MCP verb (no `termlink_agent_forward` sister — forward inherently requires a destination topic, so it's topic-flex by nature). Walks `src_topic` via channel.subscribe, finds the envelope at `offset`, then posts a new envelope on `dst_topic` with the same msg_type and payload, signed by the forwarder's identity (NOT a faithful relay — the forwarder becomes the sender on record). Metadata records `forwarded_from=<src_topic>:<offset>` and `forwarded_sender=<original_sender_id>` for trace-back. Especially relevant post-G-060 (agent-chat-arc federation gap) — operators can forward chat-arc posts to project/DM topics that DO federate."
    )]
    async fn termlink_channel_forward(
        &self,
        Parameters(p): Parameters<ChannelForwardParams>,
    ) -> String {
        use base64::Engine;
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }
        let envelopes = match walk_topic_full_mcp(&hub_socket, &p.src_topic).await {
            Ok(envs) => envs,
            Err(e) => return json_err(format!("walk_topic_full failed on src: {e}")),
        };
        let src_env = match envelopes
            .iter()
            .find(|e| e.get("offset").and_then(|v| v.as_u64()) == Some(p.offset))
        {
            Some(e) => e,
            None => {
                return json_err(format!(
                    "Source topic '{}' has no envelope at offset {}",
                    p.src_topic, p.offset
                ));
            }
        };
        let original_sender = src_env
            .get("sender_id")
            .and_then(|v| v.as_str())
            .unwrap_or("?")
            .to_string();
        let original_msg_type = src_env
            .get("msg_type")
            .and_then(|v| v.as_str())
            .unwrap_or("post")
            .to_string();
        let src_payload_b64 = src_env
            .get("payload_b64")
            .and_then(|v| v.as_str())
            .unwrap_or("");
        let payload_bytes = base64::engine::general_purpose::STANDARD
            .decode(src_payload_b64)
            .unwrap_or_default();
        let home = match std::env::var("HOME") {
            Ok(h) => h,
            Err(_) => return json_err("HOME not set"),
        };
        let identity_dir = std::path::PathBuf::from(home).join(".termlink");
        let identity = match termlink_session::agent_identity::Identity::load_or_create(&identity_dir) {
            Ok(i) => i,
            Err(e) => return json_err(format!("identity load: {e}")),
        };
        let ts_unix_ms = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_millis() as i64)
            .unwrap_or(0);
        let signed = termlink_protocol::control::channel::canonical_sign_bytes(
            &p.dst_topic,
            &original_msg_type,
            &payload_bytes,
            None,
            ts_unix_ms,
        );
        let sig = identity.sign(&signed);
        let mut sig_hex = String::with_capacity(128);
        for b in sig.to_bytes() {
            use std::fmt::Write;
            let _ = write!(&mut sig_hex, "{b:02x}");
        }
        let sender_id = p.sender_id.unwrap_or_else(|| identity.fingerprint().to_string());
        let mut metadata = serde_json::Map::new();
        metadata.insert(
            "forwarded_from".to_string(),
            serde_json::Value::String(format!("{}:{}", p.src_topic, p.offset)),
        );
        metadata.insert(
            "forwarded_sender".to_string(),
            serde_json::Value::String(original_sender),
        );
        let params = serde_json::json!({
            "topic": p.dst_topic,
            "msg_type": original_msg_type,
            "payload_b64": base64::engine::general_purpose::STANDARD.encode(&payload_bytes),
            "ts": ts_unix_ms,
            "sender_id": sender_id,
            "sender_pubkey_hex": identity.public_key_hex(),
            "signature_hex": sig_hex,
            "metadata": serde_json::Value::Object(metadata),
        });
        match termlink_session::client::rpc_call(
            &hub_socket,
            termlink_protocol::control::method::CHANNEL_POST,
            params,
        )
        .await
        {
            Ok(resp) => match termlink_session::client::unwrap_result(resp) {
                Ok(result) => serde_json::to_string_pretty(&result).unwrap_or_else(json_err),
                Err(e) => json_err(format!("channel.forward error: {e}")),
            },
            Err(e) => json_err(format!("RPC call failed: {e}")),
        }
    }

    #[tool(
        name = "termlink_channel_receipts",
        description = "Aggregate read-receipt frontiers (latest `up_to` per sender) on an arbitrary topic — MCP parity for `termlink channel receipts <topic>` CLI verb (T-1787 of T-1166). Natural read-side pair to `termlink_channel_ack` (T-1783, write-side). Prefers hub's `channel.receipts` RPC fast-path (T-1329 server-side aggregator); falls back to walker (channel.subscribe paginated + filter msg_type=receipt + latest-wins-by-ts dedup) when hub returns -32601 method-not-found. Returns `{receipts: [{sender_id, up_to, ts_unix_ms}, ...]}` sorted by sender_id. Topic-flex by construction — works on agent-chat-arc, DM channels, project topics."
    )]
    async fn termlink_channel_receipts(
        &self,
        Parameters(p): Parameters<ChannelReceiptsParams>,
    ) -> String {
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }
        use std::collections::HashMap;
        struct Receipt {
            up_to: u64,
            ts: i64,
        }
        let mut latest: HashMap<String, Receipt> = HashMap::new();
        let mut fall_back_to_walker = false;

        // Fast-path: hub's channel.receipts RPC.
        let server_resp = termlink_session::client::rpc_call(
            &hub_socket,
            termlink_protocol::control::method::CHANNEL_RECEIPTS,
            serde_json::json!({"topic": p.topic}),
        )
        .await;
        match server_resp {
            Ok(termlink_protocol::jsonrpc::RpcResponse::Success(r)) => {
                if let Some(arr) = r.result["receipts"].as_array() {
                    for entry in arr {
                        let sender = match entry.get("sender_id").and_then(|v| v.as_str()) {
                            Some(s) => s.to_string(),
                            None => continue,
                        };
                        let up_to = entry.get("up_to").and_then(|v| v.as_u64()).unwrap_or(0);
                        let ts = entry.get("ts_unix_ms").and_then(|v| v.as_i64()).unwrap_or(0);
                        latest.insert(sender, Receipt { up_to, ts });
                    }
                }
            }
            Ok(termlink_protocol::jsonrpc::RpcResponse::Error(e)) if e.error.code == -32601 => {
                fall_back_to_walker = true;
            }
            Ok(termlink_protocol::jsonrpc::RpcResponse::Error(e)) => {
                return json_err(format!(
                    "Hub returned error for channel.receipts: JSON-RPC error {}: {}",
                    e.error.code, e.error.message
                ));
            }
            Err(e) => return json_err(format!("RPC call failed: {e}")),
        }

        // Walker fallback for old hubs.
        if fall_back_to_walker {
            let envelopes = match walk_topic_full_mcp(&hub_socket, &p.topic).await {
                Ok(envs) => envs,
                Err(e) => return json_err(format!("walk_topic_full failed: {e}")),
            };
            for m in &envelopes {
                if m.get("msg_type").and_then(|v| v.as_str()) != Some("receipt") {
                    continue;
                }
                let sender = match m.get("sender_id").and_then(|v| v.as_str()) {
                    Some(s) => s.to_string(),
                    None => continue,
                };
                let up_to = m
                    .get("metadata")
                    .and_then(|md| md.get("up_to"))
                    .and_then(|v| v.as_str())
                    .and_then(|s| s.parse::<u64>().ok());
                let Some(up_to) = up_to else { continue };
                let ts = m.get("ts").and_then(|v| v.as_i64()).unwrap_or(0);
                match latest.get(&sender) {
                    Some(prev) if prev.ts > ts => {}
                    Some(prev) if prev.ts == ts && prev.up_to >= up_to => {}
                    _ => {
                        latest.insert(sender, Receipt { up_to, ts });
                    }
                }
            }
        }

        let mut entries: Vec<(String, &Receipt)> =
            latest.iter().map(|(k, v)| (k.clone(), v)).collect();
        entries.sort_by(|a, b| a.0.cmp(&b.0));
        let arr: Vec<serde_json::Value> = entries
            .iter()
            .map(|(s, r)| {
                serde_json::json!({
                    "sender_id": s,
                    "up_to": r.up_to,
                    "ts_unix_ms": r.ts,
                })
            })
            .collect();
        serde_json::to_string_pretty(&serde_json::json!({"receipts": arr})).unwrap_or_else(json_err)
    }

    #[tool(
        name = "termlink_channel_poll_start",
        description = "Start a poll on an arbitrary topic — MCP parity for `termlink channel poll start <topic> <question> -- <opt1> <opt2> ...` CLI verb (T-1788 of T-1166). Topic-flexible variant of `termlink_agent_poll_start` (hardcoded chat-arc, T-1570). Posts a `msg_type=poll_start` envelope with payload=question and `metadata.poll_options=a|b|c` (pipe-delimited). Requires ≥2 options; rejects labels containing `|`. The envelope's offset becomes the `poll_id` used by subsequent vote/end envelopes."
    )]
    async fn termlink_channel_poll_start(
        &self,
        Parameters(p): Parameters<ChannelPollStartParams>,
    ) -> String {
        use base64::Engine;
        if p.options.len() < 2 {
            return json_err(format!(
                "poll requires at least 2 options (got {})",
                p.options.len()
            ));
        }
        if p.options.iter().any(|o| o.contains('|')) {
            return json_err(
                "option labels cannot contain '|' (used as the metadata delimiter)",
            );
        }
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }
        let msg_type = "poll_start";
        let payload_bytes = p.question.into_bytes();
        let home = match std::env::var("HOME") {
            Ok(h) => h,
            Err(_) => return json_err("HOME not set"),
        };
        let identity_dir = std::path::PathBuf::from(home).join(".termlink");
        let identity = match termlink_session::agent_identity::Identity::load_or_create(&identity_dir) {
            Ok(i) => i,
            Err(e) => return json_err(format!("identity load: {e}")),
        };
        let ts_unix_ms = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_millis() as i64)
            .unwrap_or(0);
        let signed = termlink_protocol::control::channel::canonical_sign_bytes(
            &p.topic,
            msg_type,
            &payload_bytes,
            None,
            ts_unix_ms,
        );
        let sig = identity.sign(&signed);
        let mut sig_hex = String::with_capacity(128);
        for b in sig.to_bytes() {
            use std::fmt::Write;
            let _ = write!(&mut sig_hex, "{b:02x}");
        }
        let sender_id = p.sender_id.unwrap_or_else(|| identity.fingerprint().to_string());
        let mut metadata = serde_json::Map::new();
        metadata.insert(
            "poll_options".to_string(),
            serde_json::Value::String(p.options.join("|")),
        );
        let params = serde_json::json!({
            "topic": p.topic,
            "msg_type": msg_type,
            "payload_b64": base64::engine::general_purpose::STANDARD.encode(&payload_bytes),
            "ts": ts_unix_ms,
            "sender_id": sender_id,
            "sender_pubkey_hex": identity.public_key_hex(),
            "signature_hex": sig_hex,
            "metadata": serde_json::Value::Object(metadata),
        });
        match termlink_session::client::rpc_call(
            &hub_socket,
            termlink_protocol::control::method::CHANNEL_POST,
            params,
        )
        .await
        {
            Ok(resp) => match termlink_session::client::unwrap_result(resp) {
                Ok(result) => serde_json::to_string_pretty(&result).unwrap_or_else(json_err),
                Err(e) => json_err(format!("channel.poll_start error: {e}")),
            },
            Err(e) => json_err(format!("RPC call failed: {e}")),
        }
    }

