    #[tool(
        name = "termlink_channel_claims_summary_all",
        description = "Fleet-wide claim-state sweep — MCP parity for `termlink channel claims-summary --all` CLI verb (T-2042, arc-parallel-substrate Slice 9; T-2043 is the MCP wrapping = Slice 10). The cold-start investigator verb: when you don't yet know which topic has the stuck worker, this returns one row per topic on the hub with the same Slice 6 aggregate shape PLUS a `potentially_stuck: bool` annotation. Heuristic: `expired_count > 0` OR `oldest_active_age_ms > 60_000` (60s, conservative — picked above the runbook's 30s default TTL so a healthy near-TTL worker doesn't trip the flag). Returns `{ok, topic_count, stuck_count, topics: [{ok, topic, active_count, expired_count, oldest_active_at_ms?, oldest_active_age_ms?, next_active_expiry_ms?, potentially_stuck}, ...]}`. Per-topic fetch errors during the sweep are non-fatal — captured as `{ok: false, topic, error}` entries, sweep continues. Use this first to identify which topic is misbehaving, then drill in with `termlink_channel_claims` for the per-claim breakdown. No state mutation; safe for cron + investigator agents."
    )]
    async fn termlink_channel_claims_summary_all(
        &self,
        Parameters(_p): Parameters<ChannelClaimsSummaryAllParams>,
    ) -> String {
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }

        // Step 1: enumerate every topic via channel.list.
        let list_resp = match termlink_session::client::rpc_call(
            &hub_socket,
            termlink_protocol::control::method::CHANNEL_LIST,
            serde_json::json!({}),
        )
        .await
        {
            Ok(r) => r,
            Err(e) => return json_err(format!("channel.list RPC failed: {e}")),
        };
        let list_result = match termlink_session::client::unwrap_result(list_resp) {
            Ok(r) => r,
            Err(e) => return json_err(format!("channel.list error: {e}")),
        };
        let topic_names: Vec<String> = list_result["topics"]
            .as_array()
            .cloned()
            .unwrap_or_default()
            .iter()
            .filter_map(|t| t["name"].as_str().map(|s| s.to_string()))
            .collect();

        // Step 2: per-topic claims_summary. Per-topic errors do NOT
        // abort the sweep — they become {ok: false, topic, error}
        // entries in the array, matching the Slice 9 CLI --json shape.
        let mut entries: Vec<serde_json::Value> = Vec::with_capacity(topic_names.len());
        let mut stuck_count: u64 = 0;
        for t in &topic_names {
            let params = serde_json::json!({ "topic": t });
            let summary_resp = termlink_session::client::rpc_call(
                &hub_socket,
                termlink_protocol::control::method::CHANNEL_CLAIMS_SUMMARY,
                params,
            )
            .await;
            match summary_resp {
                Ok(resp) => match termlink_session::client::unwrap_result(resp) {
                    Ok(result) => {
                        // T-2043: apply Slice 9's stuck heuristic to keep
                        // CLI/MCP semantics aligned for agents pivoting
                        // between the two surfaces.
                        let expired = result["expired_count"].as_u64().unwrap_or(0);
                        let age = result["oldest_active_age_ms"].as_i64();
                        let stuck = expired > 0 || age.map(|a| a > 60_000).unwrap_or(false);
                        if stuck {
                            stuck_count += 1;
                        }
                        let mut entry = result.clone();
                        if let Some(obj) = entry.as_object_mut() {
                            obj.insert("ok".to_string(), serde_json::json!(true));
                            obj.insert(
                                "potentially_stuck".to_string(),
                                serde_json::json!(stuck),
                            );
                        }
                        entries.push(entry);
                    }
                    Err(e) => {
                        entries.push(serde_json::json!({
                            "ok": false,
                            "topic": t,
                            "error": format!("channel.claims_summary error: {e}"),
                        }));
                    }
                },
                Err(e) => {
                    entries.push(serde_json::json!({
                        "ok": false,
                        "topic": t,
                        "error": format!("RPC call failed: {e}"),
                    }));
                }
            }
        }

        let envelope = serde_json::json!({
            "ok": true,
            "topic_count": topic_names.len(),
            "stuck_count": stuck_count,
            "topics": entries,
        });
        serde_json::to_string_pretty(&envelope).unwrap_or_else(json_err)
    }

    #[tool(
        name = "termlink_channel_react",
        description = "Emit a reaction envelope on an arbitrary topic, tied to a parent post offset — MCP parity for `termlink channel react <topic> <offset> <emoji>` (add path) CLI verb (T-1778 of T-1166). Topic-flexible variant of `termlink_agent_react` (hardcoded chat-arc). Use case: react to a post in a DM channel (`dm:a:b`) or project topic. Posts a `msg_type=reaction` envelope with payload=emoji (UTF-8 bytes) and `metadata.in_reply_to=<offset>`. **Add-only scope** (matches `agent_react`); reaction removal (walk topic → find matching reaction → emit redaction) is a separate follow-up. Returns the raw `channel.post` result envelope on success."
    )]
    async fn termlink_channel_react(
        &self,
        Parameters(p): Parameters<ChannelReactParams>,
    ) -> String {
        use base64::Engine;
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }
        let msg_type = "reaction";
        let payload_bytes = p.emoji.into_bytes();
        let home = match std::env::var("HOME") {
            Ok(h) => h,
            Err(_) => return json_err("HOME not set"),
        };
        let identity_dir = std::path::PathBuf::from(home).join(".termlink");
        let identity = match termlink_session::agent_identity::Identity::load_or_create(&identity_dir) {
            Ok(i) => i,
            Err(e) => return json_err(format!("identity load: {e}")),
        };
        let ts_unix_ms = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_millis() as i64)
            .unwrap_or(0);
        let signed = termlink_protocol::control::channel::canonical_sign_bytes(
            &p.topic,
            msg_type,
            &payload_bytes,
            None,
            ts_unix_ms,
        );
        let sig = identity.sign(&signed);
        let mut sig_hex = String::with_capacity(128);
        for b in sig.to_bytes() {
            use std::fmt::Write;
            let _ = write!(&mut sig_hex, "{b:02x}");
        }
        let sender_id = p.sender_id.unwrap_or_else(|| identity.fingerprint().to_string());
        let mut metadata = serde_json::Map::new();
        metadata.insert("in_reply_to".to_string(), serde_json::Value::String(p.offset.to_string()));
        let params = serde_json::json!({
            "topic": p.topic,
            "msg_type": msg_type,
            "payload_b64": base64::engine::general_purpose::STANDARD.encode(&payload_bytes),
            "ts": ts_unix_ms,
            "sender_id": sender_id,
            "sender_pubkey_hex": identity.public_key_hex(),
            "signature_hex": sig_hex,
            "metadata": serde_json::Value::Object(metadata),
        });
        match termlink_session::client::rpc_call(
            &hub_socket,
            termlink_protocol::control::method::CHANNEL_POST,
            params,
        )
        .await
        {
            Ok(resp) => match termlink_session::client::unwrap_result(resp) {
                Ok(result) => serde_json::to_string_pretty(&result).unwrap_or_else(json_err),
                Err(e) => json_err(format!("channel.react error: {e}")),
            },
            Err(e) => json_err(format!("RPC call failed: {e}")),
        }
    }

    #[tool(
        name = "termlink_channel_mentions",
        description = "Cross-topic mentions search — find every envelope mentioning `target` across ALL topics (optionally prefix-filtered). MCP parity for `termlink channel mentions` CLI verb (T-1777 of T-1166). **Distinct from `termlink_channel_mentions_of`**: that walks ONE topic; this walks the FLEET. Value-add: lets an MCP agent answer 'where am I mentioned anywhere?' — including DM topics it has not yet subscribed to. Defaults `target` to caller's local Identity fingerprint when omitted. Mention matching uses T-1333 rules (`*` wildcard on either side, literal-equality on parts). Skips META msg-types (receipt/reaction/redaction/edit/topic_metadata). Iterates topics from `channel.list` (optional `prefix` filter — e.g. `dm:` to scope to DMs); `limit` default 100, `0` = unlimited, short-circuits across topics once reached. Returns `{ok, target, prefix, hits: [{topic, offset, sender_id, ts, msg_type, payload, mentions}, ...], count}` — each hit carries its source topic. NO new RPC surface — uses `channel.list` + `channel.subscribe` only."
    )]
    async fn termlink_channel_mentions(
        &self,
        Parameters(p): Parameters<ChannelMentionsParams>,
    ) -> String {
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }
        let target = match p.target {
            Some(s) => s,
            None => {
                let home = match std::env::var("HOME") {
                    Ok(h) => h,
                    Err(_) => return json_err("HOME not set; cannot resolve identity dir"),
                };
                let identity_dir = std::path::PathBuf::from(home).join(".termlink");
                let identity =
                    match termlink_session::agent_identity::Identity::load_or_create(&identity_dir)
                    {
                        Ok(i) => i,
                        Err(e) => return json_err(format!("identity load: {e}")),
                    };
                identity.fingerprint().to_string()
            }
        };
        let list_params = match &p.prefix {
            Some(pfx) => serde_json::json!({"prefix": pfx}),
            None => serde_json::json!({}),
        };
        let list_resp = match termlink_session::client::rpc_call(
            &hub_socket,
            termlink_protocol::control::method::CHANNEL_LIST,
            list_params,
        )
        .await
        {
            Ok(r) => r,
            Err(e) => return json_err(format!("channel.list RPC failed: {e}")),
        };
        let list_result = match termlink_session::client::unwrap_result(list_resp) {
            Ok(r) => r,
            Err(e) => return json_err(format!("channel.list error: {e}")),
        };
        let topic_names: Vec<String> = list_result["topics"]
            .as_array()
            .map(|arr| {
                arr.iter()
                    .filter_map(|t| t.get("name").and_then(|v| v.as_str()).map(String::from))
                    .collect()
            })
            .unwrap_or_default();
        const META: &[&str] = &["reaction", "edit", "redaction", "topic_metadata", "receipt"];
        let limit = p.limit.unwrap_or(100);
        let mut hits: Vec<serde_json::Value> = Vec::new();
        'topic_loop: for topic in &topic_names {
            let envelopes = match walk_topic_full_mcp(&hub_socket, topic).await {
                Ok(v) => v,
                Err(_) => continue, // single-topic failure must not poison the fleet sweep
            };
            for env in &envelopes {
                let mt = env.get("msg_type").and_then(|v| v.as_str()).unwrap_or("");
                if META.contains(&mt) {
                    continue;
                }
                let csv = match extract_mentions_mcp(env) {
                    Some(s) => s,
                    None => continue,
                };
                if !mentions_match_mcp(&csv, &target) {
                    continue;
                }
                let offset = env.get("offset").and_then(|v| v.as_u64()).unwrap_or(0);
                let sender = env
                    .get("sender_id")
                    .and_then(|v| v.as_str())
                    .unwrap_or("")
                    .to_string();
                let ts = env
                    .get("ts_unix_ms")
                    .and_then(|v| v.as_i64())
                    .or_else(|| env.get("ts").and_then(|v| v.as_i64()));
                let payload = decode_payload_lossy_mcp(env);
                hits.push(serde_json::json!({
                    "topic": topic,
                    "offset": offset,
                    "sender_id": sender,
                    "ts": ts,
                    "msg_type": mt,
                    "payload": payload,
                    "mentions": csv,
                }));
                if limit > 0 && hits.len() as u64 >= limit {
                    break 'topic_loop;
                }
            }
        }
        let count = hits.len();
        serde_json::to_string_pretty(&serde_json::json!({
            "ok": true,
            "target": target,
            "prefix": p.prefix,
            "hits": hits,
            "count": count,
        }))
        .unwrap_or_else(json_err)
    }

    #[tool(
        name = "termlink_channel_search",
        description = "Pattern-search any topic for envelopes whose payload matches — MCP parity for `termlink channel search <topic> <pattern>` CLI verb (T-1771 of T-1166). Four value-adds over `termlink_agent_search`: (1) topic-flexibility (any topic, not just agent-chat-arc); (2) regex support — set `regex=true` to compile `pattern` as a regular expression (with `(?i)` prefix when `case_sensitive=false`); (3) `all=true` includes meta msg-types (receipt/reaction/redaction/edit/topic_metadata) which are normally skipped; (4) richer row shape with `msg_type` exposed. Fail-fast: invalid regex returns error before any topic walk. Limit: `0` = unlimited, default 100, max 1000. Iterates envelopes in offset order; stops once `limit` is reached. Returns `{ok, topic, pattern, regex, case_sensitive, all, hits: [{offset, sender_id, ts, msg_type, payload}, ...], count}`. Empty payloads (missing or undecodable `payload_b64`) are always filtered. NO new RPC surface — uses `channel.subscribe` only."
    )]
    async fn termlink_channel_search(
        &self,
        Parameters(p): Parameters<ChannelSearchParams>,
    ) -> String {
        const META: &[&str] = &["reaction", "edit", "redaction", "topic_metadata", "receipt"];
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }
        let regex = p.regex.unwrap_or(false);
        let case_sensitive = p.case_sensitive.unwrap_or(false);
        let all = p.all.unwrap_or(false);
        let limit = p.limit.unwrap_or(100).min(1000);
        // Fail-fast: validate regex once up-front before any RPC.
        if regex {
            let effective = if case_sensitive {
                p.pattern.clone()
            } else {
                format!("(?i){}", p.pattern)
            };
            if let Err(e) = ::regex::Regex::new(&effective) {
                return json_err(format!("invalid regex pattern '{}': {e}", p.pattern));
            }
        }
        let envelopes = match walk_topic_full_mcp(&hub_socket, &p.topic).await {
            Ok(v) => v,
            Err(e) => return json_err(format!("walk_topic_full({}): {e}", p.topic)),
        };
        let mut hits: Vec<serde_json::Value> = Vec::new();
        for env in &envelopes {
            let mt = env.get("msg_type").and_then(|v| v.as_str()).unwrap_or("");
            if !all && META.contains(&mt) {
                continue;
            }
            let payload = decode_payload_lossy_mcp(env);
            if payload.is_empty() {
                continue;
            }
            match payload_matches_mcp(&payload, &p.pattern, regex, case_sensitive) {
                Ok(true) => {}
                Ok(false) => continue,
                Err(e) => return json_err(e),
            }
            let offset = env.get("offset").and_then(|v| v.as_u64()).unwrap_or(0);
            let sender = env
                .get("sender_id")
                .and_then(|v| v.as_str())
                .unwrap_or("")
                .to_string();
            let ts = env
                .get("ts_unix_ms")
                .and_then(|v| v.as_i64())
                .or_else(|| env.get("ts").and_then(|v| v.as_i64()));
            hits.push(serde_json::json!({
                "offset": offset,
                "sender_id": sender,
                "ts": ts,
                "msg_type": mt,
                "payload": payload,
            }));
            if limit > 0 && hits.len() as u64 >= limit {
                break;
            }
        }
        let count = hits.len();
        serde_json::to_string_pretty(&serde_json::json!({
            "ok": true,
            "topic": p.topic,
            "pattern": p.pattern,
            "regex": regex,
            "case_sensitive": case_sensitive,
            "all": all,
            "hits": hits,
            "count": count,
        }))
        .unwrap_or_else(json_err)
    }

    #[tool(
        name = "termlink_agent_poll_start",
        description = "Open a chat-arc poll. Posts a `msg_type=poll_start` envelope with the question as payload and `metadata.poll_options=opt1|opt2|...` (pipe-delimited per CLI T-1543 wire convention). Returns the offset of the new envelope — that offset is the `poll_id` used by subsequent vote/end calls. Requires at least 2 options; option labels cannot contain '|'."
    )]
    async fn termlink_agent_poll_start(
        &self,
        Parameters(p): Parameters<AgentPollStartParams>,
    ) -> String {
        use base64::Engine;
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }
        if p.options.len() < 2 {
            return json_err(format!("poll requires at least 2 options (got {})", p.options.len()));
        }
        if p.options.iter().any(|o| o.contains('|')) {
            return json_err("option labels cannot contain '|' (used as the metadata delimiter)");
        }
        let topic = "agent-chat-arc";
        let msg_type = "poll_start";
        let payload_bytes = p.question.into_bytes();
        let home = match std::env::var("HOME") {
            Ok(h) => h,
            Err(_) => return json_err("HOME not set"),
        };
        let identity_dir = std::path::PathBuf::from(home).join(".termlink");
        let identity = match termlink_session::agent_identity::Identity::load_or_create(&identity_dir) {
            Ok(i) => i,
            Err(e) => return json_err(format!("identity load: {e}")),
        };
        let ts_unix_ms = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_millis() as i64)
            .unwrap_or(0);
        let signed = termlink_protocol::control::channel::canonical_sign_bytes(
            topic,
            msg_type,
            &payload_bytes,
            None,
            ts_unix_ms,
        );
        let sig = identity.sign(&signed);
        let mut sig_hex = String::with_capacity(128);
        for b in sig.to_bytes() {
            use std::fmt::Write;
            let _ = write!(&mut sig_hex, "{b:02x}");
        }
        let sender_id = p.sender_id.unwrap_or_else(|| identity.fingerprint().to_string());
        let opts_joined = p.options.join("|");
        let mut metadata = serde_json::Map::new();
        metadata.insert("poll_options".to_string(), serde_json::Value::String(opts_joined));
        let params = serde_json::json!({
            "topic": topic,
            "msg_type": msg_type,
            "payload_b64": base64::engine::general_purpose::STANDARD.encode(&payload_bytes),
            "ts": ts_unix_ms,
            "sender_id": sender_id,
            "sender_pubkey_hex": identity.public_key_hex(),
            "signature_hex": sig_hex,
            "metadata": serde_json::Value::Object(metadata),
        });
        match termlink_session::client::rpc_call(
            &hub_socket,
            termlink_protocol::control::method::CHANNEL_POST,
            params,
        )
        .await
        {
            Ok(resp) => match termlink_session::client::unwrap_result(resp) {
                Ok(result) => serde_json::to_string_pretty(&result).unwrap_or_else(json_err),
                Err(e) => json_err(format!("agent.poll_start error: {e}")),
            },
            Err(e) => json_err(format!("RPC call failed: {e}")),
        }
    }

