    #[tool(
        name = "termlink_channel_ack_status",
        description = "Per-sender ack-status dashboard on an arbitrary topic — MCP parity for the `termlink channel ack-status <TOPIC> [--pending]` CLI verb (T-1361, channel.rs:7266). Value-add over `termlink_agent_ack_status` (chat-arc only, ackers only): surfaces ghost lurkers (members who posted but never acked) with `up_to=None` and `lag=latest+1`, includes a `lag` field per sender, and supports `pending_only` filter to focus on members who aren't caught up. Members = union of envelope senders + receipt-only senders. Sort: lag desc, sender_id asc tiebreak. Returns `{ok, topic, latest_offset, rows: [{sender_id, up_to, latest, lag, ts}, ...], count}`. Use case: coordination ('who do I need to wait for'), staleness audits. Pure read."
    )]
    async fn termlink_channel_ack_status(
        &self,
        Parameters(p): Parameters<ChannelAckStatusParams>,
    ) -> String {
        let hub_socket = termlink_hub::server::hub_socket_path();
        if !hub_socket.exists() {
            return json_err("Hub is not running (no socket found)");
        }
        let envelopes = match walk_topic_full_mcp(&hub_socket, &p.topic).await {
            Ok(v) => v,
            Err(e) => return json_err(format!("walk_topic_full({}): {e}", p.topic)),
        };
        if envelopes.is_empty() {
            return serde_json::to_string_pretty(&serde_json::json!({
                "ok": true,
                "topic": p.topic,
                "latest_offset": 0,
                "rows": [],
                "count": 0,
            })).unwrap_or_else(json_err);
        }
        let latest_offset = envelopes
            .iter()
            .filter_map(|e| e.get("offset").and_then(|v| v.as_u64()))
            .max()
            .unwrap_or(0);
        // Derive receipts from envelope walk (sender -> (max up_to, ts at max).
        let mut receipts: std::collections::HashMap<String, (u64, i64)> = std::collections::HashMap::new();
        for env in &envelopes {
            if env.get("msg_type").and_then(|v| v.as_str()) != Some("receipt") {
                continue;
            }
            let sender = match env.get("sender_id").and_then(|v| v.as_str()) {
                Some(s) => s.to_string(),
                None => continue,
            };
            let up_to = match env
                .get("metadata")
                .and_then(|m| m.get("up_to"))
                .and_then(|v| v.as_str())
                .and_then(|s| s.parse::<u64>().ok())
                .or_else(|| env.get("metadata").and_then(|m| m.get("up_to")).and_then(|v| v.as_u64()))
            {
                Some(v) => v,
                None => continue,
            };
            let ts = env
                .get("ts_unix_ms")
                .and_then(|v| v.as_i64())
                .or_else(|| env.get("ts").and_then(|v| v.as_i64()))
                .unwrap_or(0);
            let entry = receipts.entry(sender).or_insert((0, 0));
            if up_to > entry.0 {
                entry.0 = up_to;
                entry.1 = ts;
            }
        }
        let mut rows = compute_ack_status_mcp(&envelopes, &receipts, latest_offset);
        if p.pending_only.unwrap_or(false) {
            rows.retain(|r| r.lag > 0);
        }
        let rows_json: Vec<serde_json::Value> = rows.iter().map(AckStatusRowMcp::to_json_mcp).collect();
        let count = rows_json.len();
        serde_json::to_string_pretty(&serde_json::json!({
            "ok": true,
            "topic": p.topic,
            "latest_offset": latest_offset,
            "rows": rows_json,
            "count": count,
        }))
        .unwrap_or_else(json_err)
    }

    // === T-1836: MCP parity for T-1830 trio (shell-out per PL-185) ===

    // Resolve a bash script under `${TERMLINK_SCRIPTS_DIR:-/opt/termlink/scripts}`.
    // Returns the absolute path, or a `json_err`-shaped string when the
    // script can't be found. Keeps the script directory overridable for
    // dev installs and tests (the e2e tests below set the env to point
    // at the repo's `scripts/` dir).
    fn resolve_t1836_script(name: &str) -> Result<std::path::PathBuf, String> {
        let dir = std::env::var("TERMLINK_SCRIPTS_DIR")
            .unwrap_or_else(|_| "/opt/termlink/scripts".to_string());
        let path = std::path::PathBuf::from(&dir).join(name);
        if !path.is_file() {
            return Err(json_err(format!(
                "T-1836 script not found: {} (set TERMLINK_SCRIPTS_DIR to override; tried '{}')",
                path.display(),
                dir
            )));
        }
        Ok(path)
    }

    // Run a `bash <script>` subprocess with bounded timeout, kill-on-drop,
    // and null stdin. Returns the structured envelope every T-1836 tool
    // emits: `{ok, exit_code, stdout, stderr}` with optional `parsed`
    // when stdout was JSON.
    async fn run_t1836_subprocess(
        script: &std::path::Path,
        args: &[String],
        timeout_secs: u64,
    ) -> String {
        let mut cmd = tokio::process::Command::new("bash");
        cmd.arg(script);
        for a in args {
            cmd.arg(a);
        }
        cmd.kill_on_drop(true);
        cmd.stdin(std::process::Stdio::null());

        let fut = cmd.output();
        let output =
            match tokio::time::timeout(std::time::Duration::from_secs(timeout_secs), fut).await {
                Ok(Ok(o)) => o,
                Ok(Err(e)) => return json_err(format!("subprocess spawn failed: {e}")),
                Err(_) => {
                    return serde_json::to_string_pretty(&serde_json::json!({
                        "ok": false,
                        "exit_code": -1,
                        "verdict": "timeout",
                        "error": format!("timeout after {}s", timeout_secs),
                        "hint": "raise timeout_secs (max 120) or check the underlying hub",
                    }))
                    .unwrap_or_else(json_err);
                }
            };

        let stdout = String::from_utf8_lossy(&output.stdout).into_owned();
        let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
        let exit_code = output.status.code().unwrap_or(-1);

        // Best-effort JSON parse so MCP clients get structured data when
        // the script supports `--json` (agent-listeners always does;
        // listener-heartbeat with `--once --json` does; agent-send is
        // text-only).
        let parsed: Option<serde_json::Value> =
            serde_json::from_str(stdout.trim()).ok();

        let mut envelope = serde_json::json!({
            "ok": exit_code == 0,
            "exit_code": exit_code,
            "stdout": stdout,
            "stderr": stderr,
        });
        if let Some(p) = parsed {
            envelope
                .as_object_mut()
                .unwrap()
                .insert("parsed".to_string(), p);
        }
        serde_json::to_string_pretty(&envelope).unwrap_or_else(json_err)
    }

