    // === T-1759: compute_starred_set_mcp tests ===

    fn star_env(
        offset: u64,
        actor: &str,
        target: u64,
        star_flag: Option<&str>,
        ts: i64,
    ) -> serde_json::Value {
        let mut md = serde_json::json!({"star_target": target.to_string()});
        if let Some(f) = star_flag {
            md["star"] = serde_json::json!(f);
        }
        serde_json::json!({
            "offset": offset,
            "sender_id": actor,
            "msg_type": "star",
            "ts_unix_ms": ts,
            "metadata": md,
        })
    }

