        let envs = timeline_envs(now);
        // n=2 should keep the 2 newest of 4 = carol + dave (chrono asc preserved).
        let posts = extract_recent_posts_mcp(&envs, 2, 600_000, now, None, None, None, None, None);
        assert_eq!(posts.len(), 2);
