    #[test]
    fn help_list_categories_returns_just_counts() {
        // T-1948: overview mode — return only category names + tool counts,
        // no per-tool fields. Use the real `help_categories()` so the
        // total_categories assertion has meaning (fixture only has 2).
        let cats = help_categories();
        let expected_cat_count = cats.len();
        let expected_tool_count: usize = cats.iter().map(|(_, t)| t.len()).sum();

        let out = build_help_json(&cats, None, None, true, None, false, false, None, None, false, false, None, None, None, None, None, None);
        let v: serde_json::Value = serde_json::from_str(&out).unwrap();

        assert_eq!(v["total_categories"], expected_cat_count);
        assert_eq!(v["total_tools"], expected_tool_count);

        let arr = v["categories"].as_array().expect("categories must be array");
        assert_eq!(arr.len(), expected_cat_count);
        for entry in arr {
            assert!(entry["name"].is_string(), "category entry missing name");
            assert!(entry["tool_count"].is_number(), "category entry missing tool_count");
            // Overview mode must NOT leak per-tool fields.
            assert!(entry["tools"].is_null(), "overview leaked tools array");
            assert!(entry["matches"].is_null(), "overview leaked matches array");
        }
    }

    #[test]
    fn help_unknown_category_hint_lists_all_real_categories() {
        // T-1949: the "Unknown category" error must mention every category
        // present in `help_categories()`. Test against the real registry, not
        // a fixture, so adding a category without wiring the hint will fail
        // this test (and the runtime derivation makes that wiring automatic).
        //
        // Prevents regression of the silent drift observed at T-1943/44/45,
        // where 6 categories were added but the hard-coded hint went stale.
        let cats = help_categories();
        let out = build_help_json(&cats, Some("nonexistent-category"), None, false, None, false, false, None, None, false, false, None, None, None, None, None, None);
        let v: serde_json::Value = serde_json::from_str(&out).unwrap();
        let err = v["error"]
            .as_str()
            .expect("error path must populate `error` field");
        assert!(
            err.contains("nonexistent-category"),
            "error must echo the user input: {err}"
        );
        let mut missing: Vec<&str> = Vec::new();
        for (cat_name, _tools) in cats.iter() {
            if !err.contains(cat_name) {
                missing.push(cat_name);
            }
        }
        assert!(
            missing.is_empty(),
            "unknown-category hint failed to mention {} category/ies: {missing:?}\nfull hint: {err}",
            missing.len()
        );
    }

