    #[test]
    fn help_list_categories_includes_descriptions() {
        // T-1957: list_categories mode must emit a non-empty `description`
        // for every category row alongside `name` and `tool_count`. This is
        // the operator-facing routing hint — empty descriptions would make
        // the field decorative-only.
        let cats = help_categories();
        let out = build_help_json(&cats, None, None, true, None, false, false, None, None, false, false, None, None, None, None, None, None);
        let v: serde_json::Value = serde_json::from_str(&out).unwrap();
        let arr = v["categories"].as_array().expect("categories must be array");
        let mut empty: Vec<String> = Vec::new();
        for entry in arr {
            let name = entry["name"].as_str().expect("name must be string");
            match entry["description"].as_str() {
                Some(d) if !d.is_empty() => {}
                _ => empty.push(name.to_string()),
            }
        }
        assert!(
            empty.is_empty(),
            "categories missing non-empty description: {empty:?}"
        );
    }

    #[test]
    fn category_descriptions_covers_all_categories() {
        // T-1957: structural invariant — the descriptions map's key set must
        // equal the set of category names from `help_categories()`. Adding a
        // category without a description (or vice-versa) fails this test, so
        // drift cannot land silently. Mirrors the T-1949 unknown-category
        // hint derivation pattern (single source of truth).
        use std::collections::HashSet;
        let cats = help_categories();
        let cat_names: HashSet<&str> = cats.iter().map(|(n, _)| *n).collect();
        let descs = category_descriptions();
        let desc_keys: HashSet<&str> = descs.keys().copied().collect();

        let mut missing_desc: Vec<&str> =
            cat_names.difference(&desc_keys).copied().collect();
        missing_desc.sort();
        assert!(
            missing_desc.is_empty(),
            "categories with no description entry: {missing_desc:?}"
        );

        let mut orphan_desc: Vec<&str> =
            desc_keys.difference(&cat_names).copied().collect();
        orphan_desc.sort();
        assert!(
            orphan_desc.is_empty(),
            "description map has entries for unknown categories: {orphan_desc:?}"
        );
    }

    #[test]
    fn tool_descriptions_extracts_all_real_tools() {
        // T-1952: the regex-based extractor must catch every `#[tool(name=…)]`
        // entry. Sanity-check against the phantom-guard's source-scan: same
        // tool name set must appear in both. If the regex misses descriptions
        // for valid tools, tool_detail mode will return "Unknown tool" for them.
        use std::collections::HashSet;
        let src = include_str!("./tools.rs");
        let name_re = regex::Regex::new(r#"name *= *"(termlink_[a-z_]+)""#).unwrap();
        let real: HashSet<&str> = name_re
            .captures_iter(src)
            .map(|c| c.get(1).unwrap().as_str())
            .collect();
        let descs = tool_descriptions();
        let extracted: HashSet<&str> = descs.keys().copied().collect();
        let mut missing: Vec<&str> = real.difference(&extracted).copied().collect();
        missing.sort();
        assert!(
            missing.is_empty(),
            "tool_descriptions regex missed {} tool(s): {missing:?}",
            missing.len()
        );
    }

    #[test]
    fn help_tool_detail_returns_full_description() {
        // T-1952: drill-in mode returns category + short (from help_categories)
        // + full (from macro) descriptions in one call.
        let cats = help_categories();
        let out = build_help_json(&cats, None, None, false, Some("termlink_help"), false, false, None, None, false, false, None, None, None, None, None, None);
        let v: serde_json::Value = serde_json::from_str(&out).unwrap();

        assert_eq!(v["tool"], "termlink_help");
        assert_eq!(v["name"], "termlink_help");
        assert!(v["category"].is_string());
        assert!(v["short_description"].is_string());
        let full = v["full_description"].as_str().expect("full_description must populate");
        // termlink_help's macro description mentions "Four modes" (post-T-1952) —
        // any value mode-related is acceptable; the key invariant is non-empty.
        assert!(!full.is_empty(), "full_description should not be empty");
        assert!(
            full.len() > v["short_description"].as_str().unwrap().len(),
            "full_description should be longer than short_description"
        );
    }

    #[test]
    fn tool_params_extracts_known_tool() {
        // T-1953: the regex-based param extractor must correctly resolve a
        // known tool's `Parameters<…>` struct and surface every field. Use
        // `termlink_help` because its `HelpParams` is stable and small
        // (4 fields, all Option<…>).
        let params = tool_params();
        let help_params = params
            .get("termlink_help")
            .expect("termlink_help must have a parameter entry");
        let names: Vec<&str> = help_params.iter().map(|p| p.name.as_str()).collect();
        assert!(
            names.contains(&"category"),
            "HelpParams.category missing — got {names:?}"
        );
        assert!(
            names.contains(&"name_filter"),
            "HelpParams.name_filter missing — got {names:?}"
        );
        assert!(
            names.contains(&"list_categories"),
            "HelpParams.list_categories missing — got {names:?}"
        );
        assert!(
            names.contains(&"tool_detail"),
            "HelpParams.tool_detail missing — got {names:?}"
        );
        // All HelpParams fields are Option<…>, so optional must be true for each.
        for p in help_params {
            assert!(
                p.optional,
                "HelpParams.{} should be optional (Option<…>) but resolved as required (type={})",
                p.name, p.type_str
            );
        }
    }

    #[test]
    fn tool_detail_response_includes_parameters() {
        // T-1953: tool_detail mode must include a `parameters` array in the
        // JSON response so LLM consumers see ground-truth field shapes
        // alongside descriptions.
        let cats = help_categories();
        let out = build_help_json(&cats, None, None, false, Some("termlink_help"), false, false, None, None, false, false, None, None, None, None, None, None);
        let parsed: serde_json::Value =
            serde_json::from_str(&out).expect("response must be valid JSON");
        let params = parsed
            .get("parameters")
            .expect("response missing `parameters` key");
        let arr = params
            .as_array()
            .expect("`parameters` must be an array");
        assert!(
            arr.len() >= 4,
            "expected ≥4 parameters on termlink_help, got {}",
            arr.len()
        );
        let names: Vec<&str> = arr
            .iter()
            .filter_map(|p| p.get("name").and_then(|n| n.as_str()))
            .collect();
        assert!(
            names.contains(&"tool_detail"),
            "tool_detail param missing from response — got {names:?}"
        );
        // Each entry must have name + type + optional fields populated.
        for entry in arr {
            assert!(entry.get("name").is_some(), "param entry missing name");
            assert!(entry.get("type").is_some(), "param entry missing type");
            assert!(
                entry.get("optional").is_some(),
                "param entry missing optional flag"
            );
        }
    }

    #[test]
    fn tool_params_covers_majority_of_real_tools() {
        // T-1953: sanity check — the param extractor should resolve the vast
        // majority of tools (some may legitimately lack a Parameters<…> arg).
        // Assert >50% coverage so a regex regression that breaks Phase 1
        // (tool→struct binding) gets caught structurally.
        use std::collections::HashSet;
        let src = include_str!("./tools.rs");
        let name_re = regex::Regex::new(r#"name *= *"(termlink_[a-z_]+)""#).unwrap();
        let real: HashSet<&str> = name_re
            .captures_iter(src)
            .map(|c| c.get(1).unwrap().as_str())
            .collect();
        let params = tool_params();
        let coverage = params.len();
        let total = real.len();
        assert!(
            coverage * 2 > total,
            "tool_params resolved only {coverage}/{total} tools (< 50%) — Phase 1 regex likely broken"
        );
    }

