    #[test]
    fn list_categories_rows_carry_deprecated_count() {
        // T-1967: every list_categories row must carry `deprecated_count`
        // equal to a parallel walk that counts is_deprecated() applications
        // for that category's tools. Locks the per-row arithmetic against
        // a future regression where the filter predicate diverges from the
        // shared `is_deprecated()` source-of-truth.
        let cats = help_categories();
        let out = build_help_json(&cats, None, None, true, None, false, false, None, None, false, false, None, None, None, None, None, None);
        let v: serde_json::Value = serde_json::from_str(&out).unwrap();
        let arr = v["categories"]
            .as_array()
            .expect("list_categories must return `categories` array");
        let mut errors: Vec<String> = Vec::new();
        for entry in arr {
            let name = entry["name"]
                .as_str()
                .unwrap_or_else(|| panic!("list_categories row missing name: {entry:?}"));
            let dc = entry["deprecated_count"].as_u64().unwrap_or(u64::MAX);
            if dc == u64::MAX {
                errors.push(format!("{name}: deprecated_count missing or non-numeric"));
                continue;
            }
            // Look up the same category in the registry and recompute
            let (_, tools) = cats
                .iter()
                .find(|(n, _)| *n == name)
                .unwrap_or_else(|| panic!("list_categories row '{name}' has no registry match"));
            let expected = tools.iter().filter(|(_, d)| is_deprecated(d)).count() as u64;
            if dc != expected {
                errors.push(format!(
                    "{name}: list_categories deprecated_count={dc}, recompute={expected}"
                ));
            }
        }
        assert!(
            errors.is_empty(),
            "list_categories deprecated_count drift on {} row(s):\n  {}",
            errors.len(),
            errors.join("\n  ")
        );
    }

    #[test]
    fn list_categories_deprecated_sum_matches_summary() {
        // T-1967: cross-mode arithmetic consistency. Sum of per-row
        // `deprecated_count` in list_categories must equal the
        // `total_deprecated` returned by summary mode. Both come from the
        // same registry + same `is_deprecated()` predicate; divergence
        // means one mode iterated wrong (e.g. skipped an empty category).
        let cats = help_categories();
        let lc_out = build_help_json(&cats, None, None, true, None, false, false, None, None, false, false, None, None, None, None, None, None);
        let lc: serde_json::Value = serde_json::from_str(&lc_out).unwrap();
        let lc_sum: u64 = lc["categories"]
            .as_array()
            .unwrap()
            .iter()
            .map(|e| e["deprecated_count"].as_u64().unwrap_or(0))
            .sum();
        let sum_out = build_help_json(&cats, None, None, false, None, true, false, None, None, false, false, None, None, None, None, None, None);
        let sm: serde_json::Value = serde_json::from_str(&sum_out).unwrap();
        let sm_total = sm["total_deprecated"].as_u64().unwrap();
        assert_eq!(
            lc_sum, sm_total,
            "list_categories sum of deprecated_count ({lc_sum}) must equal summary.total_deprecated ({sm_total})"
        );
    }

    #[test]
    fn name_filter_match_rows_carry_category_tool_count() {
        // T-1966: every name_filter match row must carry
        // `category_tool_count` equal to the live size of the match's
        // category. Spot-check: search by each tool's own name (which
        // guarantees the match returns at least itself) and verify the
        // returned row's category_tool_count matches the registry. Walking
        // every tool is wasteful here; sampling one tool per category
        // covers the per-category arithmetic without quadratic cost.
        let cats = help_categories();
        let mut errors: Vec<String> = Vec::new();
        for (cat_name, tools) in &cats {
            let Some((sample_name, _)) = tools.first() else {
                continue;
            };
            let expected_size = tools.len();
            // Search by the tool's full name — guaranteed to match itself.
            let out = build_help_json(&cats, None, Some(sample_name), false, None, false, false, None, None, false, false, None, None, None, None, None, None);
            let v: serde_json::Value = serde_json::from_str(&out).unwrap();
            let arr = v["matches"]
                .as_array()
                .unwrap_or_else(|| panic!("name_filter for {sample_name} must return matches array"));
            // Find the match row for sample_name itself
            let self_match = arr
                .iter()
                .find(|m| m["name"].as_str() == Some(sample_name))
                .unwrap_or_else(|| panic!("self-match for {sample_name} not in results"));
            let tc = self_match["category_tool_count"]
                .as_u64()
                .unwrap_or(0) as usize;
            if tc != expected_size {
                errors.push(format!(
                    "category={cat_name} sample={sample_name}: \
                     match.category_tool_count={tc}, expected {expected_size}"
                ));
            }
        }
        assert!(
            errors.is_empty(),
            "name_filter category_tool_count drift on {} category(ies):\n  {}",
            errors.len(),
            errors.join("\n  ")
        );
    }

    #[test]
    fn tool_detail_carries_category_context_for_every_tool() {
        // T-1965: every tool_detail success response must carry
        // `category_description` (non-empty) and `category_tool_count`
        // (matches the tool's category size). Walk the full registry —
        // one missing or wrong row fails. Locks the contract end-to-end:
        // if a future regression strips either field from the envelope,
        // OR if `category_descriptions()` loses an entry that
        // bijective-coverage already prevents, OR if `category_tool_count`
        // gets accidentally computed from the wrong category, this fires.
        let cats = help_categories();
        let mut errors: Vec<String> = Vec::new();
        for (cat_name, tools) in &cats {
            let expected_size = tools.len();
            for (tool_name, _) in tools {
                let out = build_help_json(&cats, None, None, false, Some(tool_name), false, false, None, None, false, false, None, None, None, None, None, None);
                let v: serde_json::Value = serde_json::from_str(&out).unwrap();
                let cat_desc = v["category_description"].as_str().unwrap_or("");
                if cat_desc.is_empty() {
                    errors.push(format!(
                        "{tool_name} ({cat_name}): category_description is empty"
                    ));
                }
                let tc = v["category_tool_count"].as_u64().unwrap_or(0) as usize;
                if tc != expected_size {
                    errors.push(format!(
                        "{tool_name} ({cat_name}): category_tool_count={tc}, expected {expected_size}"
                    ));
                }
                // Also verify the category name still matches — guards
                // against accidentally swapping which category's metadata
                // gets attached.
                let cat_attached = v["category"].as_str().unwrap_or("");
                if cat_attached != *cat_name {
                    errors.push(format!(
                        "{tool_name}: category field is '{cat_attached}', expected '{cat_name}'"
                    ));
                }
            }
        }
        assert!(
            errors.is_empty(),
            "category-context drift on {} tool(s):\n  {}",
            errors.len(),
            errors.join("\n  ")
        );
    }

    #[test]
    fn name_filter_rows_parameter_count_matches_tool_detail() {
        // T-1972: cross-mode consistency. For every tool matched by a
        // broad-enough name_filter (`termlink_` matches the whole registry),
        // the row's `parameter_count` MUST equal what tool_detail returns
        // for the same name. Locks the two bulk-listing-mode shapes to the
        // same tool_params() source — a divergence here means one path is
        // synthesizing arity instead of reading the registry.
        let cats = help_categories();
        let out = build_help_json(&cats, None, Some("termlink_"), false, None, false, false, None, None, false, false, None, None, None, None, None, None);
        let v: serde_json::Value = serde_json::from_str(&out).unwrap();
        let matches = v["matches"].as_array().expect("matches array");
        let mut errors: Vec<String> = Vec::new();
        for row in matches {
            let name = row["name"].as_str().unwrap();
            let nf_pc = row["parameter_count"].as_u64().unwrap_or(u64::MAX) as usize;
            let td_out = build_help_json(&cats, None, None, false, Some(name), false, false, None, None, false, false, None, None, None, None, None, None);
            let td: serde_json::Value = serde_json::from_str(&td_out).unwrap();
            let td_pc = td["parameter_count"].as_u64().unwrap_or(u64::MAX) as usize;
            if nf_pc != td_pc {
                errors.push(format!(
                    "{name}: name_filter parameter_count={nf_pc}, tool_detail={td_pc}"
                ));
            }
        }
        assert!(
            errors.is_empty(),
            "{} name_filter/tool_detail parameter_count divergence(s):\n  {}",
            errors.len(),
            errors.join("\n  ")
        );
    }

