    #[test]
    fn min_max_parameters_compose_for_range() {
        // T-1976: combining min_parameters and max_parameters with a
        // name_filter yields an arity-range AND name-match query. Every
        // returned row must satisfy BOTH bounds AND the name predicate.
        let cats = help_categories();
        let out = build_help_json(
            &cats,
            None,
            Some("channel"),
            false,
            None,
            false,
            false,
            Some(4),
            Some(2),
            false,
            false,
            None,
            None, None, None, None, None);
        let v: serde_json::Value = serde_json::from_str(&out).unwrap();
        let matches = v["matches"].as_array().expect("matches array");
        // Range filter is strict; the channel family is large enough that
        // some tools have arity 2-4 — non-empty is the smoke-floor.
        assert!(
            !matches.is_empty(),
            "channel-family arity[2,4] should be non-empty: {out}"
        );
        for row in matches {
            let pc = row["parameter_count"].as_u64().unwrap_or(u64::MAX) as usize;
            let name = row["name"].as_str().unwrap_or("?");
            let desc = row["description"].as_str().unwrap_or("").to_lowercase();
            assert!(
                (2..=4).contains(&pc),
                "{name}: arity {pc} outside [2,4]"
            );
            assert!(
                name.to_lowercase().contains("channel") || desc.contains("channel"),
                "{name}: row does not match needle 'channel'"
            );
        }
    }

    #[test]
    fn min_parameters_standalone_matches_arity_walk() {
        // T-1976: standalone min_parameters=K count MUST equal the count
        // obtained by walking tool_params() and filtering arity>=K. Locks
        // the standalone-arity-filter branch to the same source-of-truth
        // that tool_detail uses for parameter_count.
        const K: usize = 3;
        let cats = help_categories();
        let standalone = build_help_json(&cats, None, None, false, None, false, false, None, Some(K), false, false, None, None, None, None, None, None);
        let s_v: serde_json::Value = serde_json::from_str(&standalone).unwrap();
        let standalone_count = s_v["matches"]
            .as_array()
            .map(|a| a.len())
            .unwrap_or(usize::MAX);
        // Walk the registry independently.
        let mut walked = 0usize;
        for (_, tools) in &cats {
            for (name, _) in tools {
                let pc = tool_params().get(*name).map(|v| v.len()).unwrap_or(0);
                if pc >= K {
                    walked += 1;
                }
            }
        }
        assert_eq!(
            standalone_count, walked,
            "min_parameters={K} returned {standalone_count} rows but registry-walk={walked}"
        );
    }

