    #[test]
    fn categories_composes_with_sort_by() {
        // T-1999: scope filter applied, then sort runs over the filtered
        // multi-namespace set.
        let cats = help_categories();
        let arr = vec!["channel".to_string(), "agent_chat".to_string()];
        let v = help_with_categories(&cats, Some("post"), None, Some(&arr), None, Some("name"));
        let matches = v["matches"].as_array().unwrap();
        for window in matches.windows(2) {
            let a = window[0]["name"].as_str().unwrap();
            let b = window[1]["name"].as_str().unwrap();
            assert!(a <= b);
            // Cross-check: still inside the scope.
            let cat = window[0]["category"].as_str().unwrap();
            assert!(cat == "channel" || cat == "agent_chat");
        }
    }

