    #[test]
    fn tool_detail_category_counts_consistent_with_walk() {
        // T-1983: both new fields MUST equal independent per-category walks.
        // Pick `termlink_help` (in `diagnostics` category) — diagnostics is
        // populated with deprecated AND live tools (T-1166 inbox primitives
        // sit there), so both counts are non-trivial.
        let cats = help_categories();
        let out = build_help_json(
            &cats, None, None, false, Some("termlink_help"),
            false, false, None, None, false, false,
            None,
            None, None, None, None, None);
        let v: serde_json::Value = serde_json::from_str(&out).unwrap();
        let cat = v["category"].as_str().expect("category");
        let target_tools = &cats.iter().find(|(n, _)| *n == cat).expect("category in cats").1;
        let walked_dep = target_tools.iter().filter(|(_, d)| is_deprecated(d)).count();
        let walked_live = target_tools.len() - walked_dep;
        let reported_dep = v["category_deprecated_count"].as_u64().unwrap_or(u64::MAX) as usize;
        let reported_live = v["category_live_tool_count"].as_u64().unwrap_or(u64::MAX) as usize;
        assert_eq!(reported_dep, walked_dep, "category_deprecated_count drift");
        assert_eq!(reported_live, walked_live, "category_live_tool_count drift");
    }

    #[test]
    fn tool_detail_category_counts_sum_to_tool_count() {
        // T-1983: arithmetic identity locking the two new fields to the
        // existing category_tool_count. Walks every tool — broad coverage
        // catches per-category miscounting on any single namespace.
        let cats = help_categories();
        for (_, tools) in &cats {
            for (name, _) in tools {
                let out = build_help_json(
                    &cats, None, None, false, Some(name),
                    false, false, None, None, false, false,
                    None,
                    None, None, None, None, None);
                let v: serde_json::Value = serde_json::from_str(&out).unwrap();
                let total = v["category_tool_count"].as_u64().unwrap_or(u64::MAX);
                let dep = v["category_deprecated_count"].as_u64().unwrap_or(u64::MAX);
                let live = v["category_live_tool_count"].as_u64().unwrap_or(u64::MAX);
                assert_eq!(
                    live + dep, total,
                    "{name}: category_live_tool_count + category_deprecated_count != category_tool_count ({} + {} != {})",
                    live, dep, total
                );
            }
        }
    }

    #[test]
    fn tool_detail_category_counts_match_list_categories_row() {
        // T-1983: cross-mode invariant. tool_detail's per-namespace counts
        // MUST match the same category's row in list_categories mode.
        // Locks the two derivations to a single source-of-truth walk.
        let cats = help_categories();
        let lc_out = build_help_json(
            &cats, None, None, true, None, false, false, None, None, false, false,
            None,
            None, None, None, None, None);
        let lc_v: serde_json::Value = serde_json::from_str(&lc_out).unwrap();
        let lc_rows = lc_v["categories"].as_array().expect("categories array");
        // Walk every tool, compare per tool_detail call.
        for (cat_name, tools) in &cats {
            let lc_row = lc_rows
                .iter()
                .find(|r| r["name"].as_str() == Some(*cat_name))
                .unwrap_or_else(|| panic!("{cat_name}: missing in list_categories"));
            let lc_dep = lc_row["deprecated_count"].as_u64().unwrap_or(u64::MAX);
            let lc_live = lc_row["live_tool_count"].as_u64().unwrap_or(u64::MAX);
            // Sample first tool in the category — same per-namespace counts
            // expected on every tool's detail, so first is sufficient.
            if let Some((name, _)) = tools.first() {
                let td_out = build_help_json(
                    &cats, None, None, false, Some(name),
                    false, false, None, None, false, false,
                    None,
                    None, None, None, None, None);
                let td_v: serde_json::Value = serde_json::from_str(&td_out).unwrap();
                let td_dep = td_v["category_deprecated_count"].as_u64().unwrap_or(u64::MAX);
                let td_live = td_v["category_live_tool_count"].as_u64().unwrap_or(u64::MAX);
                assert_eq!(
                    td_dep, lc_dep,
                    "{cat_name}: tool_detail deprecated_count={td_dep} but list_categories deprecated_count={lc_dep}"
                );
                assert_eq!(
                    td_live, lc_live,
                    "{cat_name}: tool_detail live_tool_count={td_live} but list_categories live_tool_count={lc_live}"
                );
            }
        }
    }

    #[test]
    fn help_summary_total_parameters_matches_sum_over_tool_detail() {
        // T-1973: cross-mode arithmetic. summary.total_parameters MUST
        // equal the sum of tool_detail.parameter_count across every tool.
        // Both paths go through tool_params() — divergence would mean one
        // of them is computing arity from a different source.
        let cats = help_categories();
        let summary_out = build_help_json(&cats, None, None, false, None, true, false, None, None, false, false, None, None, None, None, None, None);
        let summary: serde_json::Value = serde_json::from_str(&summary_out).unwrap();
        let summary_total = summary["total_parameters"].as_u64().unwrap_or(u64::MAX) as usize;
        let mut walked_total = 0usize;
        for (_, tools) in &cats {
            for (name, _) in tools {
                let td_out = build_help_json(&cats, None, None, false, Some(name), false, false, None, None, false, false, None, None, None, None, None, None);
                let td: serde_json::Value = serde_json::from_str(&td_out).unwrap();
                walked_total += td["parameter_count"].as_u64().unwrap_or(0) as usize;
            }
        }
        assert_eq!(
            summary_total, walked_total,
            "summary.total_parameters={summary_total} but sum-over-tool_detail={walked_total}"
        );
    }

    #[test]
    fn help_summary_zero_arity_tools_matches_walk_count() {
        // T-1973: zero_arity_tools MUST equal the count of tools whose
        // tool_detail.parameter_count == 0. Walks the same registry.
        let cats = help_categories();
        let summary_out = build_help_json(&cats, None, None, false, None, true, false, None, None, false, false, None, None, None, None, None, None);
        let summary: serde_json::Value = serde_json::from_str(&summary_out).unwrap();
        let summary_zero = summary["zero_arity_tools"].as_u64().unwrap_or(u64::MAX) as usize;
        let mut walked_zero = 0usize;
        for (_, tools) in &cats {
            for (name, _) in tools {
                let td_out = build_help_json(&cats, None, None, false, Some(name), false, false, None, None, false, false, None, None, None, None, None, None);
                let td: serde_json::Value = serde_json::from_str(&td_out).unwrap();
                if td["parameter_count"].as_u64().unwrap_or(u64::MAX) == 0 {
                    walked_zero += 1;
                }
            }
        }
        assert_eq!(
            summary_zero, walked_zero,
            "summary.zero_arity_tools={summary_zero} but walked-zero count={walked_zero}"
        );
    }

    #[test]
    fn help_summary_highest_arity_tools_ranked_and_real() {
        // T-1973: highest_arity_tools rows must (a) cap at 5, (b) be sorted
        // descending by parameter_count, (c) each row's parameter_count
        // must match tool_detail for that name, (d) every row name resolves
        // to a real registry tool. Locks the ranking contract end-to-end.
        let cats = help_categories();
        let summary_out = build_help_json(&cats, None, None, false, None, true, false, None, None, false, false, None, None, None, None, None, None);
        let summary: serde_json::Value = serde_json::from_str(&summary_out).unwrap();
        let arr = summary["highest_arity_tools"]
            .as_array()
            .expect("highest_arity_tools must be an array");
        assert!(
            arr.len() <= 5,
            "highest_arity_tools must cap at 5 — got {}",
            arr.len()
        );
        let known: std::collections::HashSet<&str> = cats
            .iter()
            .flat_map(|(_, tools)| tools.iter().map(|(n, _)| *n))
            .collect();
        // (b) descending order check
        for w in arr.windows(2) {
            let a = w[0]["parameter_count"].as_u64().unwrap();
            let b = w[1]["parameter_count"].as_u64().unwrap();
            assert!(
                a >= b,
                "highest_arity_tools must be descending — {a} < {b}"
            );
        }
        // (a) (c) (d) per-row checks
        for entry in arr {
            let name = entry["name"]
                .as_str()
                .unwrap_or_else(|| panic!("highest_arity_tools row missing name: {entry:?}"));
            assert!(
                known.contains(name),
                "highest_arity_tools references unknown tool '{name}'"
            );
            let pc = entry["parameter_count"].as_u64().unwrap_or(u64::MAX) as usize;
            let td_out = build_help_json(&cats, None, None, false, Some(name), false, false, None, None, false, false, None, None, None, None, None, None);
            let td: serde_json::Value = serde_json::from_str(&td_out).unwrap();
            let td_pc = td["parameter_count"].as_u64().unwrap_or(u64::MAX) as usize;
            assert_eq!(
                pc, td_pc,
                "{name}: highest_arity_tools row pc={pc}, tool_detail pc={td_pc}"
            );
        }
    }

    #[test]
    fn help_summary_takes_precedence_over_list_categories_and_filter() {
        // T-1963: when summary=true is set, list_categories / name_filter /
        // category must be ignored. Output shape is the summary envelope, not
        // the list_categories envelope. Locks the documented precedence so a
        // future regression can't silently reorder the branches.
        let cats = help_categories();
        // Pass list_categories=true AND name_filter AND category alongside
        // summary=true — summary should win.
        let out = build_help_json(
            &cats,
            Some("session"),
            Some("zzz_no_match_xyz"),
            true,
            None,
            true,
            false,
            None,
            None,
            false,
            false,
            None,
            None, None, None, None, None);
        let v: serde_json::Value = serde_json::from_str(&out).unwrap();
        // summary-envelope keys present
        assert!(v["total_tools"].is_u64(), "summary envelope missing total_tools");
        assert!(
            v["largest_categories"].is_array(),
            "summary envelope missing largest_categories"
        );
        // list_categories-envelope key absent
        assert!(
            v["categories"].is_null(),
            "summary mode must NOT emit list_categories envelope's `categories` field"
        );
        // name_filter-envelope key absent
        assert!(
            v["matches"].is_null(),
            "summary mode must NOT emit name_filter envelope's `matches` field"
        );
    }

    #[test]
    fn name_filter_multi_token_and_matches_combined() {
        // T-1955: `agent post` should now match `termlink_agent_post` —
        // both tokens present in the name. Before T-1955 this returned 0
        // matches because the exact phrase "agent post" doesn't appear
        // anywhere literally (the tool name has an underscore separator).
        let cats = help_categories();
        let out = build_help_json(&cats, None, Some("agent post"), false, None, false, false, None, None, false, false, None, None, None, None, None, None);
        let v: serde_json::Value = serde_json::from_str(&out).unwrap();
        let matches = v["matches"].as_array().expect("matches must be array");
        let names: Vec<&str> = matches
            .iter()
            .filter_map(|m| m["name"].as_str())
            .collect();
        assert!(
            names.contains(&"termlink_agent_post"),
            "expected termlink_agent_post in multi-token results — got {names:?}"
        );
    }

    #[test]
    fn name_filter_multi_token_and_drops_partial_matches() {
        // T-1955: logical AND semantics — adding a nonsense token to a
        // valid one zeroes out all results. The bare token "agent" by
        // itself would surface dozens of tools; pairing with "zzz999xyz"
        // (no tool contains that string) reduces it to 0.
        let cats = help_categories();
        let out = build_help_json(&cats, None, Some("agent zzz999xyz"), false, None, false, false, None, None, false, false, None, None, None, None, None, None);
        let v: serde_json::Value = serde_json::from_str(&out).unwrap();
        assert_eq!(
            v["total_matches"], 0,
            "nonsense token must veto all matches under logical-AND semantics; got {v}"
        );
    }

    #[test]
    fn name_filter_multi_token_distributes_across_name_and_desc() {
        // T-1955: a token may match the name while another matches the
        // description — `pin react` should surface at least one tool where
        // these two intent words combine. `termlink_agent_pin` whose
        // description references reactions OR `termlink_agent_react` whose
        // description mentions pinning satisfies this.
        let cats = help_categories();
        let out = build_help_json(&cats, None, Some("pin react"), false, None, false, false, None, None, false, false, None, None, None, None, None, None);
        let v: serde_json::Value = serde_json::from_str(&out).unwrap();
        let total = v["total_matches"].as_u64().unwrap_or(0);
        assert!(
            total >= 1,
            "expected ≥1 match for cross-name-and-desc tokens; got {total}"
        );
    }

    #[test]
    fn tool_detail_unknown_includes_suggestions() {
        // T-1954: passing a near-miss tool name (`termlink_post` — common
        // partial that LLMs guess) must surface `did_you_mean` with the
        // closest real candidates by Levenshtein distance. Eliminates the
        // round-trip where an LLM has to fall back to name_filter='post'.
        let cats = help_categories();
        let out = build_help_json(&cats, None, None, false, Some("termlink_post"), false, false, None, None, false, false, None, None, None, None, None, None);
        let v: serde_json::Value = serde_json::from_str(&out).unwrap();
        assert!(v["error"].is_string(), "error must populate");
        let suggestions = v["did_you_mean"]
            .as_array()
            .expect("did_you_mean must be present as array");
        let names: Vec<&str> = suggestions.iter().filter_map(|x| x.as_str()).collect();
        assert!(
            names.contains(&"termlink_agent_post"),
            "did_you_mean should include termlink_agent_post — got {names:?}"
        );
        assert!(
            names.contains(&"termlink_channel_post"),
            "did_you_mean should include termlink_channel_post — got {names:?}"
        );
    }

